CustomInfo: ConfigSection "Name=A/V Config"
CustomInfo: ConfigParam "Name=Audio" "Parent=A/V Config" "Priority=Important" "Type=bool" "Desc=Enable sound and speech tasks (say, play, sendSound)." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=SoftwareAdjustment" "Parent=A/V Config" "Priority=Expert" "Type=bool" "Desc=Software VolumeAdjustment without moving volume slider. User can adjust volume near SoftwareAdjustmentBase." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=" "Parent=A/V Config" "Priority=Expert" "Type=unknown" "Desc="
CustomInfo: ConfigParam "Name=EncodingQuality" "Parent=A/V Config" "Priority=Expert" "Type=double" "Desc=The general level of quality for audio.  Lower levels use less bandwidth." "Value=6" "Max=10"
CustomInfo: ConfigParam "Name=EncoderFilterNoise" "Parent=A/V Config" "Priority=Expert" "Type=bool" "Desc=Enable the adaptive noise filter for audio.  This will reduce consistent background noise if it is detected, although it may also introduce minor artifacts and slightly increase CPU use. Recommend enabling." "Value=true"
CustomInfo: ConfigParam "Name=EncoderFilterNoiseAGC" "Parent=A/V Config" "Priority=Expert" "Type=bool" "Desc=Use automatic gain control with noise filter for audio.  This will adjust the volume of input audio after processing with a denoise filter to maximize the volume of voice or other signals, but it may also cause poor quality. Recommend disabling unless the denoise filter is making audio too quiet." "Value=false"
CustomInfo: ConfigParam "Name=StatsReportFreq" "Parent=A/V Config" "Priority=Expert" "Type=double" "Desc=Frequency (in sec.) at which to write audio statistics to the log file. This includes information on recording, encoding, sending, receiving, and decoding.  0 to disable." "Value=0"
CustomInfo: ConfigParam "Name=VBR" "Parent=A/V Config" "Priority=Expert" "Type=bool" "Desc=Whether audio is encoded with a variable bit rate; bandwidth usage is related to amount of voice or other signal recorded.  Recommend enabling." "Value=true"
CustomInfo: ConfigParam "Name=VAD" "Parent=A/V Config" "Priority=Expert" "Type=bool" "Desc=Whether audio is encoded with a voice activation detection, so minimal bandwidth is used if voice or other signal is not detected for some time. Only meaningful if VBR is false." "Value=true"
CustomInfo: ConfigParam "Name=EncodingComplexity" "Parent=A/V Config" "Priority=Expert" "Type=int" "Desc=Determines complexity or "detail" of voice encoding. Higher values may improve quality but also may impact CPU performance and bandwidth use. It is recommended that this parameter only be modified if maximum EncodingQuality does not provide adequate quality." "Value=4" "Max=8"
CustomInfo: ConfigParam "Name=SoundsAndSpeechMix" "Parent=A/V Config" "Priority=Expert" "Type=string" "Desc=If "PauseAudio", audio is paused (both talk and listen) during sound and speech synthesis playback. If "SupressSounds", sound and speech playback is skipped while audio is active (either talk or listen)" "Value=SupressSounds" "Display=Choices:SupressSounds;;PauseAudio"
CustomInfo: ConfigParam "Name=SoftwareAdjustmentBase" "Parent=A/V Config" "Priority=Expert" "Type=double" "Desc=Base software volume for lowering to mid level. It enables increase/decrease volume adjustment near the level." "Value=1" "Max=1"
CustomInfo: ConfigSection "Name=Absolute Movement Maximums"
CustomInfo: ConfigParam "Name=AbsoluteMaxTransVel" "Parent=Absolute Movement Maximums" "Priority=Expert" "Type=int" "Desc=Absolute maximum translational speed (in mm/sec).  This cannot be exceeded under any circumstances." "Value=1200" "Max=1200" "Display=Visible:true"
CustomInfo: ConfigParam "Name=AbsoluteMaxTransNegVel" "Parent=Absolute Movement Maximums" "Priority=Expert" "Type=int" "Desc=Absolute maximum negative translational speed (in -mm/sec).  This cannot be exceeded under any circumstances." "Value=-200" "Max=-100" "Display=Visible:true"
CustomInfo: ConfigParam "Name=AbsoluteMaxTransAccel" "Parent=Absolute Movement Maximums" "Priority=Expert" "Type=int" "Desc=Absolute maximum translational acceleration (in mm/sec/sec) that cannot be exceeded under any circumstances." "Value=600" "Max=600" "Display=Visible:true"
CustomInfo: ConfigParam "Name=AbsoluteMaxTransDecel" "Parent=Absolute Movement Maximums" "Priority=Expert" "Type=int" "Desc=Absolute maximum translational deceleration (in mm/sec/sec).  This cannot be exceeded under any circumstances.  WARNING!  Changing this parameter can adversely impact the robot's safe stopping distance.  This parameter must only be changed by trained safety personnel." "Value=2000" "Max=2000" "Display=Visible:true"
CustomInfo: ConfigParam "Name=AbsoluteMaxRotVel" "Parent=Absolute Movement Maximums" "Priority=Expert" "Type=int" "Desc=Absolute maximum rotational speed (in deg/sec).  This cannot be exceeded under any circumstances." "Value=120" "Max=180" "Display=Visible:true"
CustomInfo: ConfigParam "Name=AbsoluteMaxRotAccel" "Parent=Absolute Movement Maximums" "Priority=Expert" "Type=int" "Desc=Absolute maximum rotational acceleration (in deg/sec/sec).  This cannot be exceeded under any circumstances." "Value=360" "Max=360" "Display=Visible:true"
CustomInfo: ConfigParam "Name=AbsoluteMaxRotDecel" "Parent=Absolute Movement Maximums" "Priority=Expert" "Type=int" "Desc=Absolute maximum rotational deceleration (in deg/sec/sec).  This cannot be exceeded under any circumstances.   WARNING!  Changing this parameter can adversely impact the robot's safe stopping distance.  This parameter must only be changed by trained safety personnel." "Value=360" "Max=360" "Display=Visible:true"
CustomInfo: ConfigParam "Name=AbsoluteMaxLatVel" "Parent=Absolute Movement Maximums" "Priority=Expert" "Type=int" "Desc=Absolute maximum lateral speed (in mm/sec).  This cannot be exceeded under any circumstances." "Value=2500" "Max=32767" "Display=Visible:false"
CustomInfo: ConfigParam "Name=AbsoluteMaxLatAccel" "Parent=Absolute Movement Maximums" "Priority=Expert" "Type=int" "Desc=Absolute maximum lateral acceleration (in mm/sec/sec).  This cannot be exceeded under any circumstances." "Value=2000" "Max=32767" "Display=Visible:false"
CustomInfo: ConfigParam "Name=AbsoluteMaxLatDecel" "Parent=Absolute Movement Maximums" "Priority=Expert" "Type=int" "Desc=Absolute maximum lateral deceleration (in mm/sec/sec).  This cannot be exceeded under any circumstances.  WARNING!  Changing this parameter can adversely impact the robot's safe stopping distance.  This parameter must only be changed by trained safety personnel." "Value=-2000" "Max=32767" "Display=Visible:false"
CustomInfo: ConfigSection "Name=Acuity Camera"
CustomInfo: ConfigParam "Name=CameraPower" "Parent=Acuity Camera" "Priority=Factory" "Type=string" "Desc=Peripheral output used to power Acuity camera" "Value=" "Display=Choices:;;Main_Laser_Power;;HMI_Power;;WheelLight_Power;;Sonar_1_Power;;Sonar_2_Power;;USB_1_and_2_Power;;USB_3_Power;;Vertical_Laser_Power;;Foot_Laser_Power;;Battery_Out_1;;Battery_Out_2;;Battery_Out_3_and_4;;Aux_5V;;Aux_12V;;Aux_20V;;Audio_Power"
CustomInfo: ConfigSection "Name=ARCL server setup"
CustomInfo: ConfigParam "Name=OpenTextServer" "Parent=ARCL server setup" "Priority=Important" "Type=bool" "Desc=Open the ARCL server. A Password must be specified below." "Value=true"
CustomInfo: ConfigParam "Name=PortNumber" "Parent=ARCL server setup" "Priority=Important" "Type=int" "Desc=TCP port on which to open the ARCL server." "Value=7171" "Max=65536"
CustomInfo: ConfigParam "Name=Password" "Parent=ARCL server setup" "Priority=Important" "Type=string" "Desc=Password used to connect to the ARCL server. If there is no password, the ARCL server will not start." "Value=omron"
CustomInfo: ConfigParam "Name=LogReceived" "Parent=ARCL server setup" "Priority=Expert" "Type=bool" "Desc=Log the text received by the ARCL server." "Value=true"
CustomInfo: ConfigParam "Name=LogSent" "Parent=ARCL server setup" "Priority=Expert" "Type=bool" "Desc=Log the text sent by the ARCL server." "Value=false"
CustomInfo: ConfigParam "Name=SessionTimeoutMins" "Parent=ARCL server setup" "Priority=Expert" "Type=double" "Desc=-1 (or any negative value) disables this feature, otherwise if the robot doesn't get any data from ARCL socket for this period of time it drops the connection. (note that this always uses at least 60 seconds if its enabled)... note that you can simply send a space character (with the new line feed) you don't need to send a command.  Note that this is a double so you can do a value like .25 for 15 seconds." "Value=-1" "Min=-1"
CustomInfo: ConfigParam "Name=ArclConfig" "Parent=ARCL server setup" "Priority=Expert" "Type=bool" "Desc=Allow config parameters to be changed via ARCL commands. Note that using these commands on an unsecured wireless network creates a security risk because ARCL passwords are sent in plain text." "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=ArclScan" "Parent=ARCL server setup" "Priority=Expert" "Type=bool" "Desc=Allow scanning to be controlled via ARCL commands. Note that using these commands can potentially be hazardous because scanning turns off localization." "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=ArclDisableMotors" "Parent=ARCL server setup" "Priority=Expert" "Type=bool" "Desc=Enable an ARCL command to disable the motors.  This acts as though the estop button was pressed, but without the hardware latching.  In general, this command should not be necessary." "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=ArclFreeMotors" "Parent=ARCL server setup" "Priority=Expert" "Type=bool" "Desc=Enable an ARCL command to free the motors.  This can be helpful when the user needs to release the brakes without pushing the EStop button. In general, this command should not be necessary." "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=" "Parent=ARCL server setup" "Priority=Expert" "Type=unknown" "Desc="
CustomInfo: ConfigSection "Name=Battery_1"
CustomInfo: ConfigParam "Name=BatteryAutoConnect" "Parent=Battery_1" "Priority=Expert" "Type=bool" "Desc=Battery_1 exists and should be automatically connected at startup." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=" "Parent=Battery_1" "Priority=Factory" "Type=unknown" "Desc="
CustomInfo: ConfigParam "Name=BatteryType" "Parent=Battery_1" "Priority=Expert" "Type=string" "Desc=Type of battery." "Value=mtx" "Display=Visible:BatteryAutoConnect=true&&Choices:mtx"
CustomInfo: ConfigParam "Name=BatteryPortType" "Parent=Battery_1" "Priority=Expert" "Type=string" "Desc=Port type that the battery is on." "Value=serial" "Display=Visible:BatteryAutoConnect=true&&Choices:serial;;serial422;;tcp"
CustomInfo: ConfigParam "Name=BatteryPort" "Parent=Battery_1" "Priority=Expert" "Type=string" "Desc=Port the battery is on." "Value=/dev/ttyUSB1" "Display=Visible:BatteryAutoConnect=true"
CustomInfo: ConfigParam "Name=BatteryBaud" "Parent=Battery_1" "Priority=Expert" "Type=int" "Desc=Baud rate to use for battery communication (9600, 19200, 38400, etc.)." "Value=115200" "Display=Visible:BatteryAutoConnect=true"
CustomInfo: ConfigSection "Name=Bumpers Settings"
CustomInfo: ConfigParam "Name=MaxSecondsToKeepCurrent" "Parent=Bumpers Settings" "Priority=Expert" "Type=int" "Desc=Duration (in sec) to store the current readings. If 0 or negative, then the readings are not automatically discarded based on age." "Value=15"
CustomInfo: ConfigParam "Name=MinDistBetweenCurrent" "Parent=Bumpers Settings" "Priority=Expert" "Type=double" "Desc=Minimum distance (in mm) between the stored current readings." "Value=0"
CustomInfo: ConfigParam "Name=UseCustomMaxRange" "Parent=Bumpers Settings" "Priority=Expert" "Type=bool" "Desc=When enabled (true), the specified CustomMaxRange is used instead of the default maximum range for the sensor. (Use with caution. This is an advanced option that should only be enabled by expert users.)" "Value=false"
CustomInfo: ConfigParam "Name=CustomMaxRange" "Parent=Bumpers Settings" "Priority=Expert" "Type=int" "Desc=Custom maximum range (in mm) for the sensor. This is applied only when UseCustomMaxRange is enabled. 0 means there is no maximum." "Value=0" "Min=0" "Display=Visible:UseCustomMaxRange=true"
CustomInfo: ConfigSection "Name=Call Button and I/O Devices"
