CustomInfo: ConfigParam "Name=Log" "Parent=Data Log Settings" "Priority=Expert" "Type=bool" "Desc=Enable logging of the selected data. If logging is turned off and on while ARAM is running, then new log entries are appended to the previous data log file if possible. (If the selected data types are changed, then a new log file is created.)" "Value=false"
CustomInfo: ConfigParam "Name=LogInterval" "Parent=Data Log Settings" "Priority=Expert" "Type=double" "Desc=Time (in sec) between data log entries.  0 means log data every cycle.  Fractional seconds are allowed, but note that the actual logging interval will vary slightly based on the execution cycles." "Value=0" "Min=0"
