CustomInfo: ConfigSection "Name=Debug Features"
CustomInfo: ConfigParam "Name=DisableDataLog" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=Disables data logging (data/dataLog_<robotName>_<yymmdd>_<hhmmss>)" "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=DisableBatterySimulation" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=Disables the feature that simulates robot SoC." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=DisableTorqueHandler" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=Disables the torque handler, this is something which lets us datalog the torque values from the motors." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=DisableHeadingHandler" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=Disables the heading handler, this is something which lets us datalog the heading from the robot." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=AcuityPylonRetry" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=Enables acuity camera retry" "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=Debug" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=Enable various debug options. This adds Custom Commands for debugging, and also publishes extra data for display in the client applications." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=WatchMotorPacket" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=When enabled, motor packet receive is watched, and SEGV shutdown is sent if none received in 30secs." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=WatchDoubleFree" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=When enabled, memory double free is watched, and SIGABRT shutdown is sent if memory is freed twice." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=DebugExternalIO" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=Enable logging of external I/O, via extIODump. This should only be enabled when debugging." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=DisableExternalIO" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=Disable the external I/O feature." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=DisableMarcConfiguration" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=Disables the MARC configuration feature" "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=DisableAccelHandler" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=Disables the accel handler, this is something which lets us datalog the accelerometer data and controls the robot tipped fault on the ARAM side." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=ZipInMapping" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=Automatically package scan files and associated data into a z2d container file when mapping is complete." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=DebugMakeServerTcpOnly" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=Only use TCP for server communications. This should generally be disabled unless there are problems with UDP." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=DisableCommMonitor" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=Do not monitor communication between the robot and any client applications, such as MobileEyes and MobilePlanner." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=DisableDefaultMapComposites" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=Disables all the default composite map objects" "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=DisableIgnoreLowLaserWhileDocking" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=Disables the feature that ignores low lasers while docking an LD or a Lynx" "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=LocalizationHistoryDrawing" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=Maintain a history of the localization data  for display in MobileEyes." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=AddConfigToMapping" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=When scanning, log the Aria configuration data in the scan file for debug purposes." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=" "Parent=Debug Features" "Priority=Expert" "Type=unknown" "Desc="
CustomInfo: ConfigParam "Name=DisableMemoryMonitorRestart" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=Disables the gentle software restart feature when memory monitor detects that the physical memory usage exceeds the memory threshold." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=LogMARCPowerStatusChanges" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=True to log any changes in MARC FPGA power status registers, false not to." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=LogMARCCoreVoltageChanges" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=True to log any changes from the MARC FPGA core voltages greater than 0.5V difference from the corresponding reference voltage, false not to." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=RestartSystemOnFault" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=True to restart system on occurrence of a fault, false not to. This must be set to true in addition to selecting faults for which system restart is needed." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=RestartSystemOn_AmpError" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=True to restart system on occurrence of this fault, false not to." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=DisableRobotOnIsGo" "Parent=Debug Features" "Priority=Expert" "Type=bool" "Desc=Check this to prevent the robot on (green button) from acting as a 'go' button." "Value=false" "Display=Checkbox"
CustomInfo: ConfigSection "Name=Debug log"
CustomInfo: ConfigParam "Name=MaxFileSizeMegs" "Parent=Debug log" "Priority=Expert" "Type=double" "Desc=Maximum size (in MB) of a single debug log in a plain text format i.e. before compression. This must be less than TotalMaxMegs, and preferably less than (TotalMaxMegs / 2) to store files from multiple runs." "Value=300" "Min=0"
CustomInfo: ConfigParam "Name=TotalMaxMegs" "Parent=Debug log" "Priority=Expert" "Type=double" "Desc=Maximum size (in MB) allocated to all of the debug logs i.e. the sum of the compressed files in the folder and the current file in plain text format." "Value=700" "Min=0"
CustomInfo: ConfigParam "Name=TotalNumFiles" "Parent=Debug log" "Priority=Expert" "Type=int" "Desc=Maximum number of debug logs to store. 0 means no limit." "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=RestartWhenFull" "Parent=Debug log" "Priority=Expert" "Type=bool" "Desc=Restart the debug log when it is full. This should generally be disabled, but exceptions may be necessary for tracking down transient problems. Overrides FreezeWhenFull." "Value=false"
CustomInfo: ConfigParam "Name=RestartWhenFullIfNotLost" "Parent=Debug log" "Priority=Expert" "Type=bool" "Desc=Restart the debug log when it is full provided that the robot is not lost. This should generally be disabled, but exceptions may be necessary for tracking down transient problems. Overrides FreezeWhenFull." "Value=true"
CustomInfo: ConfigParam "Name=FreezeWhenFull" "Parent=Debug log" "Priority=Expert" "Type=bool" "Desc=Freeze the debug log when it is full. When debug log is frozen, file writing is simply stopped and the file is not added to the container. (It will be added on the next restart however.) If RestartWhenFull is enabled, then this parameter is disregarded." "Value=false"
CustomInfo: ConfigParam "Name=RestartAcrossRuns" "Parent=Debug log" "Priority=Expert" "Type=bool" "Desc=Restart the debug log, if active, when ARAM is restarted. This should generally be disabled, but exceptions may be necessary for tracking down transient problems." "Value=false"
CustomInfo: ConfigParam "Name=RestartAcrossRunsIfNotLost" "Parent=Debug log" "Priority=Expert" "Type=bool" "Desc=Restart the debug log, if active, when ARAM restarts and the robot is not lost. This should generally be disabled, but exceptions may be necessary for tracking down transient problems." "Value=true"
CustomInfo: ConfigSection "Name=Destination Drawing"
CustomInfo: ConfigParam "Name=DrawingMode" "Parent=Destination Drawing" "Priority=Expert" "Type=string" "Desc=How the destination indicator is drawn." "Value=AlwaysOff" "Display=Choices:AlwaysOff;;AlwaysOn;;Flash&&Status:Deprecated"
CustomInfo: ConfigParam "Name=FlashMSec" "Parent=Destination Drawing" "Priority=Expert" "Type=int" "Desc=Rate (in ms) at which the destination should be flashed. Valid only when DrawingMode is set to Flash. 0 to disable drawing." "Value=1000" "Min=0" "Display=Status:Deprecated"
CustomInfo: ConfigParam "Name=Shape" "Parent=Destination Drawing" "Priority=Expert" "Type=string" "Desc=Shape to be drawn for the destination indicator." "Value=polyDots" "Display=Choices:polyDots;;polyArrows;;polyLine;;polyPoints;;polySegments&&Status:Deprecated"
CustomInfo: ConfigParam "Name=PrimaryColor" "Parent=Destination Drawing" "Priority=Expert" "Type=int" "Desc=Primary drawing color for the destination indicator." "Value=16776960" "Max=16777215" "Display=Color&&Status:Deprecated"
CustomInfo: ConfigParam "Name=SecondaryColor" "Parent=Destination Drawing" "Priority=Expert" "Type=int" "Desc=Secondary drawing color for the destination indicator." "Value=0" "Max=16777215" "Display=Color&&Status:Deprecated"
CustomInfo: ConfigParam "Name=Size" "Parent=Destination Drawing" "Priority=Expert" "Type=int" "Desc=Size (in mm) of the destination indicator." "Value=800" "Min=0" "Display=Status:Deprecated"
CustomInfo: ConfigParam "Name=Layer" "Parent=Destination Drawing" "Priority=Expert" "Type=int" "Desc=Map layer on which the destination indicator is drawn." "Value=49" "Min=0" "Display=Status:Deprecated"
CustomInfo: ConfigParam "Name=RefreshTime" "Parent=Destination Drawing" "Priority=Expert" "Type=int" "Desc=Rate (in ms) at which to refresh the destination indicator." "Value=200" "Min=50" "Display=Status:Deprecated"
CustomInfo: ConfigSection "Name=Docking"
CustomInfo: ConfigParam "Name=SA_MotionMode" "Parent=Docking" "Priority=Normal" "Type=string" "Desc=" "Value=AGV" "Display=Visible:UseSelectableAutonomy=true&&Choices:AGV;;Straight&&"
CustomInfo: ConfigParam "Name=SA_ObstacleMode" "Parent=Docking" "Priority=Normal" "Type=string" "Desc=" "Value=None" "Display=Visible:UseSelectableAutonomy=true&&Choices:None;;Wait&&"
