CustomInfo: ConfigParam "Name=AutoDock" "Parent=Docking" "Priority=Normal" "Type=bool" "Desc=True if we should automatically dock" "Value=false"
CustomInfo: ConfigParam "Name=AutoDockStateOfCharge" "Parent=Docking" "Priority=Normal" "Type=double" "Desc=If auto docking the robot state of charge to automatically dock at" "Value=0" "Max=100"
CustomInfo: ConfigParam "Name=AutoDockIdleTime" "Parent=Docking" "Priority=Normal" "Type=double" "Desc=If auto docking the idle time in minutes until auto dock (0 means never auto dock because of idle)" "Value=5" "Min=0"
CustomInfo: ConfigParam "Name=PreferredDock" "Parent=Docking" "Priority=Normal" "Type=string" "Desc=If there is a charger with this name this robot will use that dock if either OnlyUsePreferredDock is true or the dock is available.  If one of those conditions isn't met or a charger of this name does not exist then the default behavior of using the closest dock (by geometric distance) will apply." "Value=" "Display=MapItem:DockLynx|SubTypeAndParent|Optional"
CustomInfo: ConfigParam "Name=OnlyUsePreferredDock" "Parent=Docking" "Priority=Normal" "Type=bool" "Desc=If this is true the robot will only use the preferred dock (which will prevent other robots from using it in a central multirobot setup)" "Value=false" "Display=MapItem:DockLynx|SubTypeAndParent|Optional"
CustomInfo: ConfigParam "Name=DockUntilDoneCharging" "Parent=Docking" "Priority=Normal" "Type=bool" "Desc=If true then the robot will dock until it is done charging (in float mode)" "Value=true"
CustomInfo: ConfigParam "Name=MinutesToChargeFor" "Parent=Docking" "Priority=Normal" "Type=int" "Desc=If 0 don't finish charging based on time, if -1 then just undock as soon as docked (mostly for testing) if greater than 0 then be done charging after this many minutes" "Value=0" "Min=-1"
CustomInfo: ConfigParam "Name=StateOfChargeToChargeTo" "Parent=Docking" "Priority=Normal" "Type=double" "Desc=If 0 don't finish charging based on state of charge, if greater than 0 then be done charging after robot's state of charge reaches this point" "Value=0" "Max=100"
CustomInfo: ConfigParam "Name=MinutesBetweenAutoDock" "Parent=Docking" "Priority=Normal" "Type=int" "Desc=If 0 don't limit how often the robot can charge, if greater than 0 then this many minutes will elapse between when the robot last docked and when it will autodock" "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=FailedDriveInIgnoreMinutes" "Parent=Docking" "Priority=Normal" "Type=double" "Desc=The number of minutes to ignore a dock after the robot has failed to drive into it too many times (FailedDriveInAttemptsBeforeIgnore)." "Value=60" "Min=1"
CustomInfo: ConfigParam "Name=FailedDriveInAttemptsBeforeIgnore" "Parent=Docking" "Priority=Normal" "Type=int" "Desc=The number of times to try to drive into a dock before ignoring it (for FailedDriveInIgnoreMinutes)...  0 means never to ignore a dock for this reason." "Value=3" "Min=0"
CustomInfo: ConfigParam "Name=SameDockDistanceTolerance" "Parent=Docking" "Priority=Expert" "Type=double" "Desc=For cases where overrideMapName has been used docks within this distance and within SameDockAngleTolerance are counted as the same for purposes of seeing which docks are occupied by other robots." "Value=1000" "Min=1" "Display=Status:Deprecated"
CustomInfo: ConfigParam "Name=SameDockAngleTolerance" "Parent=Docking" "Priority=Expert" "Type=double" "Desc=For cases where overrideMapName has been used docks within this angular tolerance and within SameDockDistanceTolerance are counted as the same for purposes of seeing which docks are occupied by other robots." "Value=10" "Min=1" "Display=Status:Deprecated"
CustomInfo: ConfigParam "Name=AutoDockShutdownMinutes" "Parent=Docking" "Priority=Normal" "Type=int" "Desc=This controls how long the robot should wait before shutting down if it cannot move on its way to the dock while in a low battery situation.  0 means do not automatically shutdown for this reason, any other value is how many minutes to wait before shutting down" "Value=0" "Max=60"
CustomInfo: ConfigParam "Name=UnforcedDockShutdownMinutes" "Parent=Docking" "Priority=Normal" "Type=int" "Desc=This controls how long the robot should wait before shutting down if it cannot move on its way to the dock if docking because the robot was idle or an explicit dock request was made.  0 means do not automatically shutdown for this reason, any other value is how many minutes to wait before shutting down" "Value=0" "Max=60"
CustomInfo: ConfigParam "Name=FinalOffsetX" "Parent=Docking" "Priority=Normal" "Type=double" "Desc=Final axial distance in mm from the target center to the AMR center in the coordinate system of the specified target" "Value=-1000" "Max=-300"
CustomInfo: ConfigParam "Name=FinalOffsetY" "Parent=Docking" "Priority=Normal" "Type=double" "Desc=Final lateral distance in mm from the target center to the AMR center in the coordinate system of the specified target" "Value=0" "Max=250"
