CustomInfo: ConfigSection "Name=Driving problem response"
CustomInfo: ConfigParam "Name=BumpStopAndFailEnabled" "Parent=Driving problem response" "Priority=Expert" "Type=bool" "Desc=When enabled (true), the robot stops for bumps and may eventually fail due to them. When disabled, the robot always tries to extricate itself from the bump." "Value=false"
CustomInfo: ConfigParam "Name=BumpSecondsToWait" "Parent=Driving problem response" "Priority=Expert" "Type=int" "Desc=Time (in sec) for the robot to wait before moving after a bump." "Value=5"
CustomInfo: ConfigParam "Name=BumpSecondsToFail" "Parent=Driving problem response" "Priority=Expert" "Type=int" "Desc=Minimum acceptable interval (in sec) between bumps. If more than one bump occurs during this time period, the robot fails to go to its goal." "Value=5"
CustomInfo: ConfigParam "Name=EmergencyStopFailEnabled" "Parent=Driving problem response" "Priority=Expert" "Type=bool" "Desc=Fail if the emergency stop is pressed." "Value=true"
CustomInfo: ConfigParam "Name=LostFailEnabled" "Parent=Driving problem response" "Priority=Expert" "Type=bool" "Desc=Fail going to a goal if the robot becomes lost." "Value=true"
CustomInfo: ConfigParam "Name=LostFailEnabled" "Parent=Driving problem response" "Priority=Expert" "Type=bool" "Desc=Fail going to a goal if the robot becomes lost." "Value=true"
