CustomInfo: ConfigParam "Name=TimeHorizon" "Parent=Dynamic Obstacles" "Priority=Expert" "Type=double" "Desc=How long in the future to predict obstacle motions (sec)" "Value=7.5" "Max=10" "Display=Visible:Enable=true"
CustomInfo: ConfigParam "Name=MinAvoidanceSpeed" "Parent=Dynamic Obstacles" "Priority=Expert" "Type=double" "Desc=Minimum speed to consider an obstacle in path planning (mm/s)" "Value=300" "Max=2000" "Display=Visible:Enable=true"
CustomInfo: ConfigParam "Name=MinObstacleAge" "Parent=Dynamic Obstacles" "Priority=Expert" "Type=double" "Desc=Minimum age of an obstacle before it is considered in path planning (s)" "Value=0.3" "Min=0" "Display=Visible:Enable=true"
CustomInfo: ConfigParam "Name=ForceWithMultirobot" "Parent=Dynamic Obstacles" "Priority=Expert" "Type=bool" "Desc=Force dynamic tracking when multirobot is enabled through an EM" "Value=false" "Display=Visible:Enable=true&&Checkbox"
CustomInfo: ConfigParam "Name=MinReadings" "Parent=Dynamic Obstacles" "Priority=Expert" "Type=int" "Desc=Minimum number of readings that are clustered into an obstacle observation" "Value=3" "Min=3" "Display=Visible:Enable=true"
CustomInfo: ConfigParam "Name=MaxNeighborDistance" "Parent=Dynamic Obstacles" "Priority=Expert" "Type=double" "Desc=Maximum distance between laser readings for which they can be together (mm)" "Value=500" "Max=1000" "Display=Visible:Enable=true"
CustomInfo: ConfigParam "Name=MatchLikelihood" "Parent=Dynamic Obstacles" "Priority=Expert" "Type=string" "Desc=Percent likelihood that a reading will be found for an obstacle. The percentage defines a distance proportional to the obstacle's standard deviation. If a cluster of laser readings is further from the obstacle than that distance, it cannot be an observation for that obstacle" "Value=95" "Display=Visible:Enable=true&&Choices:99;;97.5;;95;;90;;75"
CustomInfo: ConfigParam "Name=DisableFilterOccGrid" "Parent=Dynamic Obstacles" "Priority=Expert" "Type=bool" "Desc=Disable the occupancy grid to filter out static obstacle" "Value=false" "Display=Visible:Enable=true&&Checkbox"
CustomInfo: ConfigParam "Name=FilterOccGridThresh" "Parent=Dynamic Obstacles" "Priority=Expert" "Type=double" "Desc=Threshold for when a cell is considered static in the filtering occ grid (s). If something remains in a single grid cell for this many seconds, it is ignored in tracking" "Value=0.5" "Min=0" "Display=Visible:Enable=true&&Visible:DisableFilterOccGrid=false"
CustomInfo: ConfigParam "Name=MaxFilterOccGridValue" "Parent=Dynamic Obstacles" "Priority=Expert" "Type=double" "Desc=Maximum value a cell in the filter occupancy grid can obtain (s)" "Value=2.5" "Min=0" "Display=Visible:Enable=true&&Visible:DisableFilterOccGrid=false"
CustomInfo: ConfigParam "Name=PrimaryLaser" "Parent=Dynamic Obstacles" "Priority=Expert" "Type=string" "Desc=Primary Laser to use" "Value=Laser_1" "Display=Visible:Enable=true&&Choices:Laser_1;;Laser_2;;Laser_3;;Laser_4;;Laser_5;;Laser_6"
CustomInfo: ConfigParam "Name=SecondaryLaser" "Parent=Dynamic Obstacles" "Priority=Expert" "Type=string" "Desc=Secondary Laser to use" "Value=None" "Display=Visible:Enable=true&&Choices:None;;Laser_1;;Laser_2;;Laser_3;;Laser_4;;Laser_5;;Laser_6"
