CustomInfo: ConfigParam "Name=RobotLanguage" "Parent=Language/Location" "Priority=Normal" "Type=string" "Desc=Language displayed on the robot's touchscreen and used in the information sent by the robot to clients, e.g.MobilePlanner. If a language is supported only on the robot's touchscreen but not on all of the robot's software yet (e.g. French, German), the information sent by the robot to the clients will default to English, but the touchscreen will use the selected language. If the value is modified, the software will restart for the new language to take effect. This parameter does not set the language for Speech Synthesis." "Value=English" "Display=Choices:English;;Chinese-Simplified;;Chinese-Traditional;;Czech;;French;;German;;Italian;;Japanese;;Korean;;Polish;;Spanish"
CustomInfo: ConfigParam "Name=Voice_Selection" "Parent=Language/Location" "Priority=Expert" "Type=unknown" "Desc=Voice selection for speech synthesis."
CustomInfo: ConfigSection "Name=Laser_1"
CustomInfo: ConfigParam "Name=LaserAutoConnect" "Parent=Laser_1" "Priority=Expert" "Type=bool" "Desc=Laser_1 exists and should be automatically connected at startup." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=" "Parent=Laser_1" "Priority=Factory" "Type=unknown" "Desc="
CustomInfo: ConfigParam "Name=LaserX" "Parent=Laser_1" "Priority=Expert" "Type=int" "Desc=Location (in mm) of the laser in X (+ front, - back) relative to the robot's idealized center of rotation." "Value=485" "Display=Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserY" "Parent=Laser_1" "Priority=Expert" "Type=int" "Desc=Location (in mm) of the laser in Y (+ left, - right) relative to the robot's idealized center of rotation." "Value=0" "Display=Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserTh" "Parent=Laser_1" "Priority=Expert" "Type=double" "Desc=Rotation (in deg) of the laser (+ counterclockwise, - clockwise)." "Value=0" "Max=180" "Display=Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserZ" "Parent=Laser_1" "Priority=Expert" "Type=int" "Desc=Height (in mm) of the laser from the ground. 0 means unknown." "Value=195" "Min=0" "Display=Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserIgnore" "Parent=Laser_1" "Priority=Expert" "Type=string" "Desc=Angles (in deg) at which to ignore readings, +/1 one degree. Ranges are entered as start:end. Multiple ranges may be separated by commas." "Value=-135:-80,80:135" "Display=Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserFlipped" "Parent=Laser_1" "Priority=Expert" "Type=bool" "Desc=Laser_1 is upside-down." "Value=true" "Display=Visible:LaserAutoConnect=true&&Checkbox"
CustomInfo: ConfigParam "Name=LaserType" "Parent=Laser_1" "Priority=Expert" "Type=string" "Desc=Type of laser." "Value=os32c" "Display=Visible:LaserAutoConnect=true&&Choices:s3series;;tim3XX;;tim510;;tim551;;os32c;;os32cethernet"
CustomInfo: ConfigParam "Name=LaserPortType" "Parent=Laser_1" "Priority=Expert" "Type=string" "Desc=Type of port the laser is on." "Value=serial422" "Display=Visible:LaserAutoConnect=true&&Choices:serial;;serial422;;tcp"
CustomInfo: ConfigParam "Name=LaserPort" "Parent=Laser_1" "Priority=Expert" "Type=string" "Desc=Port the laser is on." "Value=/dev/ttyUSB4" "Display=Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserPowerOutput" "Parent=Laser_1" "Priority=Expert" "Type=string" "Desc=Power output that controls this laser's power." "Value=" "Display=Visible:LaserAutoConnect=true&&Choices:;;Main_Laser_Power;;HMI_Power;;WheelLight_Power;;Sonar_1_Power;;Sonar_2_Power;;USB_1_and_2_Power;;USB_3_Power;;Vertical_Laser_Power;;Foot_Laser_Power;;Battery_Out_1;;Battery_Out_2;;Battery_Out_3_and_4;;Aux_5V;;Aux_12V;;Aux_20V;;Audio_Power"
CustomInfo: ConfigParam "Name=LaserStartingBaudChoice" "Parent=Laser_1" "Priority=Expert" "Type=string" "Desc=StartingBaud for this laser. Leave blank to use the default." "Value=921600" "Display=Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserAutoBaudChoice" "Parent=Laser_1" "Priority=Expert" "Type=string" "Desc=AutoBaud for this laser. Leave blank to use the default." "Value=" "Display=Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserIsLow" "Parent=Laser_1" "Priority=Expert" "Type=bool" "Desc=If this laser is a low laser for sensing low obstacles (like feet, pallets, etc)." "Value=false" "Display=Checkbox&&Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserIsForCartSensing" "Parent=Laser_1" "Priority=Expert" "Type=bool" "Desc=If this laser is the one mounted in the top deck for sensing the cart.  This laser is ignored by path planning." "Value=false" "Display=Checkbox&&Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserIsTilted" "Parent=Laser_1" "Priority=Expert" "Type=bool" "Desc=The laser is tilted for sensing positive obstacles, i.e. ones above the ground." "Value=false" "Display=Checkbox&&Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=TiltedFlipped" "Parent=Laser_1" "Priority=Expert" "Type=bool" "Desc=Flip the raw readings from the tilted laser upside-down. Applicable only when LaserIsTilted or LaserIsTiltedNegativeSensor." "Value=false" "Display=Checkbox&&Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserIsTiltedNegativeSensor" "Parent=Laser_1" "Priority=Expert" "Type=bool" "Desc=Tilted lasers can be used as a secondary protection method against robots encountering negative obstacles (loading docks, stairs, etc.). This detection is only possible in the sensing plane of the tilted laser and cannot be used as the sole means of negative obstacle avoidance. Other primary protection methods should always be used. Talk to your robot provider before using this feature. This is still an experimental beta feature." "Value=false" "Display=Checkbox&&Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserIsFiltered" "Parent=Laser_1" "Priority=Expert" "Type=bool" "Desc=Readings from the laser must be filtered. This may need to be enabled when the laser can detect the robot's casters (for example). If LaserIsTilted or LaserIsTiltedNegativeSensor is enabled, then this option is disregarded." "Value=false" "Display=Checkbox&&Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserIsFiltered_v2" "Parent=Laser_1" "Priority=Expert" "Type=bool" "Desc=Readings from the laser must be filtered with the version 2 filter that works even when LaserIsTilted or LaserIsTiltedNegativeSensor is enabled. Like the original LaserIsFiltered parameter, this may need to be enabled when the laser can detect the robot's casters (for example). When enabled, this overrides the LaserIsFiltered value." "Value=true" "Display=Checkbox&&Visible:LaserAutoConnect=true"
CustomInfo: ConfigSection "Name=Laser_1 Settings"
CustomInfo: ConfigParam "Name=" "Parent=Laser_1 Settings" "Priority=Expert" "Type=unknown" "Desc="
CustomInfo: ConfigParam "Name=Filter_v2_Disable" "Parent=Laser_1 Settings" "Priority=Expert" "Type=bool" "Desc=If this filter should be disabled.  This is redundant with the enable in the Laser sections in Robot Physical but exists so that the filtering can easily be toggled on a whole fleet." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=Filter_v2_MinValidReading" "Parent=Laser_1 Settings" "Priority=Expert" "Type=int" "Desc=Filter out ANY readings that are closer than this such that they they aren't used for other filtering (meaning it's to compensate for laser problems rather than actual seen objects). (mm)" "Value=0" "Min=0" "Display=Visible:Filter_v2_Disable=false"
CustomInfo: ConfigParam "Name=Filter_v2_Width" "Parent=Laser_1 Settings" "Priority=Expert" "Type=double" "Desc=How wide (relative to the laser ray) of an area in mm to look for close readings to indicate this reading should not be filtered. Negative values turn off this filtering.  (mm)" "Value=-1" "Max=200" "Display=Visible:Filter_v2_Disable=false"
CustomInfo: ConfigParam "Name=Filter_v2_CloseLength" "Parent=Laser_1 Settings" "Priority=Expert" "Type=double" "Desc=The difference in distance in mm from the laser that makes a reading count as 'close' to a reading being checked. (mm)" "Value=250" "Max=1000" "Display=Visible:Filter_v2_Disable=false"
CustomInfo: ConfigParam "Name=Filter_v2_SingleMaxDistFromLaser" "Parent=Laser_1 Settings" "Priority=Expert" "Type=double" "Desc=Filter out single readings that do not have a close neighbor out to this distance from the laser itself (this does not take into account the position of the laser on the robot).  Negative values turn off this filtering.  (mm)" "Value=-1" "Min=-1" "Display=Visible:Filter_v2_Disable=false"
CustomInfo: ConfigParam "Name=Filter_v2_SingleCloseLength" "Parent=Laser_1 Settings" "Priority=Expert" "Type=double" "Desc=The difference in distance in mm from the laser that makes a reading count as 'close' to a reading being checked. (mm)" "Value=250" "Max=1000" "Display=Visible:Filter_v2_Disable=false"
CustomInfo: ConfigParam "Name=MinDistBetweenCurrent" "Parent=Laser_1 Settings" "Priority=Expert" "Type=double" "Desc=Minimum distance (in mm) between the stored current readings." "Value=0"
CustomInfo: ConfigParam "Name=CumulativeBufferSize" "Parent=Laser_1 Settings" "Priority=Expert" "Type=int" "Desc=Maximum number of readings to store in the cumulative buffer. Changes to this value can have a significant effect on CPU use due to the overhead associated with cleaning the cumulative readings." "Value=200"
CustomInfo: ConfigParam "Name=MaxSecondsToKeepCumulative" "Parent=Laser_1 Settings" "Priority=Expert" "Type=int" "Desc=Duration (in sec) to store the cumulative readings. If 0 or negative, then the cumulative readings are not automatically discarded based on age." "Value=30"
CustomInfo: ConfigParam "Name=MaxDistToKeepCumulative" "Parent=Laser_1 Settings" "Priority=Expert" "Type=double" "Desc=Maximum distance (in mm) allowed between the current pose and the stored cumulative readings. If a reading exceeds this distance, it is discarded. If 0 or negative, then the cumulative readings are not automatically discarded based on distance." "Value=4000"
CustomInfo: ConfigParam "Name=MinDistBetweenCumulative" "Parent=Laser_1 Settings" "Priority=Expert" "Type=double" "Desc=Minimum distance (in mm) between the cumulative readings. If 0 or negative, then readings are not discarded due to their proximity to each other." "Value=200"
CustomInfo: ConfigParam "Name=MaxInsertDistCumulative" "Parent=Laser_1 Settings" "Priority=Expert" "Type=double" "Desc=Maximum distance (in mm) allowed between the current robot position and the new cumulative reading. If a reading exceeds this distance, then it will not be inserted into the cumulative readings." "Value=3000"
CustomInfo: ConfigParam "Name=CumulativeCleanDist" "Parent=Laser_1 Settings" "Priority=Expert" "Type=double" "Desc=Minimum distance (in mm) between the stored cumulative readings and the current beams. If this is 0 or negative, then readings are not discarded due to their proximity to the beams." "Value=75"
CustomInfo: ConfigParam "Name=CumulativeCleanInterval" "Parent=Laser_1 Settings" "Priority=Expert" "Type=int" "Desc=Interval (in msecs) at which to clean the cumulative readings." "Value=1000"
CustomInfo: ConfigParam "Name=UseCustomMaxRange" "Parent=Laser_1 Settings" "Priority=Expert" "Type=bool" "Desc=When enabled (true), the specified CustomMaxRange is used instead of the default maximum range for the sensor. (Use with caution. This is an advanced option that should only be enabled by expert users.)" "Value=false"
CustomInfo: ConfigParam "Name=CustomMaxRange" "Parent=Laser_1 Settings" "Priority=Expert" "Type=int" "Desc=Custom maximum range (in mm) for the sensor. This is applied only when UseCustomMaxRange is enabled. 0 means there is no maximum." "Value=0" "Min=0" "Display=Visible:UseCustomMaxRange=true"
