CustomInfo: ConfigParam "Name=LaserPowerOutput" "Parent=Laser_2" "Priority=Expert" "Type=string" "Desc=Power output that controls this laser's power." "Value=Foot_Laser_Power" "Display=Visible:LaserAutoConnect=true&&Choices:;;Main_Laser_Power;;HMI_Power;;WheelLight_Power;;Sonar_1_Power;;Sonar_2_Power;;USB_1_and_2_Power;;USB_3_Power;;Vertical_Laser_Power;;Foot_Laser_Power;;Battery_Out_1;;Battery_Out_2;;Battery_Out_3_and_4;;Aux_5V;;Aux_12V;;Aux_20V;;Audio_Power"
CustomInfo: ConfigParam "Name=LaserStartingBaudChoice" "Parent=Laser_2" "Priority=Expert" "Type=string" "Desc=StartingBaud for this laser. Leave blank to use the default." "Value=" "Display=Visible:LaserAutoConnect=true"
