CustomInfo: ConfigParam "Name=LaserPowerOutput" "Parent=Laser_4" "Priority=Expert" "Type=string" "Desc=Power output that controls this laser's power." "Value=Vertical_Laser_Power" "Display=Visible:LaserAutoConnect=true&&Choices:;;Main_Laser_Power;;HMI_Power;;WheelLight_Power;;Sonar_1_Power;;Sonar_2_Power;;USB_1_and_2_Power;;USB_3_Power;;Vertical_Laser_Power;;Foot_Laser_Power;;Battery_Out_1;;Battery_Out_2;;Battery_Out_3_and_4;;Aux_5V;;Aux_12V;;Aux_20V;;Audio_Power"
CustomInfo: ConfigParam "Name=LaserStartingBaudChoice" "Parent=Laser_4" "Priority=Expert" "Type=string" "Desc=StartingBaud for this laser. Leave blank to use the default." "Value=" "Display=Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserAutoBaudChoice" "Parent=Laser_4" "Priority=Expert" "Type=string" "Desc=AutoBaud for this laser. Leave blank to use the default." "Value=" "Display=Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserIsLow" "Parent=Laser_4" "Priority=Expert" "Type=bool" "Desc=If this laser is a low laser for sensing low obstacles (like feet, pallets, etc)." "Value=false" "Display=Checkbox&&Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserIsForCartSensing" "Parent=Laser_4" "Priority=Expert" "Type=bool" "Desc=If this laser is the one mounted in the top deck for sensing the cart.  This laser is ignored by path planning." "Value=false" "Display=Checkbox&&Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserIsTilted" "Parent=Laser_4" "Priority=Expert" "Type=bool" "Desc=The laser is tilted for sensing positive obstacles, i.e. ones above the ground." "Value=true" "Display=Checkbox&&Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=TiltedFlipped" "Parent=Laser_4" "Priority=Expert" "Type=bool" "Desc=Flip the raw readings from the tilted laser upside-down. Applicable only when LaserIsTilted or LaserIsTiltedNegativeSensor." "Value=false" "Display=Checkbox&&Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserIsTiltedNegativeSensor" "Parent=Laser_4" "Priority=Expert" "Type=bool" "Desc=Tilted lasers can be used as a secondary protection method against robots encountering negative obstacles (loading docks, stairs, etc.). This detection is only possible in the sensing plane of the tilted laser and cannot be used as the sole means of negative obstacle avoidance. Other primary protection methods should always be used. Talk to your robot provider before using this feature. This is still an experimental beta feature." "Value=false" "Display=Checkbox&&Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserIsFiltered" "Parent=Laser_4" "Priority=Expert" "Type=bool" "Desc=Readings from the laser must be filtered. This may need to be enabled when the laser can detect the robot's casters (for example). If LaserIsTilted or LaserIsTiltedNegativeSensor is enabled, then this option is disregarded." "Value=false" "Display=Checkbox&&Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserIsFiltered_v2" "Parent=Laser_4" "Priority=Expert" "Type=bool" "Desc=Readings from the laser must be filtered with the version 2 filter that works even when LaserIsTilted or LaserIsTiltedNegativeSensor is enabled. Like the original LaserIsFiltered parameter, this may need to be enabled when the laser can detect the robot's casters (for example). When enabled, this overrides the LaserIsFiltered value." "Value=true" "Display=Checkbox&&Visible:LaserAutoConnect=true"
CustomInfo: ConfigSection "Name=Laser_5"
CustomInfo: ConfigParam "Name=LaserAutoConnect" "Parent=Laser_5" "Priority=Expert" "Type=bool" "Desc=Laser_5 exists and should be automatically connected at startup." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=" "Parent=Laser_5" "Priority=Factory" "Type=unknown" "Desc="
CustomInfo: ConfigParam "Name=LaserX" "Parent=Laser_5" "Priority=Expert" "Type=int" "Desc=Location (in mm) of the laser in X (+ front, - back) relative to the robot's idealized center of rotation." "Value=0" "Display=Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserY" "Parent=Laser_5" "Priority=Expert" "Type=int" "Desc=Location (in mm) of the laser in Y (+ left, - right) relative to the robot's idealized center of rotation." "Value=0" "Display=Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserTh" "Parent=Laser_5" "Priority=Expert" "Type=double" "Desc=Rotation (in deg) of the laser (+ counterclockwise, - clockwise)." "Value=-180" "Max=180" "Display=Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserZ" "Parent=Laser_5" "Priority=Expert" "Type=int" "Desc=Height (in mm) of the laser from the ground. 0 means unknown." "Value=0" "Min=0" "Display=Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserIgnore" "Parent=Laser_5" "Priority=Expert" "Type=string" "Desc=Angles (in deg) at which to ignore readings, +/1 one degree. Angles are entered as strings, separated by a space." "Value=" "Display=Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserFlipped" "Parent=Laser_5" "Priority=Expert" "Type=bool" "Desc=Laser_5 is upside-down." "Value=false" "Display=Visible:LaserAutoConnect=true&&Checkbox"
CustomInfo: ConfigParam "Name=LaserType" "Parent=Laser_5" "Priority=Expert" "Type=string" "Desc=Type of laser." "Value=tim3XX" "Display=Visible:LaserAutoConnect=true&&Choices:s3series;;tim3XX;;tim510;;tim551;;os32c;;os32cethernet"
CustomInfo: ConfigParam "Name=LaserPortType" "Parent=Laser_5" "Priority=Expert" "Type=string" "Desc=Type of port the laser is on." "Value=serial" "Display=Visible:LaserAutoConnect=true&&Choices:serial;;serial422;;tcp"
CustomInfo: ConfigParam "Name=LaserPort" "Parent=Laser_5" "Priority=Expert" "Type=string" "Desc=Port the laser is on." "Value=/dev/ttyUSB11" "Display=Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserPowerOutput" "Parent=Laser_5" "Priority=Expert" "Type=string" "Desc=Power output that controls this laser's power." "Value=Aux_20V" "Display=Visible:LaserAutoConnect=true&&Choices:;;Main_Laser_Power;;HMI_Power;;WheelLight_Power;;Sonar_1_Power;;Sonar_2_Power;;USB_1_and_2_Power;;USB_3_Power;;Vertical_Laser_Power;;Foot_Laser_Power;;Battery_Out_1;;Battery_Out_2;;Battery_Out_3_and_4;;Aux_5V;;Aux_12V;;Aux_20V;;Audio_Power"
CustomInfo: ConfigParam "Name=LaserStartingBaudChoice" "Parent=Laser_5" "Priority=Expert" "Type=string" "Desc=StartingBaud for this laser. Leave blank to use the default." "Value=" "Display=Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserAutoBaudChoice" "Parent=Laser_5" "Priority=Expert" "Type=string" "Desc=AutoBaud for this laser. Leave blank to use the default." "Value=" "Display=Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserIsLow" "Parent=Laser_5" "Priority=Expert" "Type=bool" "Desc=If this laser is a low laser for sensing low obstacles (like feet, pallets, etc)." "Value=false" "Display=Checkbox&&Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserIsForCartSensing" "Parent=Laser_5" "Priority=Expert" "Type=bool" "Desc=If this laser is the one mounted in the top deck for sensing the cart.  This laser is ignored by path planning." "Value=false" "Display=Checkbox&&Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserIsTilted" "Parent=Laser_5" "Priority=Expert" "Type=bool" "Desc=The laser is tilted for sensing positive obstacles, i.e. ones above the ground." "Value=false" "Display=Checkbox&&Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=TiltedFlipped" "Parent=Laser_5" "Priority=Expert" "Type=bool" "Desc=Whether to flip the raw laser readings in the tilted laser" "Value=false" "Display=Checkbox&&Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserIsTiltedNegativeSensor" "Parent=Laser_5" "Priority=Expert" "Type=bool" "Desc=Tilted lasers can be used as a secondary protection method against robots encountering negative obstacles (loading docks, stairs, etc.). This detection is only possible in the sensing plane of the tilted laser and cannot be used as the sole means of negative obstacle avoidance. Other primary protection methods should always be used. Talk to your robot provider before using this feature. This is still an experimental beta feature." "Value=false" "Display=Checkbox&&Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserIsFiltered" "Parent=Laser_5" "Priority=Expert" "Type=bool" "Desc=If the laser readings need to be filtered (thus far this is only the case for lasers that can see the casters). This option will not take effect if the laser is tilted, is a tilted negative sensor, or is filted with the _v2 filter." "Value=false" "Display=Checkbox&&Visible:LaserAutoConnect=true"
CustomInfo: ConfigParam "Name=LaserIsFiltered_v2" "Parent=Laser_5" "Priority=Expert" "Type=bool" "Desc=If the lasers readings should be filtered with the version 2 filter.  This will work with LaserIsTilted and LaserIsTiltedNegativeSensor.   If true it'll override LaserIsFiltered" "Value=false" "Display=Checkbox&&Visible:LaserAutoConnect=true"
CustomInfo: ConfigSection "Name=LCD_1"
CustomInfo: ConfigParam "Name=LCDAutoConnect" "Parent=LCD_1" "Priority=Expert" "Type=bool" "Desc=LCD_1 exists and should be automatically connected on startup." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=LCDDisconnectOnConnectFailure" "Parent=LCD_1" "Priority=Expert" "Type=bool" "Desc=When enabled (true), this indicates that the LCD is a required component. If ARAM cannot communicate with a required LCD, the robot will restart." "Value=false" "Display=Visible:LCDAutoConnect=true&&Checkbox"
CustomInfo: ConfigParam "Name=" "Parent=LCD_1" "Priority=Factory" "Type=unknown" "Desc="
CustomInfo: ConfigParam "Name=LCDType" "Parent=LCD_1" "Priority=Expert" "Type=string" "Desc=Type of LCD." "Value=mtx" "Display=Visible:LCDAutoConnect=true&&Choices:mtx"
CustomInfo: ConfigParam "Name=LCDPortType" "Parent=LCD_1" "Priority=Expert" "Type=string" "Desc=Port type for the LCD." "Value=serial422" "Display=Visible:LCDAutoConnect=true&&Choices:serial;;serial422;;tcp"
CustomInfo: ConfigParam "Name=LCDPort" "Parent=LCD_1" "Priority=Expert" "Type=string" "Desc=Port on which the LCD is connected." "Value=/dev/ttyUSB8" "Display=Visible:LCDAutoConnect=true"
CustomInfo: ConfigParam "Name=LCDPowerOutput" "Parent=LCD_1" "Priority=Expert" "Type=string" "Desc=Power output that controls this LCD's power." "Value=HMI_Power" "Display=Visible:LCDAutoConnect=true&&Choices:;;Main_Laser_Power;;HMI_Power;;WheelLight_Power;;Sonar_1_Power;;Sonar_2_Power;;USB_1_and_2_Power;;USB_3_Power;;Vertical_Laser_Power;;Foot_Laser_Power;;Battery_Out_1;;Battery_Out_2;;Battery_Out_3_and_4;;Aux_5V;;Aux_12V;;Aux_20V;;Audio_Power"
CustomInfo: ConfigParam "Name=LCDBaud" "Parent=LCD_1" "Priority=Expert" "Type=int" "Desc=Baud rate for the LCD communication (9600, 19200, 38400, etc.)." "Value=115200" "Display=Visible:LCDAutoConnect=true"
CustomInfo: ConfigSection "Name=Light Analysis"
CustomInfo: ConfigParam "Name=MappingSnapshotSaving" "Parent=Light Analysis" "Priority=Expert" "Type=bool" "Desc=Enable the saving of snapshot image files during the scanning process. These files can be used during light analysis instead of the saved summary information. (See AnalyzeDebugSnapshots.)" "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=" "Parent=Light Analysis" "Priority=Expert" "Type=unknown" "Desc="
CustomInfo: ConfigSection "Name=Local EtherNet/IP Device Setup"
CustomInfo: ConfigParam "Name=EIPIODevice_1" "Parent=Local EtherNet/IP Device Setup" "Priority=Normal" "Type=unknown" "Desc=An EtherNet/IP IO Device."
CustomInfo: ConfigParam "Name=EIPIODevice_2" "Parent=Local EtherNet/IP Device Setup" "Priority=Normal" "Type=unknown" "Desc=An EtherNet/IP IO Device."
CustomInfo: ConfigParam "Name=EIPIODevice_3" "Parent=Local EtherNet/IP Device Setup" "Priority=Normal" "Type=unknown" "Desc=An EtherNet/IP IO Device."
CustomInfo: ConfigParam "Name=EIPIODevice_4" "Parent=Local EtherNet/IP Device Setup" "Priority=Normal" "Type=unknown" "Desc=An EtherNet/IP IO Device."
CustomInfo: ConfigParam "Name=EIPIODevice_5" "Parent=Local EtherNet/IP Device Setup" "Priority=Normal" "Type=unknown" "Desc=An EtherNet/IP IO Device."
CustomInfo: ConfigParam "Name=EIPIODevice_6" "Parent=Local EtherNet/IP Device Setup" "Priority=Normal" "Type=unknown" "Desc=An EtherNet/IP IO Device."
CustomInfo: ConfigParam "Name=EIPIODevice_7" "Parent=Local EtherNet/IP Device Setup" "Priority=Normal" "Type=unknown" "Desc=An EtherNet/IP IO Device."
CustomInfo: ConfigParam "Name=EIPIODevice_8" "Parent=Local EtherNet/IP Device Setup" "Priority=Normal" "Type=unknown" "Desc=An EtherNet/IP IO Device."
CustomInfo: ConfigParam "Name=EIPIODevice_9" "Parent=Local EtherNet/IP Device Setup" "Priority=Normal" "Type=unknown" "Desc=An EtherNet/IP IO Device."
CustomInfo: ConfigParam "Name=EIPIODevice_10" "Parent=Local EtherNet/IP Device Setup" "Priority=Normal" "Type=unknown" "Desc=An EtherNet/IP IO Device."
CustomInfo: ConfigSection "Name=Localization Modules"
CustomInfo: ConfigParam "Name=DisableLaserLocalization" "Parent=Localization Modules" "Priority=Factory" "Type=bool" "Desc=Disable laser localization. (Use with caution. The robot will not be able to track its location.)" "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=LightLocalization" "Parent=Localization Modules" "Priority=Normal" "Type=bool" "Desc=Enable light localization." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=" "Parent=Localization Modules" "Priority=Expert" "Type=unknown" "Desc="
CustomInfo: ConfigSection "Name=Localization settings"
CustomInfo: ConfigParam "Name=LocalizationAlwaysIgnorePoseLegality" "Parent=Localization settings" "Priority=Expert" "Type=bool" "Desc=Ignore the legal status of poses, and thereby prevent the robot from determining that it is in a wall (for example). This is primarily intended for highly dynamic environments that have a poor map. (Use with caution.)" "Value=false" "Display=Checkbox&&Visible:disableLaserLocalization=false"
CustomInfo: ConfigParam "Name=" "Parent=Localization settings" "Priority=Expert" "Type=unknown" "Desc="
CustomInfo: ConfigParam "Name=NumSamples" "Parent=Localization settings" "Priority=Expert" "Type=int" "Desc=Number of pose samples to use for localization. Increasing this number results in increased computation. If the number is set too low, then the robot will fail to localize. If AdjustNumSamplesFlag is enabled, then this specifies the maximum number of samples that will be used for localization." "Value=2000" "Min=1"
CustomInfo: ConfigParam "Name=NumSamplesAtInit" "Parent=Localization settings" "Priority=Expert" "Type=int" "Desc=Number of pose samples to use when initializing the robot in the map. Since this is presumably done when the robot is at rest, it can be larger than NumSamples and use more computation for greater accuracy. A value of 0 will make it equal to NumSamples." "Value=2000" "Min=0"
CustomInfo: ConfigParam "Name=GridRes" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Resolution (in mm) of the occupancy grid representing the map. Decreasing the resolution results in greater accuracy but also increases computation." "Value=100" "Min=10"
CustomInfo: ConfigParam "Name=PassThreshold" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Minimum score, out of 1.0, for the sample with the maximum probability to be considered localized after sensor correction, based on the match between sensor and map points. This is not the only measure of the robot being lost: Once the score drops below PassThreshold, the robot has to move a significant distance to raise its uncertainty above the parameter LostThresholdDistance to be considered lost." "Value=0.2"
CustomInfo: ConfigParam "Name=PassThreshold" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Minimum score, out of 1.0, for the sample with the maximum probability to be considered localized after sensor correction, based on the match between sensor and map points. This is not the only measure of the robot being lost: Once the score drops below PassThreshold, the robot has to move a significant distance to raise its uncertainty above the parameter LostThresholdDistance to be considered lost." "Value=0.2"
CustomInfo: ConfigParam "Name=PassThreshold" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Minimum score, out of 1.0, for the sample with the maximum probability to be considered localized after sensor correction, based on the match between sensor and map points. This is not the only measure of the robot being lost: Once the score drops below PassThreshold, the robot has to move a significant distance to raise its uncertainty above the parameter LostThresholdDistance to be considered lost." "Value=0.2" "Max=1"
CustomInfo: ConfigParam "Name=LostThresholdDistance" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Maximum position uncertainty (in mm) of the robot pose before the robot will be considered lost. This threshold will only come into play if none of the samples during sensor correction score higher than PassThreshold. As soon as this happens, the position uncertainty distance will grow based on the movement from the last localized pose." "Value=100" "Min=0"
CustomInfo: ConfigParam "Name=KMmPerMm" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Expected linear error (in mm) when the robot moves linearly. This is mm of linear error per linear mm moved." "Value=0.05" "Min=0"
CustomInfo: ConfigParam "Name=KDegPerDeg" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Expected error (in deg) in angle when the robot rotates. This is degrees of error per degrees rotated." "Value=0.05" "Min=0"
CustomInfo: ConfigParam "Name=KDegPerMm" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Expected error (in deg) in angle when the robot moves linearly. This is degrees of error per linear mm moved." "Value=0.0025" "Min=0"
CustomInfo: ConfigParam "Name=TriggerDistance" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Distance (in mm)  to trigger localization. Because localization is computationally expensive, it is triggered only when the robot has moved the TriggerDistance." "Value=200" "Min=0"
CustomInfo: ConfigParam "Name=TriggerAngle" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Angle (in deg) to trigger localization. Because localization is computationally expensive, it is triggered only when the robot has rotated by the TriggerAngle." "Value=5" "Min=0"
CustomInfo: ConfigParam "Name=TriggerTimeEnabled" "Parent=Localization settings" "Priority=Expert" "Type=bool" "Desc=Force localization every TriggerTime interval. When enabled (true), the IdleTimeTrigger* parameters  take effect. This feature allows the position to be refined occasionally, even when the robot has not moved much." "Value=false"
CustomInfo: ConfigParam "Name=TriggerTime" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Minimum time (in ms) the robot must be idle before localization is triggered from the last known pose." "Value=10000" "Min=1500"
CustomInfo: ConfigParam "Name=IdleTimeTriggerX" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Range (in mm) of the samples in X coords when localization is triggered by idle time." "Value=200" "Min=0"
CustomInfo: ConfigParam "Name=IdleTimeTriggerY" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Range (in mm) of the samples in Y coords when localization is triggered by idle time." "Value=200" "Min=0"
CustomInfo: ConfigParam "Name=IdleTimeTriggerTh" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Range (in deg) of the samples in Theta coords when localization is triggered by idle time." "Value=15" "Min=0"
CustomInfo: ConfigParam "Name=RecoverOnFail" "Parent=Localization settings" "Priority=Expert" "Type=bool" "Desc=Force a static localization attempt based on the last known robot pose if localization fails. When enabled (true), this reinitialization can cause the robot to become hopelessly lost if the actual robot pose is very different from its last known pose." "Value=false"
CustomInfo: ConfigParam "Name=FailedX" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Range (in mm) of the box in the X axis to distribute samples after localization fails." "Value=300" "Min=0"
CustomInfo: ConfigParam "Name=FailedY" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Range (in mm) of the box in the Y axis to distribute samples after localization fails." "Value=300" "Min=0"
CustomInfo: ConfigParam "Name=FailedTh" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Range (in deg) of the angle to distribute samples after localization fails." "Value=45" "Min=0"
CustomInfo: ConfigParam "Name=PeturbX" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=After sensor correction and resampling the chosen pose is perturbed to generate a new sample. This parameter decides the range to perturb the X axis in mm." "Value=10" "Min=0"
CustomInfo: ConfigParam "Name=PeturbY" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=After sensor correction and resampling the chosen pose is perturbed to generate a new sample. This parameter decides the range to perturb the Y axis in mm." "Value=10" "Min=0"
CustomInfo: ConfigParam "Name=PeturbTh" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=After sensor correction and resampling the chosen pose is perturbed to generate a new sample. This parameter decides the range to perturb the angle in degs." "Value=1" "Min=0"
CustomInfo: ConfigParam "Name=PeakStdX" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Size (in mm) of the ellipse in the X axis beyond which the sample poses will be considered multiple localizations after resampling." "Value=10" "Min=0"
CustomInfo: ConfigParam "Name=PeakStdY" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Size (in mm) of the ellipse in the Y axis beyond which the sample poses will be considered multiple localizations after resampling." "Value=10" "Min=0"
CustomInfo: ConfigParam "Name=PeakStdTh" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Angle (in deg) beyond which the sample poses will be considered multiple localizations after resampling." "Value=1" "Min=0"
CustomInfo: ConfigParam "Name=PeakFactor" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Factor, multiplied by the maximum probability (in the number of samples taken), to determine the threshold below which readings are discarded. Used when a number of readings have non-zero probabilities, such as when there are ambiguities in a corridor." "Value=0" "Max=1"
CustomInfo: ConfigParam "Name=StdX" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Standard deviation (in mm) of the Gaussian ellipse in X axis at start of localization." "Value=400" "Min=0"
CustomInfo: ConfigParam "Name=StdY" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Standard deviation (in mm) of the Gaussian ellipse in Y axis at start of localization." "Value=400" "Min=0"
CustomInfo: ConfigParam "Name=StdTh" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Standard deviation (in deg) of the Gaussian angle at start of localization." "Value=30" "Min=0"
CustomInfo: ConfigParam "Name=SensorBelief" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Probability that a range reading from the laser is valid. This is used in the correction of the probabilities of the samples using the sensor." "Value=0.9" "Max=1"
CustomInfo: ConfigParam "Name=OccThreshold" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Threshold value of the occupancy grid to consider as occupied. 0 is unoccupied, 1 is totally occupied." "Value=0.1" "Max=1"
CustomInfo: ConfigParam "Name=AngleIncrement" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Separation (in deg) required between laser readings to be used for localization. The readings that are too close together are discarded, which reduces the computational load on the CPU." "Value=1" "Max=180"
CustomInfo: ConfigParam "Name=DiscardThreshold" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Threshold of an occupancy grid cell above which a robot sample pose, lying inside the cell, will be discarded. Useful in cases where robot may intersect map points such as during docking." "Value=0.33" "Max=1"
CustomInfo: ConfigParam "Name=TransitionFromIdleNumSamples" "Parent=Localization settings" "Priority=Expert" "Type=int" "Desc=Number of samples laser localization will use when localization is re-enabled after it was idle, to initialize at the new robot pose." "Value=100" "Min=1"
CustomInfo: ConfigParam "Name=TransitionFromIdleXStd" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Spread of the samples in the X coordinates when localization is re-enabled after it was idle, to initialize at the new robot pose." "Value=100" "Min=0"
CustomInfo: ConfigParam "Name=TransitionFromIdleYStd" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Spread of the samples in the Y coordinates when localization is re-enabled after it was idle, to initialize at the new robot pose." "Value=100" "Min=0"
CustomInfo: ConfigParam "Name=TransitionFromIdleTStd" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Spread of the samples in the Theta coordinates when localization is re-enabled after it was idle, to initialize at the new robot pose." "Value=1" "Min=0"
CustomInfo: ConfigParam "Name=LogFlag" "Parent=Localization settings" "Priority=Expert" "Type=bool" "Desc=Write internal debbuging data to the output log." "Value=false"
CustomInfo: ConfigParam "Name=LogLevel" "Parent=Localization settings" "Priority=Expert" "Type=int" "Desc=Amount of logging to include when LogFlag is enabled. 1 is minimal and 3 is maximum." "Value=1" "Min=1"
CustomInfo: ConfigParam "Name=ErrorLogFlag" "Parent=Localization settings" "Priority=Expert" "Type=bool" "Desc=Write the localization error computed for each successful localization to the output log." "Value=false"
CustomInfo: ConfigParam "Name=AdjustNumSamplesFlag" "Parent=Localization settings" "Priority=Expert" "Type=bool" "Desc=Automatically vary the number of samples based on the localization score. When enabled (true), the number of samples is lowered when the robot is in motion and the localization score is high. This reduces computation. As the localization score drops, the number of samples is increased. The default behavior (false) maintains a constant high number of samples to keep the robot from losing localization even after initialization." "Value=false"
CustomInfo: ConfigParam "Name=MinNumSamples" "Parent=Localization settings" "Priority=Expert" "Type=int" "Desc=Minimum number of samples taken, used when the AdjustNumSamplesFlag is enabled." "Value=200" "Min=0"
CustomInfo: ConfigParam "Name=NumSamplesAngleFactor" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Factor, based on the robot's rotation, used when the AdjustNumSamplesFlag is enabled. When the robot has rotated significantly, it needs more samples than if it had only moved in translation. A large factor will cause the number of samples to drop more slowly when the localization is triggered by rotation." "Value=1" "Min=0"
CustomInfo: ConfigParam "Name=SlowDownEnableFlag" "Parent=Localization settings" "Priority=Expert" "Type=bool" "Desc=Enable the slow-down action. When disabled (false), it is not necessary to turn it off with the other parameters." "Value=false"
CustomInfo: ConfigParam "Name=SlowDownEnableFlag" "Parent=Localization settings" "Priority=Expert" "Type=bool" "Desc=Enable the slow-down action. When disabled (false), it is not necessary to turn it off with the other parameters." "Value=false"
CustomInfo: ConfigParam "Name=SlowDownTransVelMin" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Minimum translation velocity when the localization score drops to zero. Values less than 100 are treated as 100. If you want to actually stop the robot, change the LostTresholdDist and PassThreshold so it gets lost." "Value=250" "Min=0"
CustomInfo: ConfigParam "Name=SlowDownTransVelMin" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Minimum translation velocity when the localization score drops to zero. Values less than 100 are treated as 100. If you want to actually stop the robot, change the LostTresholdDist and PassThreshold so it gets lost." "Value=250" "Min=0"
CustomInfo: ConfigParam "Name=SlowDownRotVelMin" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Minimum rotational velocity when the localization score drops to zero. Values less than 10 are treated as 10. If you want to actually stop the robot, change the LostTresholdDist and PassThreshold so it gets lost." "Value=25" "Min=0"
CustomInfo: ConfigParam "Name=SlowDownRotVelMin" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Minimum rotational velocity when the localization score drops to zero. Values less than 10 are treated as 10. If you want to actually stop the robot, change the LostTresholdDist and PassThreshold so it gets lost." "Value=25" "Min=0"
CustomInfo: ConfigParam "Name=SlowDownMaxThreshold" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Maximum localization score above which the robot is not slowed down. TransVelMax will be used in this case. (The complementary minimum threshold is the PassThreshold for localization.)" "Value=0.9" "Max=1"
CustomInfo: ConfigParam "Name=SlowDownMaxThreshold" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Maximum localization score above which the robot is not slowed down. TransVelMax will be used in this case. (The complementary minimum threshold is the PassThreshold for localization.)" "Value=0.9" "Max=1"
CustomInfo: ConfigParam "Name=SlowDownPower" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Degree to which the localization score is raised to compute the slow-down speed when the localization score is between the min and max thresholds." "Value=1" "Min=1"
CustomInfo: ConfigParam "Name=SlowDownPower" "Parent=Localization settings" "Priority=Expert" "Type=double" "Desc=Degree to which the localization score is raised to compute the slow-down speed when the localization score is between the min and max thresholds." "Value=1" "Min=1"
CustomInfo: ConfigSection "Name=Log Config"
CustomInfo: ConfigParam "Name=MaxSingleFileSizeMegs" "Parent=Log Config" "Priority=Expert" "Type=double" "Desc=Maximum file size (in MB) for an individual log file." "Value=50" "Min=1"
CustomInfo: ConfigParam "Name=LogTotalMaxMegs" "Parent=Log Config" "Priority=Expert" "Type=double" "Desc=Maximum total size (in MB) of all log files." "Value=300" "Min=0"
CustomInfo: ConfigParam "Name=LogTotalNumFiles" "Parent=Log Config" "Priority=Expert" "Type=int" "Desc=Maximum number of log files to keep.  0 means no limit." "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=Level" "Parent=Log Config" "Priority=Expert" "Type=string" "Desc=Level of detail to include in the ARAM output log." "Value=Normal" "Display=Choices:Terse;;Normal;;Verbose"
CustomInfo: ConfigSection "Name=Map Features"
CustomInfo: ConfigParam "Name=PreferredLine" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable lines that the path planning will prefer to use (by a parameterized amount)." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=PreferredDirectionRight" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable sectors that cause the robot to prefer driving on the right, in both directions." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=PreferredDirectionLeft" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable sectors that cause the robot to prefer driving on the left, in both directions." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=PreferredDirectionRightSingle" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable sectors that cause the robot to prefer driving on the right, in only one direction. Generally, the bi-directional PreferredDirectionRight should be used instead. If two single direction sectors are placed next to each other, they must be aligned extremely well." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=PreferredDirectionLeftSingle" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable sectors that cause the robot to prefer driving on the left, in only one direction. Generally, the bi-directional PreferredDirectionLeft should be used instead. If two single direction sectors are placed next to each other, they must be aligned extremely well." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=IgnoreSonar" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable sectors that cause the robot to ignore sonar readings. Any sonar reading that is detected within the bounds of these sectors will be ignored." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=IgnoreDynamicObstacle" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enables a sector that will ignore any tracked dynamic obstacle that fall into its region." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=IgnoreLowLaser" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable a sector  that causes the robot to ignore readings from its low lasers.  This should only be needed when driving up and down ramps." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=IgnoreTiltedLaser" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable a sector that causes the robot to ignore readings from its tilted laser (as long as the robot isn't lost or being driven by joystick.)  Note that the negative obstacle portion won't be ignored if it's enabled." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=IgnoreInternalReadings" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enables a sector that will allow the robot to ignore readings (laser & sonar) internal to the robot's footprint and continue driving.  This overrides the normal safety behavior of stopping whenever a reading is detected inside the robot's footprint." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=DisableClearanceSector" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enables a sector that will allow the robot to override the clearance values on a task and not stop for obstacles." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=Standby" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable Standby goals and ManagedDestination sectors. Standby goals are used for buffering when a robot's destination is already occupied. They are also used for parking when an Fleet Queuing job is complete, if Queuing Manager, EnableParking is also on. ManagedDestination sectors allow multiple goals to be treated as a single destination for the purpose of the occupied determination. Requires a Fleet Manager." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=DisableStandbyDeferSaving" "Parent=Map Features" "Priority=Expert" "Type=bool" "Desc=When enabled (true), the Standby behavior reverts to the old version (prior to ARAM 4.5b.41).   In early versions, the robot was declared 'arrived' at a standby goal as soon as the robot reached the goal location.  The new correct behavior waits until the robot has also executed all of the 'after' tasks associated with the standby goal.  This flag exists solely for backwards compatibility in older applications." "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=ManagedMotion" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable ManagedMotion and ManagedMotionOverride sectors. ManagedMotion sectors are used to limit the number of robots that may drive in an area at any given time. ManagedMotionOverride sectors make the contained robot appear to be driving for the purpose of ManagedMotion. The override sectors are primarily used in constricted areas. Standby goals are also automatically enabled. Requires a Fleet Manager." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=DistanceUncrossableLine" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable DistanceUncrossable lines. If the straight-line path between the robot and its proposed destination intersects a DistanceUncrossable line, then the robot will not drive to the destination. These lines can be used to guide a robot to the appropriate dock or standby goal." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=ResistedSectorAndLine" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable sectors and lines that path planning will resist using, but will use if necessary." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=RestrictiveBoundaryAndSector" "Parent=Map Features" "Priority=Expert" "Type=bool" "Desc=Enable boundaries and sectors that the robot will avoid if possible. (Deprecated. ResistedSectorAndLine is preferred since it is individually adjustable)." "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=MovementParametersSector" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable sectors for changing movement parameters." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=PathPlanningSettingsSector" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable sectors for changing path-planning settings." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=NeedToEnterSector" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable sectors that a robot will enter only when its goal is within the sector. If the robot is already in the sector, then it is allowed to move. If any part of the robot will be inside the sector when at the final Goal, the Robot will get permission to enter the sector, and will drive there using the shortest available path." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=SingleRobotSector" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable sectors in which a maximum of one robot can drive at any given time." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=VolumeAdjustmentSector" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable the VolumeAdjustment sector for changing the volume of the robot's audio output.  This is independent of the audio controls in MobilePlanner or the touchscreen." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=TaskSector" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable sectors that cause the robot to execute a task list upon entering and exiting." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=OneWay" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable one-way areas. (Deprecated. PreferredDirectionRight or PreferredDirectionLeft sectors are preferred unless the map is old.)" "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=ForceLostLine" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable force lost lines, which make the robot lost if it crosses them." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=NoLostSector" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable sectors in which the robot cannot become lost. This is used for highly dynamic areas. (It sets the pass threshold to 0.0 while the robot is in the sector.)" "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=SpeedSectors" "Parent=Map Features" "Priority=Expert" "Type=bool" "Desc=Enable the speed sectors:  Very Fast, Fast, Slow, and Very Slow." "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=SectorLaserLocalizationIgnore" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable sectors in which the robot will ignore laser localization. (Use with caution. This can potentially be hazardous.)" "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=Doors" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable sectors that allow the robot to operate in environments with doors. (The current implementation only supports virtual doors.)" "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=SwitchableForbiddenAreaAndLine" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable areas and lines that may be switched on to act like forbidden areas and lines. These can be controlled through ARCL, ArInterface, or the tasks switchForbidden*." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=DistanceOneWay" "Parent=Map Features" "Priority=Normal" "Type=bool" "Desc=Enable one-way planning areas. These are similar to OneWay sectors, except that the restriction is placed on goal selection instead of movement planning.  When the robot is in a DistanceOneWay sector, it will not select goals within the same sector that would cause it to move "backward" with respect to the direction of the sector." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=" "Parent=Map Features" "Priority=Expert" "Type=unknown" "Desc="
CustomInfo: ConfigSection "Name=MARC Configuration"
CustomInfo: ConfigParam "Name=MARCCustom" "Parent=MARC Configuration" "Priority=Expert" "Type=bool" "Desc=Internal var to determine if we are displaying MARC config items" "Value=false" "Display=Visible:false"
CustomInfo: ConfigParam "Name=Type" "Parent=MARC Configuration" "Priority=Expert" "Type=string" "Desc=Type of robot, e.g. LD, Lynx" "Value=MTX" "Display=Visible:false"
CustomInfo: ConfigParam "Name=Subtype" "Parent=MARC Configuration" "Priority=Expert" "Type=string" "Desc=Subtype of robot" "Value=MARC_devel" "Display=Visible:false"
CustomInfo: ConfigParam "Name=SerialNum" "Parent=MARC Configuration" "Priority=Expert" "Type=string" "Desc=Serial number of the robot" "Value=1" "Display=Visible:false"
CustomInfo: ConfigParam "Name=Name" "Parent=MARC Configuration" "Priority=Expert" "Type=string" "Desc=Name of the robot" "Value=Omron LD250" "Display=Visible:false"
CustomInfo: ConfigParam "Name=ConfigFlags" "Parent=MARC Configuration" "Priority=Expert" "Type=int" "Desc=Robot firmware configuration flags. 0 - isBootloader, 1 - canDowloadMTX_FW, 2 - canDowloadMTX_BL, 3 - notLegacyGyro" "Value=22" "Display=Visible:false"
CustomInfo: ConfigParam "Name=SipCycleTime" "Parent=MARC Configuration" "Priority=Expert" "Type=int" "Desc=Robot info packet update period (ms)" "Value=100" "Max=1000" "Display=Visible:false"
CustomInfo: ConfigParam "Name=AramTimeout" "Parent=MARC Configuration" "Priority=Expert" "Type=int" "Desc=ARAM connection timeout period (ms)" "Value=2000" "Max=10000" "Display=Visible:false"
CustomInfo: ConfigParam "Name=AramPort" "Parent=MARC Configuration" "Priority=Expert" "Type=int" "Desc=Aram serial port. Port A = 0, B = 1, C = 2" "Value=0" "Max=2" "Display=Visible:false"
CustomInfo: ConfigParam "Name=AramBaud" "Parent=MARC Configuration" "Priority=Expert" "Type=int" "Desc=Aram baud rate. 9600 = 0, 19200 = 1" "Value=3" "Max=4" "Display=Visible:false"
CustomInfo: ConfigParam "Name=CanOpenBitrate" "Parent=MARC Configuration" "Priority=Expert" "Type=int" "Desc=CANOpen bus bitrate in kbps" "Value=500" "Max=1000" "Display=Visible:false"
CustomInfo: ConfigParam "Name=CanOpenNodeID" "Parent=MARC Configuration" "Priority=Expert" "Type=int" "Desc=Core CANOpen Node ID" "Value=1" "Max=127" "Display=Visible:false"
