CustomInfo: ConfigParam "Name=TransAccelTop" "Parent=MARC Configuration" "Priority=Expert" "Type=int" "Desc=maximum translational acceleration (mm/sec/sec)" "Value=2000" "Max=32767" "Display=Visible:false"
CustomInfo: ConfigParam "Name=TransDecelTop" "Parent=MARC Configuration" "Priority=Expert" "Type=int" "Desc=maximum translational deceleration (mm/sec/sec)" "Value=-2000" "Max=32767" "Display=Visible:false"
CustomInfo: ConfigParam "Name=RotVelTop" "Parent=MARC Configuration" "Priority=Expert" "Type=int" "Desc=maximum translational velocity (deg/sec)" "Value=180" "Max=32767" "Display=Visible:false"
CustomInfo: ConfigParam "Name=RotAccelTop" "Parent=MARC Configuration" "Priority=Expert" "Type=int" "Desc=maximum translational acceleration (deg/sec/sec)" "Value=360" "Max=32767" "Display=Visible:false"
CustomInfo: ConfigParam "Name=RotDecelTop" "Parent=MARC Configuration" "Priority=Expert" "Type=int" "Desc=maximum translational deceleration (deg/sec/sec)" "Value=361" "Max=32767" "Display=Visible:false"
CustomInfo: ConfigParam "Name=LatVelTop" "Parent=MARC Configuration" "Priority=Expert" "Type=int" "Desc=maximum lateral velocity (mm/sec)" "Value=2500" "Max=32767" "Display=Visible:false"
CustomInfo: ConfigParam "Name=LatAccelTop" "Parent=MARC Configuration" "Priority=Expert" "Type=int" "Desc=maximum lateral acceleration (mm/sec/sec)" "Value=2000" "Max=32767" "Display=Visible:false"
CustomInfo: ConfigParam "Name=LatDecelTop" "Parent=MARC Configuration" "Priority=Expert" "Type=int" "Desc=maximum lateral deceleration (mm/sec/sec)" "Value=-2000" "Max=32767" "Display=Visible:false"
CustomInfo: ConfigParam "Name=HaveGyro" "Parent=MARC Configuration" "Priority=Expert" "Type=int" "Desc=Whether we have a gyro or not (0 = no, 1 = yes)" "Value=1" "Max=1" "Display=Visible:MARCCustom=true"
CustomInfo: ConfigParam "Name=JoyVelMax" "Parent=MARC Configuration" "Priority=Expert" "Type=int" "Desc=Maximum forwards/backwards for joystick (mm/sec)" "Value=2500" "Max=32767" "Display=Visible:MARCCustom=true"
