CustomInfo: ConfigParam "Name=LinI" "Parent=MARC Configuration" "Priority=Expert" "Type=double" "Desc=linear motion controller I gain" "Value=0.25" "Max=10000" "Display=Visible:MARCCustom=true"
CustomInfo: ConfigParam "Name=LinD" "Parent=MARC Configuration" "Priority=Expert" "Type=double" "Desc=linear motion controller D gain" "Value=0" "Max=10000" "Display=Visible:MARCCustom=true"
