CustomInfo: ConfigParam "Name=GyroStillReadings" "Parent=MARC Configuration" "Priority=Expert" "Type=int" "Desc=Number of model updates below gyro speeds before it stops using the gyro." "Value=5" "Max=32767" "Display=Visible:MARCCustom=true"
