CustomInfo: ConfigParam "Name=MinimumSlowDownSpeed" "Parent=Move: Segment Defaults" "Priority=Normal" "Type=double" "Desc=" "Value=50" "Max=200" "Display=Visible:SlowDownMode=Custom&&Visible:ClearanceMode!=Default"
CustomInfo: ConfigParam "Name=SlowSpeedPaddingWidth" "Parent=Move: Segment Defaults" "Priority=Normal" "Type=double" "Desc=" "Value=150" "Max=2000" "Display=Visible:SlowDownMode=Custom&&Visible:ClearanceMode!=Default"
CustomInfo: ConfigParam "Name=SlowSpeedPaddingSpeedLimit" "Parent=Move: Segment Defaults" "Priority=Normal" "Type=double" "Desc=" "Value=300" "Max=1000" "Display=Visible:SlowDownMode=Custom&&Visible:ClearanceMode!=Default"
CustomInfo: ConfigParam "Name=FastSpeedPaddingWidth" "Parent=Move: Segment Defaults" "Priority=Normal" "Type=double" "Desc=" "Value=700" "Max=3000" "Display=Visible:SlowDownMode=Custom&&Visible:ClearanceMode!=Default"
CustomInfo: ConfigParam "Name=FastSpeedPaddingSpeedLimit" "Parent=Move: Segment Defaults" "Priority=Normal" "Type=double" "Desc=" "Value=1800" "Max=2500" "Display=Visible:SlowDownMode=Custom&&Visible:ClearanceMode!=Default"
CustomInfo: ConfigParam "Name=MinimumRotationalSlowDownSpeed" "Parent=Move: Segment Defaults" "Priority=Normal" "Type=double" "Desc=" "Value=5" "Max=20" "Display=Visible:SlowDownMode=Custom&&Visible:ClearanceMode!=Default&&Visible:false"
CustomInfo: ConfigParam "Name=RotationalPaddingRadius" "Parent=Move: Segment Defaults" "Priority=Normal" "Type=double" "Desc=" "Value=400" "Max=3000" "Display=Visible:SlowDownMode=Custom&&Visible:ClearanceMode!=Default&&Visible:false"
CustomInfo: ConfigParam "Name=RotationalPaddingSpeedLimit" "Parent=Move: Segment Defaults" "Priority=Normal" "Type=double" "Desc=" "Value=60" "Max=180" "Display=Visible:SlowDownMode=Custom&&Visible:ClearanceMode!=Default&&Visible:false"
CustomInfo: ConfigParam "Name=CheckISO3691A1Clearance" "Parent=Move: Segment Defaults" "Priority=Normal" "Type=bool" "Desc=" "Value=true" "Display=Checkbox&&Visible:SlowDownMode=Custom&&Visible:ClearanceMode!=Default&&Visible:false"
CustomInfo: ConfigParam "Name=DriveMode" "Parent=Move: Segment Defaults" "Priority=Normal" "Type=string" "Desc=" "Value=Normal" "Display=Choices:Normal;;Smooth;;Precise;;Fast"
CustomInfo: ConfigParam "Name=TranslationalSpeed" "Parent=Move: Segment Defaults" "Priority=Normal" "Type=double" "Desc=Forward translational speed limit in mm/s" "Value=100" "Max=1800" "Display=Visible:false"
CustomInfo: ConfigParam "Name=ForwardSpeed" "Parent=Move: Segment Defaults" "Priority=Normal" "Type=double" "Desc=Forward translational speed limit in mm/s" "Value=100" "Max=1800" "Display=Visible:DriveMode!=Default&&"
CustomInfo: ConfigParam "Name=ReverseSpeed" "Parent=Move: Segment Defaults" "Priority=Normal" "Type=double" "Desc=Reverse translational speed limit in mm/s" "Value=-100" "Max=-10" "Display=Visible:DriveMode!=Default&&"
CustomInfo: ConfigParam "Name=TransAccel" "Parent=Move: Segment Defaults" "Priority=Normal" "Type=double" "Desc=Translational acceleration limit in mm/s/s." "Value=400" "Max=1000" "Display=Visible:DriveMode!=Default"
CustomInfo: ConfigParam "Name=TransDecel" "Parent=Move: Segment Defaults" "Priority=Normal" "Type=double" "Desc=Translational deceleration limit in mm/s/s." "Value=400" "Max=1000" "Display=Visible:DriveMode!=Default"
CustomInfo: ConfigParam "Name=RotationalSpeed" "Parent=Move: Segment Defaults" "Priority=Normal" "Type=double" "Desc=Rotational speed limit in deg/s" "Value=30" "Max=90" "Display=Visible:DriveMode!=Default"
CustomInfo: ConfigParam "Name=RotAccel" "Parent=Move: Segment Defaults" "Priority=Normal" "Type=double" "Desc=Rotational acceleration limit in degrees/s/s." "Value=150" "Max=300" "Display=Visible:DriveMode!=Default"
CustomInfo: ConfigParam "Name=RotDecel" "Parent=Move: Segment Defaults" "Priority=Normal" "Type=double" "Desc=Rotational deceleration limit in degrees/s/s." "Value=50" "Max=300" "Display=Visible:DriveMode!=Default"
CustomInfo: ConfigParam "Name=CentripetalAccel" "Parent=Move: Segment Defaults" "Priority=Normal" "Type=double" "Desc=Cornering acceleration limit in mm/s/s." "Value=300" "Max=800" "Display=Visible:DriveMode!=Default"
CustomInfo: ConfigSection "Name=Outgoing ARCL commands"
CustomInfo: ConfigParam "Name=" "Parent=Outgoing ARCL commands" "Priority=Expert" "Type=unknown" "Desc="
CustomInfo: ConfigParam "Name=LogOutgoingCommands" "Parent=Outgoing ARCL commands" "Priority=Expert" "Type=bool" "Desc=Log the commands sent on the Outgoing ARCL connection." "Value=true"
CustomInfo: ConfigParam "Name=OutgoingCommands1" "Parent=Outgoing ARCL commands" "Priority=Expert" "Type=string" "Desc=ARCL commands to send on the Outgoing ARCL connection. Multiple commands may be separated by the vertical bar (|) character. Spaces are permitted." "Value="
CustomInfo: ConfigParam "Name=OutgoingCommands1Seconds" "Parent=Outgoing ARCL commands" "Priority=Expert" "Type=double" "Desc=Interval (in sec.) at which to send the OutgoingCommands1. Fractional seconds are allowed. 0 to disable." "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=OutgoingCommands2" "Parent=Outgoing ARCL commands" "Priority=Expert" "Type=string" "Desc=ARCL commands to send on the Outgoing ARCL connection. Multiple commands may be separated by the vertical bar (|) character. Spaces are permitted." "Value="
CustomInfo: ConfigParam "Name=OutgoingCommands2Seconds" "Parent=Outgoing ARCL commands" "Priority=Expert" "Type=double" "Desc=Interval (in sec.) at which to send the OutgoingCommands2. Fractional seconds are allowed. 0 to disable." "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=OutgoingCommands3" "Parent=Outgoing ARCL commands" "Priority=Expert" "Type=string" "Desc=ARCL commands to send on the Outgoing ARCL connection. Multiple commands may be separated by the vertical bar (|) character. Spaces are permitted." "Value="
CustomInfo: ConfigParam "Name=OutgoingCommands3Seconds" "Parent=Outgoing ARCL commands" "Priority=Expert" "Type=double" "Desc=Interval (in sec.) at which to send the OutgoingCommands3. Fractional seconds are allowed. 0 to disable." "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=OutgoingCommands4" "Parent=Outgoing ARCL commands" "Priority=Expert" "Type=string" "Desc=ARCL commands to send on the Outgoing ARCL connection. Multiple commands may be separated by the vertical bar (|) character. Spaces are permitted." "Value="
CustomInfo: ConfigParam "Name=OutgoingCommands4Seconds" "Parent=Outgoing ARCL commands" "Priority=Expert" "Type=double" "Desc=Interval (in sec.) at which to send the OutgoingCommands4. Fractional seconds are allowed. 0 to disable." "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=OutgoingCommands5" "Parent=Outgoing ARCL commands" "Priority=Expert" "Type=string" "Desc=ARCL commands to send on the Outgoing ARCL connection. Multiple commands may be separated by the vertical bar (|) character. Spaces are permitted." "Value="
CustomInfo: ConfigParam "Name=OutgoingCommands5Seconds" "Parent=Outgoing ARCL commands" "Priority=Expert" "Type=double" "Desc=Interval (in sec.) at which to send the OutgoingCommands5. Fractional seconds are allowed. 0 to disable." "Value=0" "Min=0"
CustomInfo: ConfigSection "Name=Outgoing ARCL connection setup"
CustomInfo: ConfigParam "Name=OutgoingHostname" "Parent=Outgoing ARCL connection setup" "Priority=Expert" "Type=string" "Desc=Hostname or IP address for the Outgoing ARCL connection." "Value="
CustomInfo: ConfigParam "Name=OutgoingPort" "Parent=Outgoing ARCL connection setup" "Priority=Expert" "Type=int" "Desc=Port number for the Outgoing ARCL connection. Must be non-zero to establish a connection." "Value=7179" "Max=65536"
CustomInfo: ConfigParam "Name=SendStatusInterval" "Parent=Outgoing ARCL connection setup" "Priority=Expert" "Type=int" "Desc=Frequency (in ms) of the oneLineStatus command sent on the Outgoing ARCL connection. The time is approximate and the command will not be sent more often than every 100 ms. 0 to disable." "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=OutgoingSocketTimeoutInMins" "Parent=Outgoing ARCL connection setup" "Priority=Expert" "Type=double" "Desc=Time (in min.) before declaring a timeout on the outgoing socket. If the robot cannot receive data during this interval, then the connection is closed and a new one is established. If enabled, the minimum interval is 5 seconds. A negative value to disable." "Value=0.1" "Min=-1"
CustomInfo: ConfigParam "Name=RequireConnectionToPathPlan" "Parent=Outgoing ARCL connection setup" "Priority=Expert" "Type=bool" "Desc=Require that the configured Outgoing ARCL connection be active for the robot to drive autonomously. If this is enabled (true), then the robot will stop whenever the  Outgoing ARCL connection is lost." "Value=false"
CustomInfo: ConfigSection "Name=Path Planning Settings"
CustomInfo: ConfigParam "Name=DisableGlobalReplanning" "Parent=Path Planning Settings" "Priority=Expert" "Type=bool" "Desc=Disable global replanning of paths." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=" "Parent=Path Planning Settings" "Priority=Expert" "Type=unknown" "Desc="
CustomInfo: ConfigParam "Name=MaxSpeed" "Parent=Path Planning Settings" "Priority=Normal" "Type=double" "Desc=Maximum speed (in mm/sec) during path following." "Value=300"
CustomInfo: ConfigParam "Name=MaxSpeed" "Parent=Path Planning Settings" "Priority=Normal" "Type=double" "Desc=Maximum speed (in mm/sec) during path following." "Value=300"
CustomInfo: ConfigParam "Name=MaxSpeed" "Parent=Path Planning Settings" "Priority=Normal" "Type=double" "Desc=Maximum speed (in mm/sec) during path following." "Value=300" "Min=0"
CustomInfo: ConfigParam "Name=MaxRotSpeed" "Parent=Path Planning Settings" "Priority=Normal" "Type=double" "Desc=Maximum rotational speed (in deg/sec) during path following." "Value=60"
CustomInfo: ConfigParam "Name=MaxRotSpeed" "Parent=Path Planning Settings" "Priority=Normal" "Type=double" "Desc=Maximum rotational speed (in deg/sec) during path following." "Value=60"
CustomInfo: ConfigParam "Name=MaxRotSpeed" "Parent=Path Planning Settings" "Priority=Normal" "Type=double" "Desc=Maximum rotational speed (in deg/sec) during path following." "Value=60" "Min=0"
CustomInfo: ConfigParam "Name=PlanRes" "Parent=Path Planning Settings" "Priority=Normal" "Type=double" "Desc=The resolution of the grid used for path planning in mm. It is best to use an integral fraction of the robot half width to allow for more free space in tight spaces. Smaller resolutions may let you plan through tight spaces, but will increase the computation load. Halving the resolution will raise the computation by a factor of 4." "Value=70" "Min=1"
CustomInfo: ConfigParam "Name=UseRadiusForPlan" "Parent=Path Planning Settings" "Priority=Normal" "Type=bool" "Desc=The path planner assumes that the shape of the robot is approximately a circle with a radius equal to half the robot width. Typical robots are oblong rather than circular in shape. Using the half width allows the planner to find paths through tight spots in the map like doors and narrow passages. This may cause such robots to get stuck when it tries to avoid unmapped obstacles in such tight spaces. To avoid such cases, it might be useful to make the path planner use the robot radius for path planning. This may prevent the robot from driving into tight spaces, but it also ensures that it will be able to drive in and out of any point in the path it plans." "Value=false"
CustomInfo: ConfigParam "Name=UseRearFraction" "Parent=Path Planning Settings" "Priority=Normal" "Type=double" "Desc=How far to extend the side clearances from the center of rotation to the rear of the robot. This is a multiple of the robot rear length. If the robot has rounded corners, then this value should typically be less than one. (For the LD and Lynx, the default is 0.5.) This reduces the likelihood that the robot will get stuck during path following when, otherwise, the rear corners would appear to clip obstacles during turns. This value should to be set to values larger than 1.0 on robots with rear safety zones." "Value=1" "Max=2"
CustomInfo: ConfigParam "Name=PlanFreeSpace" "Parent=Path Planning Settings" "Priority=Normal" "Type=double" "Desc=Preferred minimum distance (in mm) to maintain between the side of the robot and obstacles when planning. Larger values generally result in larger excursions around obstacles. The robot will drive closer to walls or other obstacles if necessary or cost effective." "Value=500" "Min=0"
CustomInfo: ConfigParam "Name=CollisionRange" "Parent=Path Planning Settings" "Priority=Normal" "Type=double" "Desc=Distance (in mm) from the robot within which obstacles seen by the sensors and those on the map are used to compute the local path. This value should exceed (maxVel * maxVel) / (2 x goalDecel) to allow for smoother motion when the robot encounters unmapped obstacles." "Value=3000" "Min=0"
CustomInfo: ConfigParam "Name=UseCollisionRangeForPlanning" "Parent=Path Planning Settings" "Priority=Expert" "Type=bool" "Desc=Force the robot to look CollisionRange ahead during local planning. The robot normally plans ahead locally for a distance based on its speed, which may not be sufficient in some cases. When enabled (true), this flag forces the robot to look further ahead." "Value=true"
CustomInfo: ConfigParam "Name=ClearOnFail" "Parent=Path Planning Settings" "Priority=Expert" "Type=bool" "Desc=Clear the cumulative range buffers when any failure is detected in the local path planning. When enabled, this allows the robot to immediately replan the global path after local path planning fails. Otherwise, there may be a delay of several seconds while the data in the cumulative buffers decays." "Value=true"
CustomInfo: ConfigParam "Name=NumTimesToReplan" "Parent=Path Planning Settings" "Priority=Normal" "Type=int" "Desc=Maximum number of times to replan if the path to a goal is blocked. 0 to disable. The SecsToFail parameter specifies the duration of each failed replan attempt." "Value=10" "Min=0"
CustomInfo: ConfigParam "Name=FrontClearance" "Parent=Path Planning Settings" "Priority=Normal" "Type=double" "Desc=Front clearance (in mm) of the robot while avoiding obstacles. If an obstacle is detected in this area, the robot may engage its emergency deceleration (either EmergencyMaxTransDecel or an E-Stop)." "Value=100" "Min=0"
CustomInfo: ConfigParam "Name=SlowSpeed" "Parent=Path Planning Settings" "Priority=Normal" "Type=double" "Desc=Speed (in mm/sec) which is considered slow. Anything slower is also considered slow." "Value=300" "Min=0"
CustomInfo: ConfigParam "Name=SideClearanceAtSlowSpeed" "Parent=Path Planning Settings" "Priority=Normal" "Type=double" "Desc=Side clearance (in mm) of the robot while avoiding obstacles when moving at a SlowSpeed. If an obstacle is detected in this area, the robot may engage its emergency deceleration (either EmergencyMaxTransDecel or an E-Stop)." "Value=100" "Min=0"
CustomInfo: ConfigParam "Name=FrontPaddingAtSlowSpeed" "Parent=Path Planning Settings" "Priority=Normal" "Type=double" "Desc=Padding distance (in mm) when the robot is moving at a SlowSpeed. This distance extends beyond the front clearance and defines the area in which the robot may decelerate at SuperMaxTransDecel to avoid an obstacle." "Value=150" "Min=0"
CustomInfo: ConfigParam "Name=FastSpeed" "Parent=Path Planning Settings" "Priority=Normal" "Type=double" "Desc=Speed (in mm/sec) which is considered fast. Anything faster is also considered fast." "Value=1125" "Min=0"
CustomInfo: ConfigParam "Name=SideClearanceAtFastSpeed" "Parent=Path Planning Settings" "Priority=Normal" "Type=double" "Desc=Side clearance (in mm) of the robot while avoiding obstacles when moving at a FastSpeed. If an obstacle is detected in this area, the robot may engage its emergency deceleration (either EmergencyMaxTransDecel or an E-Stop)." "Value=200" "Min=0"
CustomInfo: ConfigParam "Name=FrontPaddingAtFastSpeed" "Parent=Path Planning Settings" "Priority=Normal" "Type=double" "Desc=Padding distance (in mm) when the robot is moving at a FastSpeed. This distance extends beyond the front clearance and defines the area in which the robot may decelerate at SuperMaxTransDecel to avoid an obstacle." "Value=975" "Min=0"
CustomInfo: ConfigParam "Name=UseRotVelForClearance" "Parent=Path Planning Settings" "Priority=Expert" "Type=bool" "Desc=This parameter enables the variable clearance calculations to consider radial and linear velocity. Setting this parameter to true will improve collision avoidance between multiple AMRs operating in low clearance areas. Setting this parameter to false will calculate variable clearances based on linear velocity only." "Value=true"
CustomInfo: ConfigParam "Name=ChamferFrontClearance" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=This parameter allows the user to model the front of the robot as a 45 degree chamfer. The value of this parameter is a fraction. For example, setting it to 0.1 will cause the left and right front corners to be cut at 10% of the clearance width. Setting this parameter to a non zero value may help robots like the LD-60, LD-CT and LD-250 avoid getting stuck in tight spaces." "Value=0.3" "Max=0.49"
CustomInfo: ConfigParam "Name=RoundFrontClearance" "Parent=Path Planning Settings" "Priority=Expert" "Type=bool" "Desc=If this flag is set to true, the robot's front clearance will be modeled as a circle instead of a rectangle. Setting it to true may help prevent the robot from getting stuck in tight spaces. Note that this flag is used only if CheckInsideBounds flag is also set to true." "Value=true"
CustomInfo: ConfigParam "Name=RoundFrontLimitFactor" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=This parameter limits the influence of the RoundFrontClearance to within a limited range from the robot center. This avoids slowdown due to obstacles on the side of the robot when driving straight ahead when RoundFrontClearance is set to true. The distance from the robot center to the front boundary is multiplied by RoundFrontLimitFactor to check for obstacles." "Value=1.1" "Min=1.1"
CustomInfo: ConfigParam "Name=SuperMaxTransDecel" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Maximum translational deceleration (in mm/sec/sec) that the robot should use when avoiding obstacles detected in the *Padding areas. Generally, this should be less than the EmergencyMaxTransDecel to help limit the wear and tear caused by emergency decelerations." "Value=1300" "Min=0"
CustomInfo: ConfigParam "Name=EmergencyMaxTransDecel" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Maximum emergency translational deceleration (in mm/sec/sec) allowed for avoiding obstacles. This is used in conjunction with the clearance parameters to limit the maximum deceleration allowed even if there is a chance for collision. If set to 0, then SuperMaxTransDecel is used as the maximum deceleration." "Value=0" "Min=0" "Display=Status:Deprecated"
CustomInfo: ConfigParam "Name=UseEStop" "Parent=Path Planning Settings" "Priority=Expert" "Type=bool" "Desc=Trigger an E-Stop if an obstacle in the path cannot be avoided by the regular deceleration of the robot. This will result in an almost instantaneous stop which may not be suitable for all platforms. (The stability of the platform during E-Stop should be considered.)" "Value=true" "Display=Status:Deprecated"
CustomInfo: ConfigParam "Name=SecsToFail" "Parent=Path Planning Settings" "Priority=Normal" "Type=int" "Desc=Maximum amount of time (in sec) that local search should retry planning after it has failed to find a safe local path. The timer starts when the robot cannot move, and is reset when the robot drives or turns. If a safe local path is not found before the timer expires, then the robot will either attempt a global replan or report a failure. See NumTimesToReplan." "Value=8" "Min=0"
CustomInfo: ConfigParam "Name=EndMoveSecsToFail" "Parent=Path Planning Settings" "Priority=Expert" "Type=int" "Desc=Maximum amount of time (in sec) permitted for the end move to goal. If the goal is not reached within this time, then the goal is cancelled. This is a final check to ensure that the robot does not keep trying to reach a goal forever. A negative value disables the timeout, and allows the robot to try forever." "Value=60"
CustomInfo: ConfigParam "Name=LocalPathFailDistance" "Parent=Path Planning Settings" "Priority=Normal" "Type=double" "Desc=Distance (in mm) the robot is allowed to approach a sensed block. This is meant to help in cases where the robot senses false obstacles from afar and stops too soon, such as on ramps. The distance at which the robot actually stops will depend on the velocity of the robot." "Value=1000" "Min=0"
CustomInfo: ConfigParam "Name=MarkOldPathFactor" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Factor (between 0.1 and 1) used to reduce the cost of the cells in an old path in situations where the robot encounters a number of unmapped obstacles. Without this, the local path it plans may flip from one side of the obstacle to the other between cycles." "Value=0.5" "Max=1"
CustomInfo: ConfigParam "Name=GoalDistanceTol" "Parent=Path Planning Settings" "Priority=Normal" "Type=double" "Desc=Tolerance (in mm) between the robot position and the goal position for the goal to be considered reached." "Value=50" "Min=10"
CustomInfo: ConfigParam "Name=GoalAngleTol" "Parent=Path Planning Settings" "Priority=Normal" "Type=double" "Desc=Tolerance (in deg) between the robot angle and the goal orientation for the goal orientation to be considered reached." "Value=2" "Min=0.1"
CustomInfo: ConfigParam "Name=GoalOccupiedFailDistance" "Parent=Path Planning Settings" "Priority=Normal" "Type=double" "Desc=Distance (in mm) within which the robot is allowed to approach a goal when the sensors see that the goal is occupied." "Value=1000" "Min=100"
CustomInfo: ConfigParam "Name=GoalSpeed" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Maximum speed (in mm/sec) at which the end move to a goal is executed. This value and the robot's inertia determine the goal positioning accuracy. 0 keeps the normal driving value." "Value=100" "Min=0"
CustomInfo: ConfigParam "Name=GoalRotSpeed" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Maximum rotational velocity (in deg/sec) at which the end move to a goal is executed. This value and the robot's inertia determine the goal positioning accuracy. 0 keeps the normal driving value." "Value=60"
CustomInfo: ConfigParam "Name=GoalRotSpeed" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Maximum rotational velocity (in deg/sec) at which the end move to a goal is executed. This value and the robot's inertia determine the goal positioning accuracy. 0 keeps the normal driving value." "Value=60" "Min=0"
CustomInfo: ConfigParam "Name=GoalTransAccel" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Maximum linear acceleration (in mm/sec/sec) at which the end move to a goal is executed. 0 keeps the normal driving value." "Value=100" "Min=0"
CustomInfo: ConfigParam "Name=GoalTransDecel" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Maximum linear deceleration (in mm/sec/sec) at which the end move to a goal is executed. 0 keeps the normal driving value." "Value=300" "Min=0"
CustomInfo: ConfigParam "Name=GoalRotAccel" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Maximum rotational acceleration (in deg/sec/sec) at which the end move to a goal is executed. 0 keeps the normal driving value." "Value=60"
CustomInfo: ConfigParam "Name=GoalRotAccel" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Maximum rotational acceleration (in deg/sec/sec) at which the end move to a goal is executed. 0 keeps the normal driving value." "Value=60" "Min=0"
CustomInfo: ConfigParam "Name=GoalRotDecel" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Maximum rotational deceleration (in deg/sec/sec) at which the end move to a goal is executed. 0 keeps the normal driving value." "Value=60"
CustomInfo: ConfigParam "Name=GoalRotDecel" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Maximum rotational deceleration (in deg/sec/sec) at which the end move to a goal is executed. 0 keeps the normal driving value." "Value=60" "Min=0"
CustomInfo: ConfigParam "Name=GoalSwitchTime" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Time (in sec) to switch into the end move mode prior to the time allotted for deceleration. This provides a buffer to allow for real-world inaccuracies when dropping the velocity to zero." "Value=0.2" "Min=0"
CustomInfo: ConfigParam "Name=GoalUseEncoder" "Parent=Path Planning Settings" "Priority=Expert" "Type=bool" "Desc=When enabled (true), the robot bases its end move solely on its encoder pose. This allows for fine-positioning at a goal." "Value=true"
CustomInfo: ConfigParam "Name=GoalStopSwing" "Parent=Path Planning Settings" "Priority=Normal" "Type=bool" "Desc=When the robot is near the goal and is in the end move to reach it, it may have to turn around if it goes past the goal for some reason. For large robots with long envelopes this may not be desirable. In such cases, it might be better to stop the robot instead of turning around. This flag if set will stop the swing in such cases." "Value=false"
CustomInfo: ConfigParam "Name=AlignAngle" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Maximum difference (in deg) between the robot's initial heading and the angle of the planned path. The robot rotates in place to achieve this angle before it moves linearly." "Value=10" "Min=0"
CustomInfo: ConfigParam "Name=AlignSpeed" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Maximum velocity (in mm/sec) that the robot should move when aligning its heading to the path before linear motion. This is usually low." "Value=20" "Min=0"
CustomInfo: ConfigParam "Name=HeadingRotSpeed" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Maximum rotational speed (in deg/sec) when the robot is exclusively rotating to reach a specified heading. It may be beneficial to set this lower than the normal rotational speed, especially for heavier robots. 0 keeps the normal driving value. This will not override GoalRotSpeed." "Value=30" "Max=30"
CustomInfo: ConfigParam "Name=HeadingRotAccel" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Maximum rotational acceleration (in deg/sec/sec) when the robot is exclusively rotating to reach a heading. It may be beneficial to set this lower than the normal rotational acceleration, especially for heavier robots. 0 keeps the normal driving value. This will not override GoalRotAccel." "Value=50" "Min=0"
CustomInfo: ConfigParam "Name=HeadingRotDecel" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Maximum rotational deceleration (in deg/sec/sec) when the robot is exclusively rotating to reach a heading. It may be beneficial to set this lower than the normal  rotational deceleration, especially for heavier robots. 0 keeps the normal driving value. This will not override GoalRotDecel." "Value=50" "Min=0"
CustomInfo: ConfigParam "Name=HeadingWt" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Heading weight used in the path-matching function to match the arc made from the velocities with the desired computed path." "Value=0.8" "Max=1" "Display=Status:Deprecated"
CustomInfo: ConfigParam "Name=DistanceWt" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Distance weight. Distance refers to the distance to collision, if any, if the robot continues on the path computed from the velocities." "Value=0.1" "Max=1" "Display=Status:Deprecated"
CustomInfo: ConfigParam "Name=VelocityWt" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Velocity weight. Velocity refers to the linear velocity only." "Value=0.1" "Max=1" "Display=Status:Deprecated"
CustomInfo: ConfigParam "Name=SmoothingWt" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Smoothing flag for the path following. This weight serves as a flag to enable smoothing or disable it during path following. If it is set to 1.0, the path following drive smoother and typically faster.  Set this to a value less than 1.0, to make the robot behave like old when this feature was not available." "Value=1" "Max=1" "Display=Status:Deprecated"
CustomInfo: ConfigParam "Name=NforLinVelIncrements" "Parent=Path Planning Settings" "Priority=Expert" "Type=int" "Desc=Multiplier used to compute the number of linear velocity increments of the search table: 2xN+1." "Value=1" "Min=0"
CustomInfo: ConfigParam "Name=NforRotVelIncrements" "Parent=Path Planning Settings" "Priority=Expert" "Type=int" "Desc=Multiplier used to compute the number of rotational velocity increments of the search table: 2xN+1." "Value=8" "Min=0"
CustomInfo: ConfigParam "Name=SmoothWindow" "Parent=Path Planning Settings" "Priority=Expert" "Type=int" "Desc=Size of smoothing window." "Value=2" "Min=0"
CustomInfo: ConfigParam "Name=ObsThreshold" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Threshold value of the occupancy grid to consider as occupied for path planning." "Value=0.3" "Max=1"
CustomInfo: ConfigParam "Name=MatchLengths" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Multiplier (of the robot length) used to compute path-matching distance. Shorter path lengths may be appropriate for driving through narrow openings such as doors, at low speeds." "Value=2" "Min=0"
CustomInfo: ConfigParam "Name=CheckInsideRadius" "Parent=Path Planning Settings" "Priority=Normal" "Type=bool" "Desc=True forces consideration of objects seen inside the robot's radius. If False, the robot path tracking will ignore any objects it sees inside its radius and keep moving to its local goal point. This may be useful for reproducing such behavior in older versions of software." "Value=false"
CustomInfo: ConfigParam "Name=CheckInsideBounds" "Parent=Path Planning Settings" "Priority=Normal" "Type=bool" "Desc=True prevents the robot from turning in place if any obstacle is sensed inside its bounds. If False, obstacle points inside its bounds will not prevent it from turning at the start and end of a planned path." "Value=true"
CustomInfo: ConfigParam "Name=NumSplinePoints" "Parent=Path Planning Settings" "Priority=Expert" "Type=int" "Desc=Number of points that will be used to subdivide the look-ahead in the local path, which will then serve as the knots for the spline to form over." "Value=7"
CustomInfo: ConfigParam "Name=TractionControlMode" "Parent=Path Planning Settings" "Priority=Expert" "Type=string" "Desc=This parameter reduces drive wheel slip during certain maneuvers and modes of operation. For example, when the robot is driving over floors that have lower coefficient of friction or when driving with a heavy payload. Set this parameter to off, low, medium or high depending on the amount of drive wheel slip that you observe during robot operation. NOTE: Incrementing the TractionControlMode will increase the robot's time-to-goal" "Value=Off (No Slip)" "Display=Choices:Off (No Slip);;Low Slip;;Medium Slip;;High Slip"
CustomInfo: ConfigParam "Name=CenterAwayCost" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Added cost of being away from the central spine of the one way areas. 0 causes it to not consider centering in one-way areas at all." "Value=10"
CustomInfo: ConfigParam "Name=OneWayToOldCostFactor" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Factor by which a cell cost is weighted in one-way sectors, against the old value of the cell computed based on free space from obstacles. A low value will cause the robot to plan paths based more on the free spacing. A high value will cause the robot to plan paths which are closer to the center line in the one way sector." "Value=0.9" "Max=0.99"
CustomInfo: ConfigParam "Name=Resistance" "Parent=Path Planning Settings" "Priority=Expert" "Type=int" "Desc=Resistance for Restrictive sectors and lines. The cost of traversing a cell is multiplied by this resistance value. The normal cost for regular non-restrictive cell is 1, so set this value to 1 to turn off restrictive behavior (on default Resisteds and all Restrictives sectors)." "Value=2" "Max=32767"
CustomInfo: ConfigParam "Name=Preference" "Parent=Path Planning Settings" "Priority=Expert" "Type=int" "Desc=Preference factor for Preferred lines. The cost of traversing a cell is divided by this preference value. The normal cost or regular non-preferred cell is 1, so set this value to 1 to turn off preferred behavior for Preferred Lines." "Value=2" "Max=32767"
CustomInfo: ConfigParam "Name=PreferredLineWidth" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Width (in mm) of preferred lines in the map. 0 means that the robot must occupy the same grid cell as the preferred line." "Value=300" "Min=0"
CustomInfo: ConfigParam "Name=PreferredDirectionSideOffset" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Distance (in mm) the robot should maintain between itself and the appropriate side of the preferred direction sector during path planning. This designates a preferred spine on the sector to be used instead of the center line." "Value=250"
CustomInfo: ConfigParam "Name=PreferredDirectionAwayCost" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Cost of being away from the side offset line in preferred-direction sectors. Change this only if the default value does not seem to do the right thing." "Value=1" "Min=0"
CustomInfo: ConfigParam "Name=PreferredDirectionWrongWayCost" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Cost of going the wrong way in the preferred-direction sectors. Change this only if the default value does not seem to do the right thing." "Value=4" "Min=1"
CustomInfo: ConfigParam "Name=PreferredDirectionToOldCostFactor" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Value for the preferred to old cost factor. The factor by which a cell cost is weighted in two-way preferred direction sectors and single preferred direction sectors, against the old value of the cell computed based on free space from obstacles. A low value will cause the robot to plan paths based more on the free spacing. A high value will cause the robot to plan paths which are closer to the line decided by the side offset in the sector. This is used only for local path planning." "Value=0.25" "Max=0.99"
CustomInfo: ConfigParam "Name=PreferredDirectionToOldCostFactorMain" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Value for the preferred to old cost factor for computing the main path to goal. This factor is the counterpart of the PreferredDirectionToOldCostFactor, which is used only for during the main path plan through preferred direction sectors." "Value=0.9" "Max=0.99"
CustomInfo: ConfigParam "Name=NoLocalPlanLookAhead" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Distance (in mm) the robot will look ahead if there is no local plan in effect. Typically an extremely short lookahead in such cases." "Value=200" "Min=0"
CustomInfo: ConfigParam "Name=LogFlag" "Parent=Path Planning Settings" "Priority=Expert" "Type=bool" "Desc=True writes data into a file." "Value=false"
CustomInfo: ConfigParam "Name=LogLevel" "Parent=Path Planning Settings" "Priority=Expert" "Type=int" "Desc=Level of detail in the log data." "Value=1" "Min=0"
CustomInfo: ConfigParam "Name=StallRecoverEnabled" "Parent=Path Planning Settings" "Priority=Expert" "Type=bool" "Desc=True to recover when the robot stalls." "Value=false"
CustomInfo: ConfigParam "Name=StallRecoverSpeed" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Speed (in mm/sec) at which to back away when stalled." "Value=150" "Min=0"
CustomInfo: ConfigParam "Name=StallRecoverDuration" "Parent=Path Planning Settings" "Priority=Expert" "Type=int" "Desc=Cycles of operation to move when recovering from stall." "Value=50" "Min=0"
CustomInfo: ConfigParam "Name=StallRecoverRotation" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Rotation (in deg) when recovering from a stall." "Value=45" "Min=0"
CustomInfo: ConfigParam "Name=DrivingTransVelMax" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Maximum forward translational velocity (in mm/sec) when path following. This value cannot exceed the default, TransVelMax in Robot config. 0 means use the default." "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=DrivingTransNegVelMax" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Maximum backward translational velocity (in mm/sec) when path following. This value cannot exceed the default, TransNegVelMax in Robot config. 0 means use the default." "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=DrivingTransAccel" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Translational acceleration (in mm/sec/sec) when path following. 0 means use the default, TransAccel in Robot config." "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=DrivingTransDecel" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Translational deceleration (in mm/sec/sec) when path following. 0 means use the default, TransDecel in Robot config." "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=DrivingRotVelMax" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Maximum rotational velocity (in deg/sec) when path following. 0 means use the default, RotVelMax in Robot config." "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=DrivingRotAccel" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Rotational acceleration (in deg/sec/sec) when path following. 0 means use the default, RotAccel in Robot config." "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=DrivingRotDecel" "Parent=Path Planning Settings" "Priority=Expert" "Type=double" "Desc=Rotational deceleration (in deg/sec/sec) when path following. 0 means use the default, RotDecel in Robot config." "Value=0" "Min=0"
CustomInfo: ConfigSection "Name=Patrol"
CustomInfo: ConfigParam "Name=RetryTaskCriteria" "Parent=Patrol" "Priority=Expert" "Type=string" "Desc=Behavior to use when retrying failed tasks: a simple count (Count) or an elapsed time (Duration)." "Value=Count" "Display=Choices:Count;;Duration"
CustomInfo: ConfigParam "Name=MaxRetryTaskCount" "Parent=Patrol" "Priority=Expert" "Type=int" "Desc=Maximum number of times to retry a failed task within a route, before going to next task. Used when RetryTaskCriteria is set to Count. -1 means retry forever." "Value=3" "Min=-1"
CustomInfo: ConfigParam "Name=MaxRetryTaskDuration" "Parent=Patrol" "Priority=Expert" "Type=double" "Desc=Maximum time (in min.) to retry a failed task within a route, before going to next task. Used when RetryTaskCriteria is set to Duration. -1 means retry forever." "Value=5" "Min=-1"
CustomInfo: ConfigParam "Name=MaxRestartRouteCount" "Parent=Patrol" "Priority=Expert" "Type=int" "Desc=Maximum number of times that the entire route should be restarted in the event that all tasks fail. -1 means retry forever. Note that this parameter does not apply to continuous patrols, because they are always restarted." "Value=2" "Min=-1"
CustomInfo: ConfigParam "Name=" "Parent=Patrol" "Priority=Expert" "Type=unknown" "Desc="
CustomInfo: ConfigSection "Name=Payload"
CustomInfo: ConfigParam "Name=NumSlots" "Parent=Payload" "Priority=Factory" "Type=int" "Desc=Number of payload slots on this robot." "Value=0" "Min=0"
CustomInfo: ConfigSection "Name=Payload Present Messages and Behavior"
CustomInfo: ConfigParam "Name=UseDockingWithPayloadFault" "Parent=Payload Present Messages and Behavior" "Priority=Expert" "Type=bool" "Desc=If this box is checked the robot will never dock if it has a payload, instead a driving fault will happen." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=DockingWithPayloadShortDescription" "Parent=Payload Present Messages and Behavior" "Priority=Expert" "Type=string" "Desc=The short description of the fault caused if the robot tries to dock with a payload, this should be as short as makes sense so that it'll fit well on left column of the Touchscreen peripheral." "Value=Robot Docking with Payload" "Display=Visible:UseDockingWithPayloadFault=true"
CustomInfo: ConfigParam "Name=DockingWithPayloadLongDescription" "Parent=Payload Present Messages and Behavior" "Priority=Expert" "Type=string" "Desc=The long description of the fault caused if the robot tries to dock with a payload, this should describe the fault in enough detail for the user to fix the problem." "Value=The robot attempted to dock while it was carrying a payload." "Display=Visible:UseDockingWithPayloadFault=true"
CustomInfo: ConfigParam "Name=" "Parent=Payload Present Messages and Behavior" "Priority=Factory" "Type=unknown" "Desc="
