CustomInfo: ConfigSection "Name=Queuing Manager"
CustomInfo: ConfigParam "Name=QueuingManager" "Parent=Queuing Manager" "Priority=Normal" "Type=bool" "Desc=Enable the Queuing Manager for single robot. This feature is beta." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=PatrolContinuous" "Parent=Queuing Manager" "Priority=Expert" "Type=bool" "Desc=Enable continuous patrol even when using the Queuing Manager. Note that the Queuing Manager will not use a robot that is continuously patrolling a route." "Value=false" "Display=Checkbox&&Visible:QueuingManager=true"
CustomInfo: ConfigParam "Name=QueuingManagerFlush" "Parent=Queuing Manager" "Priority=Expert" "Type=bool" "Desc=When enabled (true), the Queuing Manager flushes the save/restore operations." "Value=false" "Display=Checkbox&&Visible:QueuingManager=true"
CustomInfo: ConfigParam "Name=QueuingManagerPayloadFlush" "Parent=Queuing Manager" "Priority=Expert" "Type=bool" "Desc=When enabled (true), the Queuing Manager flushes the payload save/restore operations." "Value=false" "Display=Checkbox&&Visible:QueuingManager=true"
CustomInfo: ConfigParam "Name=DisableQueuingManagerJobHistory" "Parent=Queuing Manager" "Priority=Expert" "Type=bool" "Desc=Disables the Fleet Queuing recording of job history (and to not perform the job history save/restore operation)" "Value=false" "Display=Checkbox&&Visible:QueuingManager=true"
CustomInfo: ConfigParam "Name=QueuingConsumptionMethod" "Parent=Queuing Manager" "Priority=Expert" "Type=string" "Desc=Consumption method to be used by the Queuing Manager." "Value=Fifo" "Display=Visible:QueuingManager=true&&Choices:Fifo;;NonFifo"
CustomInfo: ConfigParam "Name=" "Parent=Queuing Manager" "Priority=Expert" "Type=unknown" "Desc="
CustomInfo: ConfigParam "Name=TranactionHistoryMaxLineCount" "Parent=Queuing Manager" "Priority=Expert" "Type=int" "Desc=Maximum number of lines in an individual job tranactions file" "Value=30000" "Max=500000"
CustomInfo: ConfigParam "Name=DefaultDropoffPriority" "Parent=Queuing Manager" "Priority=Normal" "Type=int" "Desc=Default priority to use in all DROPOFF requests to the Queuing Manager. Larger numbers have higher priority." "Value=20" "Max=200000"
CustomInfo: ConfigParam "Name=DefaultPickupPriority" "Parent=Queuing Manager" "Priority=Normal" "Type=int" "Desc=Default priority to use in all PICKUP requests to the Queuing Manager. Larger numbers have higher priority." "Value=10" "Max=200000"
CustomInfo: ConfigParam "Name=DeleteCompletedItemsMinutes" "Parent=Queuing Manager" "Priority=Expert" "Type=int" "Desc=Number of minutes to maintain a record of completed Queuing Manager job segments." "Value=60" "Max=500000"
CustomInfo: ConfigParam "Name=MaxNumberOfCompletedItems" "Parent=Queuing Manager" "Priority=Expert" "Type=int" "Desc=Maximum number of completed Queuing Manager job segments to keep." "Value=100" "Max=500000"
CustomInfo: ConfigParam "Name=QueuePickupDropoffOverlapBehavior" "Parent=Queuing Manager" "Priority=Expert" "Type=string" "Desc=Specifies the behavior of pod swapping operations." "Value=NoSpecialBehavior" "Display=Choices:NoSpecialBehavior;;ForceDropoffRobotToPickup"
CustomInfo: ConfigParam "Name=QueueFailedJobsInFront" "Parent=Queuing Manager" "Priority=Expert" "Type=bool" "Desc=When enabled, failed jobs will be queued using time and priority. When disabled (the default), failed jobs will be queued using priority only." "Value=false"
CustomInfo: ConfigParam "Name=DecisionsFactors" "Parent=Queuing Manager" "Priority=Expert" "Type=string" "Desc=Decision factor used by the Queuing Manager to select a robot for a job." "Value=Closest" "Display=Choices:Closest"
CustomInfo: ConfigSection "Name=Robot config"
CustomInfo: ConfigParam "Name=PIDConfig" "Parent=Robot config" "Priority=Expert" "Type=bool" "Desc=Allow PID values to be set by the Robot Configuration. If this is enabled (true), then the TasksForPIDSettings parameter in Task Features should be disabled. Otherwise, an excessive number of packets will be sent to the robot when the configuration is modified." "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=" "Parent=Robot config" "Priority=Expert" "Type=unknown" "Desc="
CustomInfo: ConfigParam "Name=TransVelMax" "Parent=Robot config" "Priority=Normal" "Type=int" "Desc=Maximum translational speed (in mm/sec) of the robot. This value cannot exceed the physical limitations of the platform. The *TransVelMax values in other sections will be quietly capped at this value." "Value=1200" "Max=1200"
CustomInfo: ConfigParam "Name=TransNegVelMax" "Parent=Robot config" "Priority=Normal" "Type=int" "Desc=Maximum negative translational speed (in mm/sec) of the robot. This value cannot exceed the physical limitations of the platform. The *TransNegVelMax values in other sections will be quietly capped at this value." "Value=-200" "Max=-1"
CustomInfo: ConfigParam "Name=TransAccel" "Parent=Robot config" "Priority=Normal" "Type=int" "Desc=Default translational acceleration (in mm/sec/sec) of the robot. The *TransAccel values in other sections can override this value." "Value=300" "Max=600"
CustomInfo: ConfigParam "Name=TransDecel" "Parent=Robot config" "Priority=Normal" "Type=int" "Desc=Default translational deceleration (in mm/sec/sec) of the robot. The *TransDecel values in other sections can override this value." "Value=500" "Max=600"
CustomInfo: ConfigParam "Name=RotVelMax" "Parent=Robot config" "Priority=Normal" "Type=int" "Desc=Maximum rotational speed (in deg/sec) of the robot. The *RotVelMax values in other sections will be quietly capped at this value." "Value=60" "Max=120"
CustomInfo: ConfigParam "Name=RotAccel" "Parent=Robot config" "Priority=Normal" "Type=int" "Desc=Default rotational acceleration (in deg/sec/sec) of the robot. The *RotAccel values in other sections can override this value." "Value=60" "Max=360"
CustomInfo: ConfigParam "Name=RotDecel" "Parent=Robot config" "Priority=Normal" "Type=int" "Desc=Default rotational deceleration (in deg/sec/sec) of the robot. The *RotDecel values in other sections can override this value." "Value=60" "Max=360"
CustomInfo: ConfigParam "Name=UseGyro" "Parent=Robot config" "Priority=Expert" "Type=bool" "Desc=Enable the gyro." "Value=true" "Display=Status:Deprecated"
CustomInfo: ConfigParam "Name=UseGyroInLegacyMode" "Parent=Robot config" "Priority=Expert" "Type=bool" "Desc=Check to use the gyro in it's new improved mode (default) or whether to use it in it's legacy gyro ." "Value=false" "Display=Status:Deprecated&&Checkbox"
CustomInfo: ConfigParam "Name=HighTemperatureWarning" "Parent=Robot config" "Priority=Expert" "Type=double" "Desc=The temperature that servers as the high temperature warning. -128 disables the warning" "Value=45" "Max=127"
CustomInfo: ConfigParam "Name=LowStateOfChargeWarning" "Parent=Robot config" "Priority=Expert" "Type=double" "Desc=State of charge (in %) that triggers a low battery warning. When this occurs, an ARCL message is broadcast and the microcontroller executes its low battery behavior (beeping and/or flashing lights)." "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=CriticalFaultShutdownSeconds" "Parent=Robot config" "Priority=Expert" "Type=int" "Desc=Time (in sec) after the microcontroller flags a critical fault before the robot should shut down. The maximum value is 50 seconds since the fault becomes unrecoverable after this time. Note that the microcontroller shuts down the robot 99 seconds after it flags a critical fault." "Value=40" "Max=50"
CustomInfo: ConfigSection "Name=Robot Fleet Features"
CustomInfo: ConfigParam "Name=DisableEnterpriseQueuing" "Parent=Robot Fleet Features" "Priority=Expert" "Type=bool" "Desc=Do not allow the robot to participate in Fleet Queuing. Applicable only when connected to a Fleet Manager." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=EnterprisePatrolContinuous" "Parent=Robot Fleet Features" "Priority=Expert" "Type=bool" "Desc=Enable continuous patrol even when Fleet Queuing is active." "Value=false" "Display=Checkbox&&Visible:EnterpriseQueuing=true"
CustomInfo: ConfigParam "Name=FilterUnsupportedGoals" "Parent=Robot Fleet Features" "Priority=Expert" "Type=bool" "Desc=Enables the filtering of map goals based on custom tasks. If a robot does not support all of the custom tasks that are associated with the goal, then the goal is not available to the robot. The default value of false ensures backwards compatibility with existing applications that use the goto command to send the robot to a goal even though the robot is not able to execute all of the  associated tasks." "Value=false" "Display=Checkbox&&Checkbox"
CustomInfo: ConfigParam "Name=CallStations" "Parent=Robot Fleet Features" "Priority=Expert" "Type=bool" "Desc=Enables call stations for MobilePlanner Tablet Edition" "Value=false" "Display=Checkbox&&Checkbox"
CustomInfo: ConfigParam "Name=DeleteUnusedMaps" "Parent=Robot Fleet Features" "Priority=Expert" "Type=bool" "Desc=Remove unused maps from the robot. Applicable only when connected to a Fleet Manager." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=EnterpriseManagerGatherScans" "Parent=Robot Fleet Features" "Priority=Expert" "Type=bool" "Desc=Upload scan (.2d) files to the Fleet Manager and then delete them from the robot. Applicable only when connected to a Fleet Manager." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=MultiRobotLocalization" "Parent=Robot Fleet Features" "Priority=Expert" "Type=bool" "Desc=Enable multi-robot localization. Applicable only when connected to a Fleet Manager or when MultiRobotPeer is enabled." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=RobotConfigMaxes" "Parent=Robot Fleet Features" "Priority=Expert" "Type=bool" "Desc=Set the maximum values in the Robot config section. When this is disabled (the default), the maximum values are only set if the robot is not connected to the Fleet Manager. If this is enabled, then 'Robot config' must be added as a SeparateSection  in the Fleet Manager Connection." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=DisableMultiRobot" "Parent=Robot Fleet Features" "Priority=Expert" "Type=bool" "Desc=Disable the Fleet Manager multi-robot behavior. To avoid collisions in an environment with multiple robots, either the Fleet Manager multi-robot behavior or the MultiRobotPeer behavior must be active. (If DisableMultiRobot is true, then MultiRobotPeer must also be true.)" "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=MultiRobotPeer" "Parent=Robot Fleet Features" "Priority=Expert" "Type=bool" "Desc=Enables Multi Robot handling in a peer to peer manner... use the Enterprise Manager method if at all possible (adds a new Multi Robot parameter section, requires a user with the multirobot group access if usernames are being used)" "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=SrsIsStrict" "Parent=Robot Fleet Features" "Priority=Expert" "Type=bool" "Desc=When multiple robots are on the Single Robot Sector boundary, this flag applies first in first out rule to them. More strictly, Single Robot Sector boundary tries to assure that only 1 robot can enter." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=" "Parent=Robot Fleet Features" "Priority=Expert" "Type=unknown" "Desc="
CustomInfo: ConfigParam "Name=EnableParking" "Parent=Robot Fleet Features" "Priority=Normal" "Type=bool" "Desc=When enabled (true), robots are sent to parking goals after they complete their job assignments. Applicable only when Map Features > Standby is enabled." "Value=false"
CustomInfo: ConfigParam "Name=InterruptParkingForNewJobs" "Parent=Robot Fleet Features" "Priority=Expert" "Type=bool" "Desc=When enabled (true), robots that are en route to a parking goal can be interrupted and assigned new jobs. Otherwise, the robots must reach the parking goal before they can be assigned new jobs." "Value=true"
CustomInfo: ConfigParam "Name=InProgressUnAllocWaitTime" "Parent=Robot Fleet Features" "Priority=Expert" "Type=int" "Desc=Seconds to wait for inprogress unallocated items" "Value=60" "Min=0"
CustomInfo: ConfigParam "Name=IdleTimeUntilResume" "Parent=Robot Fleet Features" "Priority=Normal" "Type=double" "Desc=Number of minutes to wait before a robot transitions its status from IdleButNotAvaliable to Available. Robots will not take queued jobs until they are Available. Fractional minutes are allowed." "Value=1" "Min=0.01"
CustomInfo: ConfigParam "Name=ParkLowStateOfCharge" "Parent=Robot Fleet Features" "Priority=Normal" "Type=double" "Desc=State of charge for which to send robots to dock rather than parking. If the robot is below this state of charge when it completes a queue item it will be sent to dock" "Value=40" "Max=100"
CustomInfo: ConfigParam "Name=LowStateOfCharge" "Parent=Robot Fleet Features" "Priority=Normal" "Type=double" "Desc=State of charge below which not to use a robot for queue items. If the robot is below this state of charge when it completes a queue item it will be sent to dock" "Value=30" "Max=100"
CustomInfo: ConfigSection "Name=Robot joystick goal button"
CustomInfo: ConfigParam "Name=RobotJoystickGoalButton" "Parent=Robot joystick goal button" "Priority=Normal" "Type=unknown" "Desc=Digital input triggered by the goal button. Inactive during mapping, so the goal button can perform its primary function."
CustomInfo: ConfigSection "Name=Robot Type"
CustomInfo: ConfigParam "Name=Configured" "Parent=Robot Type" "Priority=Factory" "Type=bool" "Desc=Internal parameter for if this core has been configured (will be invisible later)." "Value=true" "Display=Visible:false"
CustomInfo: ConfigParam "Name=ConfiguredBefore" "Parent=Robot Type" "Priority=Factory" "Type=bool" "Desc=Internal parameter for if this core was already in use before the default config existed (will be invisible later)." "Value=true" "Display=Visible:false"
CustomInfo: ConfigParam "Name=Robot_Type" "Parent=Robot Type" "Priority=Expert" "Type=unknown" "Desc=The settings for what type of robot this is" "Display=Editable:false"
