CustomInfo: ConfigParam "Name=SonarToDisplay" "Parent=Sonar Debugging" "Priority=Expert" "Type=unknown" "Desc=List of the sonar readings to debug."
CustomInfo: ConfigSection "Name=Speech Synthesis"
CustomInfo: ConfigParam "Name=DefaultVoiceParameters" "Parent=Speech Synthesis" "Priority=Expert" "Type=bool" "Desc=If set, default parameter values for the voices will be used. If unset, custom values from this section will be used." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=SynthesisPitch" "Parent=Speech Synthesis" "Priority=Expert" "Type=int" "Desc=This controls the highness of the voice.  A lower value indicates a lower voice; a higher value indicates a higher voice." "Value=100" "Max=200"
CustomInfo: ConfigParam "Name=SynthesisRate" "Parent=Speech Synthesis" "Priority=Expert" "Type=int" "Desc=This controls the speech rate of the synthetic speech. A higher value indicates a high speech rate." "Value=100" "Max=200"
CustomInfo: ConfigParam "Name=SynthesisVolume" "Parent=Speech Synthesis" "Priority=Expert" "Type=int" "Desc=This controls the volume of the synthetic speech." "Value=16000" "Max=65535"
CustomInfo: ConfigParam "Name=SynthesisShapingRange" "Parent=Speech Synthesis" "Priority=Expert" "Type=int" "Desc=This is similar to pitch and used on voices that do not support pitch control. This is a percentage of the normal voice tract length used based on gender and controls the shape of the voice by changing the vocal tract length. This can result in non-human voices." "Value=100" "Max=200"
CustomInfo: ConfigParam "Name=ForceSelectorBreak" "Parent=Speech Synthesis" "Priority=Expert" "Type=bool" "Desc=If the synthesis tool is synthesizing long sentences without punctuation marks, it can lead to pauses before the speech starts. Activating this makes the synthesis faster in those cases." "Value=false"
CustomInfo: ConfigParam "Name=PreSel" "Parent=Speech Synthesis" "Priority=Expert" "Type=int" "Desc=This controls the quality of the speech synthesis. Increasing this parameter increases the quality of the speech but also increases the need for CPU and memory." "Value=100" "Max=200"
CustomInfo: ConfigSection "Name=Standby"
CustomInfo: ConfigParam "Name=BlacklistStandbyDistance" "Parent=Standby" "Priority=Expert" "Type=int" "Desc=If the robot fails going to a standby goal but gets within this distance then the standby will be blacklisted for a period of time.  This needs to be greather than 'Path Planning Settings->GoalOccupiedFailDistance', probably by a factor of two (since this is straight distance from the front of the robot).  0 disables this behavior" "Value=2000" "Min=0"
CustomInfo: ConfigParam "Name=FreeStandbyPaddingDistance" "Parent=Standby" "Priority=Expert" "Type=int" "Desc=If the robot is using a multirobot standby, it will free the standby (for other robots) after the robot is it's length + this padding away from the goal." "Value=200" "Min=0"
CustomInfo: ConfigParam "Name=BlacklistStandbyMinutes" "Parent=Standby" "Priority=Expert" "Type=double" "Desc=The number of minutes 1) to blacklist a standby for all robots if two robots have failed it (also within this many minutes) 2) to blacklist a standby for a robot that fails going to that standby.  0 disables this feature." "Value=5" "Min=0"
CustomInfo: ConfigParam "Name=PreferredParkingMaxDistance" "Parent=Standby" "Priority=Expert" "Type=double" "Desc=The distance (in meters) beyond which a robot will ignore a PreferredParking Standby when searching for a parking spot. This makes sure that robots are not frequently driving across an entire site to Park-At-Pickup." "Value=50" "Min=0"
CustomInfo: ConfigSection "Name=Target Definition"
CustomInfo: ConfigParam "Name=TargetList" "Parent=Target Definition" "Priority=Normal" "Type=unknown" "Desc=2D target list."
CustomInfo: ConfigParam "Name=2D_TargetList" "Parent=Target Definition" "Priority=Normal" "Type=unknown" "Desc=2D target list."
CustomInfo: ConfigSection "Name=Task Features"
CustomInfo: ConfigParam "Name=LegacyPauseWaitTasks" "Parent=Task Features" "Priority=Expert" "Type=bool" "Desc=When enabled, use the legacy wait / pause implementation instead of the updated version. (This is an advanced feature that should be enabled only if problems are encountered with the current implementation. If this is the case, please notify your robot provider.)" "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=PauseCompatibility" "Parent=Task Features" "Priority=Expert" "Type=bool" "Desc=When enabled, provide backwards compatibilty for the legacy pause task. Please note that the pause task has been deprecated. It should be replaced by the new waitIndefinitely task. This compatibiltiy option may be eliminated in a future ARAM version." "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=LegacyWaitBehavior" "Parent=Task Features" "Priority=Expert" "Type=bool" "Desc=When enabled, use the legacy wait behavior. This caused the robots to wait for one more second than the specified wait time, and was the standard behavior in ARAM versions 4.4 and lower." "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=ApplicationFaultTasks" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enable applicationFaultSet/applicationFaultClear and applicationBlockDrivingSet/applicationBlockDrivingClear as tasks." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=DataLogMakeNewFile" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Assuming data logging hasn't been disabled this creates a task that'll make a new data log." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=StayAndGoTasks" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enable 'Stay' and 'Go' as tasks (as available on the Touchscreen and ARCL).  Stay starts a new wait of one minute, or extends an in-progress wait by one additional minute.   Go cancels any in-progress waits and generally causes the robot to resume executing Queuing Manager jobs or a previously "stayed" route. (Application Note: This is currently done by artifically increasing the robot's idle time to two minutes.)" "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=CustomResponses" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enable the Custom Responses, which allows task lists to be defined for various events. When enabled, the Custom Responses are included in the 'Special' tab in MobilePlanner." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=TaskArclSendText" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enable a task that sends user-defined text on the ARCL server. (Use with caution. The text must not conflict with the defined ARCL commands/responses.)" "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=MovementParametersTempTasks" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enable tasks that allows the movement parameters to be changed temporarily. The change persists for the duration of the current goal, route, etc." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=MovementParametersTask" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enable a task that allows the movement parameters to be modified until explicitly changed." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=TriangleDriveToAdvanced" "Parent=Task Features" "Priority=Expert" "Type=bool" "Desc=Enable the triangleDriveToAdvanced task. This is similar to the triangleDriveTo task, but also provides task parameters for all of the configuration options. It is primarily intended to be used within macros." "Value=true" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=TriangleDriveToAdvancedProx" "Parent=Task Features" "Priority=Expert" "Type=bool" "Desc=Enable the triangleDriveToAdvancedProx task. This is similar to the triangleDriveToAdvanced task, but also provides support for proximity sensors. If any proximity sensors are defined, then the robot will move until one is triggered." "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=TriangleDriveTo" "Parent=Task Features" "Priority=Expert" "Type=bool" "Desc=Enable the triangleDriveTo task." "Value=true" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=TriangleDriveTo2" "Parent=Task Features" "Priority=Expert" "Type=bool" "Desc=Enable an extra triangle driving task (triangleDriveTo2). triangleDriveTo2 is fundamentally the same as triangleDriveTo. Its primary purpose is to allow a second set of configuration values." "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=TriangleTargetTask" "Parent=Task Features" "Priority=Expert" "Type=bool" "Desc=Enable generalized TriangleTargetDrive task which finds a triangle in the environment and positions the robot relative to it." "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=MoveProx" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enable the moveProx task. This is similar to move, but also provides support for proximity sensors. If any proximity sensors are defined, then the robot will move until one is triggered." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=DeltaHeadingProx" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enable the deltaHeadingProx task. This is similar to deltaHeading except that the robot stops turning if any of the proximity sensors are triggered. When enabled, the robot's rotational velocity (Robot Config > RotVelMax, etc.) should be set to a low value so that the robot can stop quickly." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=ProxTasks_v2" "Parent=Task Features" "Priority=Expert" "Type=bool" "Desc=Enable the moveProx_v2 and deltaHeadingProx_v2 tasks, which allow a specific proximity sensor to be checked. These will eventually replace the original moveProx and deltaHeadingProx tasks." "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=Engage" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enable the Engage task.  This is used to execute a macro upon arriving at a goal, but not repeat the macro if there are repeated jobs to that goal." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=JobTypeCheck" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enable the JobTypeCheck task, which allows a different macro to be executed depending on whether the goal is currently a pickup, a dropoff, or neither." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=RobotSimTypeCheck" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enables a task RobotSimTypeCheck, which allows you to specify a different macro depending on whether the robot is real or simulated.  This is useful for troubleshooting maps which include tasks which cannot be simulated." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=Move2" "Parent=Task Features" "Priority=Expert" "Type=bool" "Desc=Enable an extra move task (move2). move2 is fundamentally the same as move. Its primary purpose is to allow a second set of configuration values." "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=TasksForBetterCustomIO" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enable improved tasks for handling custom I/O. (TasksForCustomIO is deprecated. Use TasksForBetterCustomIO instead.)" "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=TasksForBetterCustomIOWithFast" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enable third-generation tasks for handling custom I/O, along with corresponding 'fast' versions. (The 'fast' versions are still in development, and generally should not be used.)" "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=TasksForCustomIO" "Parent=Task Features" "Priority=Expert" "Type=bool" "Desc=Enable tasks for handling custom I/O. (Deprecated. Use TasksForBetterCustomIO instead.)" "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=TaskForevers" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enable the 'forever' tasks. These change the mode of the robot and do not return to the calling location. This is an advanced option." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=TaskDockForever" "Parent=Task Features" "Priority=Expert" "Type=bool" "Desc=Enable a task that docks the robot forever. This is the same functionality provided by the 'Dock' button in client applications. (Deprecated. Use TaskForevers instead.)" "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=PathPlanningSettingsTempTasks" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enable tasks that allows the path planning settings to be changed temporarily." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=VolumeAdjustmentTempTasks" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enables the VolumeAdjustment temporary tasks for changing the volume of the robot's audio output (separately from the robot out slider)" "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=TaskArbitraryServerSend" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enable a task that sends text to a specified server. (Use with caution. When enabled, inappropriate use could potentially have adverse effects on a network.)" "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=TaskArbitraryServerSendInstant" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enables a task to send strings instantly to an arbitrary server (think twice before enabling since inapproriate use could wreak havoc on a network)" "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=TaskEnableMotorsInstant" "Parent=Task Features" "Priority=Expert" "Type=bool" "Desc=Enable the enableMotorsInstant task. This may be used to clear an E-Stop, for example. (Use with caution. Injury or damage can result from improper use since the robot may start moving once the motors are enabled. Do not execute the task without explicit user input.)" "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=TaskShutdownRobot" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enable a task that shuts down the robot." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=TaskRestartARAM" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enable a task that restarts ARAM." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=TaskLocalizeAtGoal" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enable the localizeAtGoal task. (Use with caution. If used incorrectly, this task can cause the robot to become lost.)" "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=TaskQueueDropoff" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enables a task queueDropoff which will queue a dropoff for that robot" "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=TaskQueueDropoffRandom" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enable the queueDropoff task, which will queue a dropoff for that robot of a random goal (optionally that matches a certain prefix)." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=TaskSetMovementParametersTemp" "Parent=Task Features" "Priority=Expert" "Type=bool" "Desc=Enable the setMovementParamsTemp task to set the movement parameters temporarily. (Deprecated. MovementParametersTempTasks is preferred. The two are compatible.)" "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=GotoStraight" "Parent=Task Features" "Priority=Expert" "Type=bool" "Desc=Enable the gotoStraight task.  This task doesn't use path planning.  The robot simply points and drives straight to the goal position, stopping as necessary if an obstacle is encountered.  After arriving at the goal position, the robot turns to the goal heading.  This is generally not optimal behavior and it will not be treated like a normal goal by any of the other systems.  (For example, the 'before' and 'after' goal associates will not be executed.)  This task should only be used in limited cases." "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=TaskFaceClosest" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enable a task that rotates the robot to face the closest obstacle within some distance." "Value=false" "Display=Checkbox&&Status:BETA"
CustomInfo: ConfigParam "Name=TasksForPIDSettings" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enable tasks that change the PID settings. If this is enabled (true), then PIDConfig parameter in Robot config should be disabled. Otherwise, an excessive number of packets will be sent to the robot when the configuration is modified." "Value=false" "Display=Checkbox&&Status:BETA"
CustomInfo: ConfigParam "Name=TaskCompareNumLights" "Parent=Task Features" "Priority=Normal" "Type=bool" "Desc=Enable a task that compares the number of lights and modifies its behavior accordingly." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=" "Parent=Task Features" "Priority=Expert" "Type=unknown" "Desc="
CustomInfo: ConfigSection "Name=Teleop Settings"
CustomInfo: ConfigParam "Name=DisableRobotJoystickOverride" "Parent=Teleop Settings" "Priority=Expert" "Type=bool" "Desc=Disable the joystick's ability to override all behavior (including, for example, docking)." "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=RobotJoystickAdjustCenter" "Parent=Teleop Settings" "Priority=Expert" "Type=bool" "Desc=Enable display and adjustment of the center point on the robot joystick." "Value=false" "Display=Checkbox&&Status:Deprecated"
CustomInfo: ConfigParam "Name=RobotTeleopAvoidVirtuals" "Parent=Teleop Settings" "Priority=Expert" "Type=bool" "Desc=Avoid location-dependent obstacles (like forbidden areas) during joystick teleop. When this is enabled, the robot will also stop if it becomes lost during teleop." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=" "Parent=Teleop Settings" "Priority=Expert" "Type=unknown" "Desc="
CustomInfo: ConfigParam "Name=Timeout" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Duration (in sec) that the robot will continue to move when no teleop commands are received. Fractional seconds are allowed. 0 to disable." "Value=2" "Min=0"
CustomInfo: ConfigParam "Name=Timeout" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Duration (in sec) that the robot will continue to move when no teleop commands are received. Fractional seconds are allowed. 0 to disable." "Value=2" "Min=0"
CustomInfo: ConfigParam "Name=FullThrottleForwards" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Maximum forward speed (in mm/sec) during teleop mode. 0 means the robot's TransVelMax value." "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=FullThrottleForwards" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Maximum forward speed (in mm/sec) during teleop mode. 0 means the robot's TransVelMax value." "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=FullThrottleBackwards" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Maximum backwards speed (in mm/sec) during teleop mode. 0 means 1/4 of the robot's TransVelMax value." "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=FullThrottleBackwards" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Maximum backwards speed (in mm/sec) during teleop mode. 0 means 1/4 of the robot's TransVelMax value." "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=RotAtFullForwards" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Maximum rotation speed (in deg/sec) when going FullThrottleForwards. 0 means 1/2 of the robot's RotVelMax value." "Value=25" "Min=0"
CustomInfo: ConfigParam "Name=RotAtFullForwards" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Maximum rotation speed (in deg/sec) when going FullThrottleForwards. 0 means 1/2 of the robot's RotVelMax value." "Value=25" "Min=0"
CustomInfo: ConfigParam "Name=RotAtFullBackwards" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Maximum rotation speed (in deg/sec) when going FullThrottleBackwards. 0 means 1/2 of the robot's RotVelMax value." "Value=25" "Min=0"
CustomInfo: ConfigParam "Name=RotAtFullBackwards" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Maximum rotation speed (in deg/sec) when going FullThrottleBackwards. 0 means 1/2 of the robot's RotVelMax value." "Value=25" "Min=0"
CustomInfo: ConfigParam "Name=RotAtStopped" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Maximum rotation speed (in deg/sec) when stationary. 0 means the robot's RotVelMax value." "Value=50" "Min=0"
CustomInfo: ConfigParam "Name=RotAtStopped" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Maximum rotation speed (in deg/sec) when stationary. 0 means the robot's RotVelMax value." "Value=50" "Min=0"
CustomInfo: ConfigParam "Name=TransDeadZone" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Inner region (as % of total) of the joystick's translation direction that is unresponsive. The robot will not move until the joystick is pushed outside this region." "Value=10" "Min=0"
CustomInfo: ConfigParam "Name=TransDeadZone" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Inner region (as % of total) of the joystick's translation direction that is unresponsive. The robot will not move until the joystick is pushed outside this region." "Value=10" "Min=0"
CustomInfo: ConfigParam "Name=RotDeadZone" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Inner region (as % of total) of the joystick's rotation direction that is unresponsive. The robot will not move until the joystick is pushed outside this region." "Value=5" "Min=0"
CustomInfo: ConfigParam "Name=RotDeadZone" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Inner region (as % of total) of the joystick's rotation direction that is unresponsive. The robot will not move until the joystick is pushed outside this region." "Value=5" "Min=0"
CustomInfo: ConfigParam "Name=ForwardClearance" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Minimum distance (in mm) between the front of the  robot and any other object. If an obstacle is detected in this area, the robot may decelerate at ForwardMaxEmergencyDecel." "Value=100"
CustomInfo: ConfigParam "Name=ForwardClearance" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Minimum distance (in mm) between the front of the  robot and any other object. If an obstacle is detected in this area, the robot may decelerate at ForwardMaxEmergencyDecel." "Value=100"
CustomInfo: ConfigParam "Name=ForwardClearance" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Minimum distance (in mm) between the front of the  robot and any other object. If an obstacle is detected in this area, the robot may decelerate at ForwardMaxEmergencyDecel." "Value=100"
CustomInfo: ConfigParam "Name=ForwardClearance" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Minimum distance (in mm) between the front of the  robot and any other object. If an obstacle is detected in this area, the robot may decelerate at ForwardMaxEmergencyDecel." "Value=100"
CustomInfo: ConfigParam "Name=ForwardClearance" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Minimum distance (in mm) between the front of the  robot and any other object. If an obstacle is detected in this area, the robot may decelerate at ForwardMaxEmergencyDecel." "Value=100"
CustomInfo: ConfigParam "Name=ForwardSlowSpeed" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Speed (in mm/sec) which is considered slow when going forward in teleop mode. Anything slower is also considered slow." "Value=200"
CustomInfo: ConfigParam "Name=ForwardSlowSpeed" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Speed (in mm/sec) which is considered slow when going forward in teleop mode. Anything slower is also considered slow." "Value=200"
CustomInfo: ConfigParam "Name=ForwardSlowSpeed" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Speed (in mm/sec) which is considered slow when going forward in teleop mode. Anything slower is also considered slow." "Value=200"
CustomInfo: ConfigParam "Name=ForwardSlowSpeed" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Speed (in mm/sec) which is considered slow when going forward in teleop mode. Anything slower is also considered slow." "Value=200"
CustomInfo: ConfigParam "Name=ForwardSlowSpeed" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Speed (in mm/sec) which is considered slow when going forward in teleop mode. Anything slower is also considered slow." "Value=200"
CustomInfo: ConfigParam "Name=ForwardSideClearanceAtSlowSpeed" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Minimum distance (in mm) between the side of the robot and other objects during teleop at a ForwardSlowSpeed. The robot may decelerate at ForwardMaxEmergencyDecel or use an E-Stop to avoid any obstacle in this area." "Value=50"
CustomInfo: ConfigParam "Name=ForwardSideClearanceAtSlowSpeed" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Minimum distance (in mm) between the side of the robot and other objects during teleop at a ForwardSlowSpeed. The robot may decelerate at ForwardMaxEmergencyDecel or use an E-Stop to avoid any obstacle in this area." "Value=50"
CustomInfo: ConfigParam "Name=ForwardSideClearanceAtSlowSpeed" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Minimum distance (in mm) between the side of the robot and other objects during teleop at a ForwardSlowSpeed. The robot may decelerate at ForwardMaxEmergencyDecel or use an E-Stop to avoid any obstacle in this area." "Value=50"
CustomInfo: ConfigParam "Name=ForwardSideClearanceAtSlowSpeed" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Minimum distance (in mm) between the side of the robot and other objects during teleop at a ForwardSlowSpeed. The robot may decelerate at ForwardMaxEmergencyDecel or use an E-Stop to avoid any obstacle in this area." "Value=50"
CustomInfo: ConfigParam "Name=ForwardSideClearanceAtSlowSpeed" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Minimum distance (in mm) between the side of the robot and other objects during teleop at a ForwardSlowSpeed. The robot may decelerate at ForwardMaxEmergencyDecel or use an E-Stop to avoid any obstacle in this area." "Value=50"
CustomInfo: ConfigParam "Name=ForwardPaddingAtSlowSpeed" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Padding distance (in mm) when the robot is in teleop mode at a ForwardSlowSpeed. This distance extends beyond the front clearance and defines the area in which the robot may decelerate at ForwardPreferredDecel to avoid an obstacle." "Value=50" "Min=0"
CustomInfo: ConfigParam "Name=ForwardPaddingAtSlowSpeed" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Padding distance (in mm) when the robot is in teleop mode at a ForwardSlowSpeed. This distance extends beyond the front clearance and defines the area in which the robot may decelerate at ForwardPreferredDecel to avoid an obstacle." "Value=50" "Min=0"
CustomInfo: ConfigParam "Name=ForwardPaddingAtSlowSpeed" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Padding distance (in mm) when the robot is in teleop mode at a ForwardSlowSpeed. This distance extends beyond the front clearance and defines the area in which the robot may decelerate at ForwardPreferredDecel to avoid an obstacle." "Value=50" "Min=0"
CustomInfo: ConfigParam "Name=ForwardPaddingAtSlowSpeed" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Padding distance (in mm) when the robot is in teleop mode at a ForwardSlowSpeed. This distance extends beyond the front clearance and defines the area in which the robot may decelerate at ForwardPreferredDecel to avoid an obstacle." "Value=50" "Min=0"
CustomInfo: ConfigParam "Name=ForwardPaddingAtSlowSpeed" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Padding distance (in mm) when the robot is in teleop mode at a ForwardSlowSpeed. This distance extends beyond the front clearance and defines the area in which the robot may decelerate at ForwardPreferredDecel to avoid an obstacle." "Value=50" "Min=0"
CustomInfo: ConfigParam "Name=ForwardFastSpeed" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Speed (in mm/sec) which is considered fast when going forward in teleop mode. Anything faster is also considered fast." "Value=1000"
CustomInfo: ConfigParam "Name=ForwardFastSpeed" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Speed (in mm/sec) which is considered fast when going forward in teleop mode. Anything faster is also considered fast." "Value=1000"
CustomInfo: ConfigParam "Name=ForwardFastSpeed" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Speed (in mm/sec) which is considered fast when going forward in teleop mode. Anything faster is also considered fast." "Value=1000"
CustomInfo: ConfigParam "Name=ForwardFastSpeed" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Speed (in mm/sec) which is considered fast when going forward in teleop mode. Anything faster is also considered fast." "Value=1000"
CustomInfo: ConfigParam "Name=ForwardFastSpeed" "Parent=Teleop Settings" "Priority=Expert" "Type=double" "Desc=Speed (in mm/sec) which is considered fast when going forward in teleop mode. Anything faster is also considered fast." "Value=1000"
