CustomInfo: ConfigSection "Name=Testing Features"
CustomInfo: ConfigParam "Name=EnableShutdownFailedFault" "Parent=Testing Features" "Priority=Expert" "Type=bool" "Desc=Enable the fault 'ShutdownFailedFault' if the robot tries to shutdown but does not." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=DeadlockRecoveryBehavior" "Parent=Testing Features" "Priority=Expert" "Type=bool" "Desc=" "Value=false" "Display=Checkbox&&"
CustomInfo: ConfigParam "Name=GeneralPathPlan" "Parent=Testing Features" "Priority=Expert" "Type=bool" "Desc=Enables the new experimental path planning in (x,y,theta) instead of the old 2D path planning." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=CentrifugalLimits" "Parent=Testing Features" "Priority=Expert" "Type=bool" "Desc=Allows the user to limit the linear and rotational velocities on fully loaded robots and ensuring traction when taking turns. Refer to CentrifugalWt to set in Path Planning Settings." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=RecursiveTasks" "Parent=Testing Features" "Priority=Expert" "Type=bool" "Desc=Let's certain tasks be called recursively.   You can tell which ones allow recursion because they show 'Recursive' in their task classes in MobilePlanner" "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=DisableGLRobotGoalChecker" "Parent=Testing Features" "Priority=Expert" "Type=bool" "Desc=Disables the new robot goal checker, this is the default for this stage of testing but after testing is completing it will move to 'Debug Features' for people who need identical old behavior.   If this is not disabled then only standbys and docks where the robot can do all of the tasks will be used (others will be entirely ignored).  If it is not disabled it also improves the efficiency of the checking for tasks on jobs.  This is mainly intended for use with custom tasks but works for all tasks (though note that only instant tasks work on docks)." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=CartMacroTasks" "Parent=Testing Features" "Priority=Expert" "Type=bool" "Desc=Enables the use of macros for driving into and out of carts (replacing the default method).   This is beta functionality and will cause problems if not used in a proper manner by an expert." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=TestTranslations" "Parent=Testing Features" "Priority=Expert" "Type=bool" "Desc=Enable testing of translations...e.g. commands for testing popups, faults, etc." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=FollowMode" "Parent=Testing Features" "Priority=Expert" "Type=bool" "Desc=Enable follow mode.   This was demoted from a real feature since it is not made for production use." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=NegativeClearances" "Parent=Testing Features" "Priority=Expert" "Type=bool" "Desc=Enables negative clearances for tasks that need to move very close to, or under, objects in the environment." "Value=true" "Display=Checkbox"
CustomInfo: ConfigParam "Name=FollowGuideWithoutAcquire" "Parent=Testing Features" "Priority=Expert" "Type=bool" "Desc=Enables a modified version of the followGuide task which does not perform track acquisition.  Instead it is up to the application to acquire the track before this task is called." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=UseMovePath" "Parent=Testing Features" "Priority=Expert" "Type=bool" "Desc=use Move: Path for Goals and Jobs" "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=TestDockBusy" "Parent=Testing Features" "Priority=Expert" "Type=bool" "Desc=Enables testing feature that keeps the robot queuing state as UNAVAILABLE_BUSY while docked at a charging station" "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=" "Parent=Testing Features" "Priority=Expert" "Type=unknown" "Desc="
CustomInfo: ConfigParam "Name=DoNotEnsureProperSafetyCommissioning" "Parent=Testing Features" "Priority=Expert" "Type=bool" "Desc=By default we make sure that robots that support safety commissioning are properly safety commissioned at every startup, but this flag turns off that behavior." "Value=false" "Display=Checkbox"
