CustomInfo: ConfigSection "Name=Time Of Flight Board_1"
CustomInfo: ConfigParam "Name=AutoConnect" "Parent=Time Of Flight Board_1" "Priority=Expert" "Type=bool" "Desc=Time Of Flight Board_1 exists and should be automatically connected at startup." "Value=false" "Display=Checkbox"
CustomInfo: ConfigParam "Name=" "Parent=Time Of Flight Board_1" "Priority=Factory" "Type=unknown" "Desc="
CustomInfo: ConfigParam "Name=BoardType" "Parent=Time Of Flight Board_1" "Priority=Expert" "Type=string" "Desc=Type of the TOF board." "Value=tof" "Display=Visible:false&&Choices:mtx;;tof"
CustomInfo: ConfigParam "Name=BoardPortType" "Parent=Time Of Flight Board_1" "Priority=Expert" "Type=string" "Desc=Port type that the TOF is on." "Value=serial422" "Display=Visible:false&&Choices:serial;;serial422;;tcp"
CustomInfo: ConfigParam "Name=BoardPort" "Parent=Time Of Flight Board_1" "Priority=Expert" "Type=string" "Desc=Port the board is on." "Value=/dev/ttyUSB2" "Display=Visible:AutoConnect=true"
CustomInfo: ConfigParam "Name=BoardPowerOutput" "Parent=Time Of Flight Board_1" "Priority=Expert" "Type=string" "Desc=Power output that controls this Board's power." "Value=Sonar_1_Power" "Display=Visible:AutoConnect=true&&Choices:;;Main_Laser_Power;;HMI_Power;;WheelLight_Power;;Sonar_1_Power;;Sonar_2_Power;;USB_1_and_2_Power;;USB_3_Power;;Vertical_Laser_Power;;Foot_Laser_Power;;Battery_Out_1;;Battery_Out_2;;Battery_Out_3_and_4;;Aux_5V;;Aux_12V;;Aux_20V;;Audio_Power"
CustomInfo: ConfigParam "Name=Baud" "Parent=Time Of Flight Board_1" "Priority=Expert" "Type=int" "Desc=Baud rate for the TOF board communication. (9600, 19200, 38400, etc.)." "Value=115200" "Display=Visible:false"
CustomInfo: ConfigParam "Name=Delay" "Parent=Time Of Flight Board_1" "Priority=Expert" "Type=int" "Desc=TOF delay (in ms)." "Value=2" "Max=10" "Display=Visible:false"
CustomInfo: ConfigParam "Name=Gain" "Parent=Time Of Flight Board_1" "Priority=Expert" "Type=int" "Desc=Default gain for the board, range 0-31." "Value=10" "Max=31" "Display=Visible:AutoConnect=true"
CustomInfo: ConfigParam "Name=DetectionThreshold" "Parent=Time Of Flight Board_1" "Priority=Expert" "Type=int" "Desc=Default TOF detection threshold for the board." "Value=10000" "Max=65535" "Display=Visible:false"
CustomInfo: ConfigParam "Name=MaxRange" "Parent=Time Of Flight Board_1" "Priority=Expert" "Type=int" "Desc=Default maximum sensor range for the board." "Value=2000" "Max=4335" "Display=Visible:AutoConnect=true"
CustomInfo: ConfigSection "Name=Time_Of_Flight Settings"
CustomInfo: ConfigParam "Name=MaxSecondsToKeepCurrent" "Parent=Time_Of_Flight Settings" "Priority=Expert" "Type=int" "Desc=Duration (in sec) to store the current readings. If 0 or negative, then the readings are not automatically discarded based on age." "Value=1"
CustomInfo: ConfigParam "Name=MinDistBetweenCurrent" "Parent=Time_Of_Flight Settings" "Priority=Expert" "Type=double" "Desc=Minimum distance (in mm) between the stored current readings." "Value=0"
CustomInfo: ConfigParam "Name=UseCustomMaxRange" "Parent=Time_Of_Flight Settings" "Priority=Expert" "Type=bool" "Desc=When enabled (true), the specified CustomMaxRange is used instead of the default maximum range for the sensor. (Use with caution. This is an advanced option that should only be enabled by expert users.)" "Value=false"
CustomInfo: ConfigParam "Name=CustomMaxRange" "Parent=Time_Of_Flight Settings" "Priority=Expert" "Type=int" "Desc=Custom maximum range (in mm) for the sensor. This is applied only when UseCustomMaxRange is enabled. 0 means there is no maximum." "Value=0" "Min=0" "Display=Visible:UseCustomMaxRange=true"
CustomInfo: ConfigSection "Name=Touchscreen"
CustomInfo: ConfigParam "Name=Pages" "Parent=Touchscreen" "Priority=Normal" "Type=unknown" "Desc=Defines the pages that are displayed on the Touchscreen."
CustomInfo: ConfigParam "Name=Style/Appearance" "Parent=Touchscreen" "Priority=Normal" "Type=unknown" "Desc=Defines the style and appearance of the Touchscreen."
CustomInfo: ConfigSection "Name=Triangle Drive To"
CustomInfo: ConfigParam "Name=FinalDistFromVertex" "Parent=Triangle Drive To" "Priority=Expert" "Type=double" "Desc=Distance from the vertex of the final stopping point (for the center of the robot), 0 means go until bump or stall" "Value=500" "Max=2000"
CustomInfo: ConfigParam "Name=ApproachDistFromVertex" "Parent=Triangle Drive To" "Priority=Expert" "Type=double" "Desc=Dist from the vertex of the approach point (for the center of the robot)" "Value=750" "Max=2500"
CustomInfo: ConfigParam "Name=FailTime" "Parent=Triangle Drive To" "Priority=Expert" "Type=int" "Desc=If it takes more seconds than this the task will fail" "Value=45" "Min=0"
CustomInfo: ConfigParam "Name=TriangleDriveSpeed" "Parent=Triangle Drive To" "Priority=Expert" "Type=double" "Desc=Speed to drive at for the approach" "Value=100" "Max=500"
CustomInfo: ConfigParam "Name=TriangleDriveTolerance" "Parent=Triangle Drive To" "Priority=Expert" "Type=double" "Desc=How close to try to get to the point" "Value=25" "Max=200"
CustomInfo: ConfigParam "Name=Line1Length" "Parent=Triangle Drive To" "Priority=Expert" "Type=double" "Desc=Length of the first line of the triangle, 0 means any length line is fine" "Value=254" "Max=1000"
CustomInfo: ConfigParam "Name=AngleBetweenLines" "Parent=Triangle Drive To" "Priority=Expert" "Type=double" "Desc=The angle between the two lines, 0 means any angle is fine" "Value=135" "Max=180"
CustomInfo: ConfigParam "Name=Line2Length" "Parent=Triangle Drive To" "Priority=Expert" "Type=double" "Desc=Length of the second line of the triangle, 0 means any length line is fine" "Value=254" "Max=1000"
CustomInfo: ConfigParam "Name=MaxDistBetweenLinePoints" "Parent=Triangle Drive To" "Priority=Expert" "Type=int" "Desc=Maximum distance between points that are turned into lines, this is a parameter to use to try and get rid of the points where a laser saw part of the target and part of the background.  0 means don't use this feature (mm)" "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=MaxLateralDist" "Parent=Triangle Drive To" "Priority=Expert" "Type=int" "Desc=The maximum of how far to the left or right the robot will look for a vertex.  (Technically the maximum distance between the robot's center and an imaginary line that comes out from the vertex).  Any vertex more than that amount off will be totally ignored.  0 means don't use this feature (mm)" "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=MaxAngleMisalignment" "Parent=Triangle Drive To" "Priority=Expert" "Type=int" "Desc=The maximum of how the angle of the robot and the angle of the vertex line may be off.  Any vertex line more than that amount off will be totally ignored.  0 means don't use this feature (deg)" "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=TriangleFrontClearance" "Parent=Triangle Drive To" "Priority=Expert" "Type=double" "Desc=If any obstacle gets within this distance of the robot while driving to the triangle the robot will stop, this should be large enough the robot can path plan away" "Value=100"
CustomInfo: ConfigParam "Name=TriangleSideClearance" "Parent=Triangle Drive To" "Priority=Expert" "Type=double" "Desc=If any obstacle gets within this distance of the robot while driving to the triangle the robot will stop, this should be large enough the robot can path plan away" "Value=100"
CustomInfo: ConfigParam "Name=AvoidLocationDependentObstacles" "Parent=Triangle Drive To" "Priority=Expert" "Type=bool" "Desc=When enabled (true), the robot avoids location-dependent obstacles like forbidden lines and other robots. If this is disabled, then physical guards must be used to contain the robot." "Value=true"
CustomInfo: ConfigParam "Name=TriangleAdjustVertex" "Parent=Triangle Drive To" "Priority=Expert" "Type=bool" "Desc=Whether to use an alternate calculation for the vertex" "Value=false"
CustomInfo: ConfigParam "Name=TriangleGotoVertex" "Parent=Triangle Drive To" "Priority=Expert" "Type=bool" "Desc=True to go to the vertex instead of the point in front of it" "Value=false"
CustomInfo: ConfigParam "Name=TriangleIgnoreDist" "Parent=Triangle Drive To" "Priority=Expert" "Type=double" "Desc=Old default value was 0 for GotoVertex true, and 250 for GotoVertex false.  When the robot is within this many mm of its final point it will start ignoring the triangle and just go based on the last reading (because as we get too close sometimes we lose our target (this probably shouldn't be needed with non-black targets))" "Value=250"
CustomInfo: ConfigParam "Name=TriangleBackDist" "Parent=Triangle Drive To" "Priority=Expert" "Type=int" "Desc=After the triangle point has been reached the robot will back up this distance" "Value=0" "Max=0"
CustomInfo: ConfigParam "Name=TriangleLogMore" "Parent=Triangle Drive To" "Priority=Expert" "Type=bool" "Desc=Logs more information about the triangle driving" "Value=false"
CustomInfo: ConfigParam "Name=" "Parent=Triangle Drive To" "Priority=Expert" "Type=unknown" "Desc="
CustomInfo: ConfigParam "Name=TriangleTransVelMax" "Parent=Triangle Drive To" "Priority=Expert" "Type=double" "Desc=Maximum forward translational velocity (0 means use default)" "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=TriangleTransNegVelMax" "Parent=Triangle Drive To" "Priority=Expert" "Type=double" "Desc=Maximum backwards translational velocity (0 means use default)" "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=TriangleTransAccel" "Parent=Triangle Drive To" "Priority=Expert" "Type=double" "Desc=Translational acceleration (0 means use default)" "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=TriangleTransDecel" "Parent=Triangle Drive To" "Priority=Expert" "Type=double" "Desc=Translational deceleration (0 means use default)" "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=TriangleRotVelMax" "Parent=Triangle Drive To" "Priority=Expert" "Type=double" "Desc=Maximum rotational velocity (0 means use default)" "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=TriangleRotAccel" "Parent=Triangle Drive To" "Priority=Expert" "Type=double" "Desc=Rotational acceleration (0 means use default)" "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=TriangleRotDecel" "Parent=Triangle Drive To" "Priority=Expert" "Type=double" "Desc=Rotational deceleration (0 means use default)" "Value=0" "Min=0"
CustomInfo: ConfigParam "Name=StopOnProx" "Parent=Triangle Drive To" "Priority=Expert" "Type=bool" "Desc=Whether we should stop if any of the prox sensors detects something (this should probably always be true)" "Value=true"
CustomInfo: ConfigParam "Name=UseQuickStop" "Parent=Triangle Drive To" "Priority=Expert" "Type=bool" "Desc=Whether we should use a quickstop when the prox or input triggers (this is like an estop, but isn't latching, and will use brakes on a platform that has them)" "Value=false"
CustomInfo: RobotName Omron LD250 RobotSubType RobotType MTX
CustomInfo: OrigTicksMM 100 OrigRevCount 0 OrigDriftFactor 0 OrigGyroCW 0 OrigGyroCCW 0 OrigGyroType 2 OrigSerialNumber 1
CustomInfo: CurrentTicksMM 100 CurrentRevCount 0 CurrentDriftFactor 0 CurrentGyroCW 0 CurrentGyroCCW 0 CurrentGyroType 2 CurrentSerialNumber 1
CustomInfo: MainDirMod 90 MinLoopProb 0.8 MaxRange 16000
CustomInfo: DistError 20 ShiftError 20 TurnError 2 DriftError 1
CustomInfo: UseGyroErrorModel 0 GyroError 0.3
CustomInfo: ScanMatcher 1
CustomInfo: MatchLasers Never
CustomInfo: UseGuidanceLines 0
CustomInfo: UseReflectorPosts 1 UseReflectorPostLoopClosing 1
MapInfo: BoundaryType Name=DistanceAdjustment "Label=DistanceAdjustment" "Desc=Line to adjust crow flies distance (geometric distance) calculation." NameRequired=1 Color0=0x00FFFF Shape=Dash "TaskListCount=1" "TaskListIds=RequiredCustomTasks" "TaskListLabels=Required Custom Tasks" "TaskClasses=Custom" "Desc=Line that artificially inflates the 'as the crow flies' distance calculation." "Label=DistanceAdjustment"
MapInfo: ArgDesc Name=Grouping Parent=DistanceAdjustment Type=string Priority=Normal "Desc=Optional name of the containing logical group. If the 'as the crow flies' distance crosses multiple DistanceAdjustment lines that are in the same group, then only the line with the highest cost is applied." "Label=Grouping"
