TaskInfo: ArgDesc "Name=input 8 macro" "Parent=customInputsCheckEachInstant" "Type=string" "Priority=Detailed" "Desc=Macro to invoke if input 8 is triggered." "Value=" "Display=Macro" "Label=input 8 macro"
TaskInfo: TaskDesc "Name=customOutputOff" "Desc=Turns off the specified custom output." "Class=Instant"
TaskInfo: ArgDesc "Name=output" "Parent=customOutputOff" "Type=string" "Priority=Important" "Desc=Custom output to turn off." "Value=" "Display=DigitalIO:customOutputs|Optional" "Label=output"
TaskInfo: TaskDesc "Name=customOutputOn" "Desc=Turns on the specified custom output." "Class=Instant"
TaskInfo: ArgDesc "Name=output" "Parent=customOutputOn" "Type=string" "Priority=Important" "Desc=Custom output to turn on." "Value=" "Display=DigitalIO:customOutputs|Optional" "Label=output"
TaskInfo: TaskDesc "Name=deltaHeading" "Desc=Changes the heading by the specified relative amount." "Class=Movement|Heading"
TaskInfo: ArgDesc "Name=delta heading" "Parent=deltaHeading" "Type=int" "Priority=Important" "Desc=Amount (in deg) by which to turn the robot. Use positive values to turn the robot left/counterclockwise; negative values to turn it right/clockwise. Note that if the absolute value exceeds 360, then the robot will make at least one complete rotation." "Value=0" "Label=delta heading"
TaskInfo: ArgDesc "Name=rotVelMax" "Parent=deltaHeading" "Type=int" "Priority=Detailed" "Desc=Maximum rotational velocity (in deg/sec) when turning. 0 means use the default." "Value=0" "Min=0" "Label=rotVelMax"
TaskInfo: ArgDesc "Name=rotAccel" "Parent=deltaHeading" "Type=int" "Priority=Detailed" "Desc=Rotational acceleration (in deg/sec/sec) when turning. 0 means use the default." "Value=0" "Min=0" "Label=rotAccel"
TaskInfo: ArgDesc "Name=rotDecel" "Parent=deltaHeading" "Type=int" "Priority=Detailed" "Desc=Rotational deceleration (in deg/sec/sec) when turning. 0 means use the default." "Value=0" "Min=0" "Label=rotDecel"
TaskInfo: ArgDesc "Name=time until fail" "Parent=deltaHeading" "Type=int" "Priority=Detailed" "Desc=Duration (in sec) to wait if unable to turn before declaring that the task has failed." "Value=30" "Min=0" "Label=time until fail"
TaskInfo: ArgDesc "Name=minimum time" "Parent=deltaHeading" "Type=int" "Priority=Detailed" "Desc=Minimum duration (in sec) of this task. If the robot reaches the destination heading in less time, the task waits for the remainder of the duration. 0 means that task should complete as soon as the robot reaches the destination heading." "Value=0" "Min=0" "Label=minimum time"
TaskInfo: ArgDesc "Name=use localization" "Parent=deltaHeading" "Type=bool" "Priority=Detailed" "Desc=True to use localization while turning. False to rely solely on the odometry." "Value=true" "Label=use localization"
TaskInfo: ArgDesc "Name=checkRadius" "Parent=deltaHeading" "Type=bool" "Priority=Detailed" "Desc=Stop the robot from rotating when there is an object within a user-defined radius." "Value=false" "Label=checkRadius"
TaskInfo: ArgDesc "Name=radiusAdjustment" "Parent=deltaHeading" "Type=int" "Priority=Detailed" "Desc=The additional radius (mm) beyond the robot's radius to check for obstacles when rotating." "Value=0" "Label=radiusAdjustment"
TaskInfo: GoalTaskDesc "Name=goto" "Desc=Drives to a specified goal." "Class=Movement" "Label=goto (a goal)"
TaskInfo: ArgDesc "Name=goal to go to" "Parent=goto" "Type=string" "Priority=Normal" "Desc=Name of the destination goal." "Value=" "Label=goal to go to"
TaskInfo: TaskDesc "Name=gotoPoint" "Desc=Drives to a specified point." "Class=Movement"
TaskInfo: ArgDesc "Name=x" "Parent=gotoPoint" "Type=int" "Priority=Important" "Desc=X coordinate (in mm) of the destination." "Value=0" "Label=x"
TaskInfo: ArgDesc "Name=y" "Parent=gotoPoint" "Type=int" "Priority=Important" "Desc=Y coordinate (in mm) of the destination." "Value=0" "Label=y"
TaskInfo: ArgDesc "Name=heading" "Parent=gotoPoint" "Type=int" "Priority=Normal" "Desc=Heading (in deg) to face once the destination is reached." "Value=0" "Label=heading"
TaskInfo: TaskDesc "Name=gotoRandom" "Desc=Drives to a random goal, which may be optionally constrained by a matching name prefix." "Class=Movement"
TaskInfo: ArgDesc "Name=prefix" "Parent=gotoRandom" "Type=string" "Priority=Normal" "Desc=If a prefix is specified, then only goal names that start with the prefix are selected. If blank, then any goal is selected. Wildcards are not supported." "Value=" "Label=prefix"
TaskInfo: TaskDesc "Name=jobTypeCheck" "Desc=Specify a different macro depending on whether a goal is a pickup, dropoff or neither."
TaskInfo: ArgDesc "Name=none" "Parent=jobTypeCheck" "Type=string" "Priority=Normal" "Desc=Macro to execute when the task is not part of a pickup or dropoff job.  Optional." "Value=" "Display=Macro" "Label=none"
TaskInfo: ArgDesc "Name=pickup" "Parent=jobTypeCheck" "Type=string" "Priority=Normal" "Desc=Macro to execute when the job segment is a pickup.  Optional." "Value=" "Display=Macro" "Label=pickup"
TaskInfo: ArgDesc "Name=dropoff" "Parent=jobTypeCheck" "Type=string" "Priority=Normal" "Desc=Macro to execute when the job segment is a dropoff.  Optional." "Value=" "Display=Macro" "Label=dropoff"
TaskInfo: TaskDesc "Name=laserCheckBox" "Desc=Waits for something to enter the rectangular area surrounding the robot. Macros may be triggered upon detection or timeout." "Class=Monitor"
TaskInfo: ArgDesc "Name=width" "Parent=laserCheckBox" "Type=int" "Priority=Important" "Desc=Width (in mm) of the area to check, centered at the center of the robot." "Value=2000" "Min=100" "Label=width"
TaskInfo: ArgDesc "Name=length" "Parent=laserCheckBox" "Type=int" "Priority=Important" "Desc=Length (in mm) of the area to check, centered at the center of the robot." "Value=2000" "Min=100" "Label=length"
TaskInfo: ArgDesc "Name=triggerMacro" "Parent=laserCheckBox" "Type=string" "Priority=Normal" "Desc=Macro to invoke when something is detected in the area. Optional." "Value=" "Display=Macro" "Label=triggerMacro"
TaskInfo: ArgDesc "Name=timeout" "Parent=laserCheckBox" "Type=int" "Priority=Normal" "Desc=Maximum duration (in sec) to wait for something to be detected. 0 means wait forever." "Value=0" "Min=0" "Label=timeout"
TaskInfo: ArgDesc "Name=timeoutMacro" "Parent=laserCheckBox" "Type=string" "Priority=Normal" "Desc=Macro to invoke if nothing is detected in the area within the specified timeout. Optional." "Value=" "Display=Macro" "Label=timeoutMacro"
TaskInfo: TaskDesc "Name=laserCheckEmptyBox" "Desc=Waits for the rectangular area surrounding the robot to be empty. Macros may be triggered upon detection or timeout." "Class=Monitor"
TaskInfo: ArgDesc "Name=width" "Parent=laserCheckEmptyBox" "Type=int" "Priority=Important" "Desc=Width (in mm) of the area to check, centered at the center of the robot." "Value=2000" "Min=100" "Label=width"
TaskInfo: ArgDesc "Name=length" "Parent=laserCheckEmptyBox" "Type=int" "Priority=Important" "Desc=Length (in mm) of the area to check, centered at the center of the robot." "Value=2000" "Min=100" "Label=length"
TaskInfo: ArgDesc "Name=triggerMacro" "Parent=laserCheckEmptyBox" "Type=string" "Priority=Normal" "Desc=Macro to invoke when the area becomes empty. Optional." "Value=" "Display=Macro" "Label=triggerMacro"
TaskInfo: ArgDesc "Name=timeout" "Parent=laserCheckEmptyBox" "Type=int" "Priority=Normal" "Desc=Maximum duration (in sec) to wait for the area to become empty. 0 means wait forever." "Value=0" "Min=0" "Label=timeout"
TaskInfo: ArgDesc "Name=timeoutMacro" "Parent=laserCheckEmptyBox" "Type=string" "Priority=Normal" "Desc=Macro to invoke the area does not become empty within the specified timeout. Optional." "Value=" "Display=Macro" "Label=timeoutMacro"
TaskInfo: TaskDesc "Name=laserCheckPolar" "Desc=Waits for something to enter the angular area (i.e. pie slice) surrounding the robot. Macros may be triggered upon detection or timeout." "Class=Monitor"
TaskInfo: ArgDesc "Name=start angle" "Parent=laserCheckPolar" "Type=int" "Priority=Important" "Desc=Start angle (in deg) of the area to check. This should be less than the end angle. (Otherwise, the slice is inverted.)" "Value=-45" "Min=-180" "Max=180" "Label=start angle"
TaskInfo: ArgDesc "Name=end angle" "Parent=laserCheckPolar" "Type=int" "Priority=Important" "Desc=End angle (in deg) of the area to check. This should be greater than the start angle. (Otherwise, the slice is inverted.)" "Value=45" "Min=-180" "Max=180" "Label=end angle"
TaskInfo: ArgDesc "Name=dist" "Parent=laserCheckPolar" "Type=int" "Priority=Important" "Desc=Length (in mm) of the area, extending from the front of the robot." "Value=1000" "Min=0" "Label=dist"
TaskInfo: ArgDesc "Name=triggerMacro" "Parent=laserCheckPolar" "Type=string" "Priority=Normal" "Desc=Macro to invoke when something is detected in the area. Optional." "Value=" "Display=Macro" "Label=triggerMacro"
TaskInfo: ArgDesc "Name=timeout" "Parent=laserCheckPolar" "Type=int" "Priority=Normal" "Desc=Maximum duration (in sec) to wait for something to be detected. 0 means wait forever." "Value=0" "Min=0" "Label=timeout"
TaskInfo: ArgDesc "Name=timeoutMacro" "Parent=laserCheckPolar" "Type=string" "Priority=Normal" "Desc=Macro to invoke if nothing is detected in the area within the specified timeout. Optional." "Value=" "Display=Macro" "Label=timeoutMacro"
TaskInfo: TaskDesc "Name=laserGreetBox" "Desc=Waits for something to enter the box says something and then tries to drive up to them" "Class=Movement|RobotAudio"
TaskInfo: ArgDesc "Name=width" "Parent=laserGreetBox" "Type=int" "Priority=Important" "Desc=the width of the box to check, measured in mm, centered at the middle of the robot" "Value=2000" "Min=100" "Label=width"
TaskInfo: ArgDesc "Name=length" "Parent=laserGreetBox" "Type=int" "Priority=Important" "Desc=the length of the box to check, measured in mm, centered at the center of the robot" "Value=2000" "Min=100" "Label=length"
TaskInfo: ArgDesc "Name=greeting speech" "Parent=laserGreetBox" "Type=string" "Priority=Normal" "Desc=What to say when someone walks into the box before driving up to them. (Special Codes: $g=goal name. Current robot position $X (x in mm) $Y (y in mm) $T (heading in degrees, -180 to 180). Time in GMT: $y=current year, $m=month, $d=day, $H=hour, $M=minute, $S=second.)" "Value=" "Label=greeting speech"
TaskInfo: ArgDesc "Name=speed" "Parent=laserGreetBox" "Type=int" "Priority=Normal" "Desc=The speed in mm/sec the robot should move at" "Value=400" "Min=0" "Label=speed"
TaskInfo: ArgDesc "Name=front clearance" "Parent=laserGreetBox" "Type=int" "Priority=Detailed" "Desc=The distance in mm the robot should stop in front of obstacles" "Value=200" "Label=front clearance"
TaskInfo: ArgDesc "Name=front padding at stopped" "Parent=laserGreetBox" "Type=int" "Priority=Detailed" "Desc=The padding at 0 velocity" "Value=200" "Label=front padding at stopped"
TaskInfo: ArgDesc "Name=front padding at speed" "Parent=laserGreetBox" "Type=int" "Priority=Detailed" "Desc=The padding at speed parameter velocity" "Value=400" "Label=front padding at speed"
TaskInfo: ArgDesc "Name=max padding deceleration" "Parent=laserGreetBox" "Type=int" "Priority=Detailed" "Desc=The maximum deceleration while still in padding (it will estop if something gets through the padding)" "Value=600" "Label=max padding deceleration"
TaskInfo: ArgDesc "Name=side clearance" "Parent=laserGreetBox" "Type=int" "Priority=Detailed" "Desc=The distance in mm the robot should leave on the side of obstacles" "Value=50" "Label=side clearance"
TaskInfo: ArgDesc "Name=transAccel" "Parent=laserGreetBox" "Type=int" "Priority=Detailed" "Desc=The translational acceleration to use, 0 means use robot default" "Value=0" "Min=0" "Label=transAccel"
TaskInfo: ArgDesc "Name=transDecel" "Parent=laserGreetBox" "Type=int" "Priority=Detailed" "Desc=The translational deceleration to use, 0 means use robot default" "Value=0" "Min=0" "Label=transDecel"
TaskInfo: ArgDesc "Name=rotVelMax" "Parent=laserGreetBox" "Type=int" "Priority=Detailed" "Desc=The rotVelMax to use, 0 means use robot default" "Value=0" "Min=0" "Label=rotVelMax"
TaskInfo: ArgDesc "Name=rotAccel" "Parent=laserGreetBox" "Type=int" "Priority=Detailed" "Desc=The rotational acceleration to use, 0 means use robot default" "Value=0" "Min=0" "Label=rotAccel"
TaskInfo: ArgDesc "Name=rotDecel" "Parent=laserGreetBox" "Type=int" "Priority=Detailed" "Desc=The rotational deceleration to use, 0 means use robot default" "Value=0" "Min=0" "Label=rotDecel"
TaskInfo: TaskDesc "Name=localizeAtGoal" "Desc=<p><blockquote><b><font color=#A91B16>Use with caution. This task can cause the robot to become lost.  <nobr> Do not use the task without explicit user input.</nobr></font></b></blockquote></p><p>Localizes at a specified goal.</p>" "Class=Localize|Instant"
TaskInfo: ArgDesc "Name=goal to localize at" "Parent=localizeAtGoal" "Type=string" "Priority=Important" "Desc=Name of the goal at which to localize." "Value=" "Display=MapItem:Goal|SubtypeAndParent|Required" "Label=goal to localize at"
TaskInfo: ArgDesc "Name=xySpread" "Parent=localizeAtGoal" "Type=double" "Priority=Normal" "Desc=Distance (in mm) to spread the localization. 0 means do not spread. -1 means use the default spread." "Value=-1" "Label=xySpread"
TaskInfo: ArgDesc "Name=angleSpread" "Parent=localizeAtGoal" "Type=double" "Priority=Normal" "Desc=Angle (in deg) to spread the localization. 0 means do not spread. -1 means use the default spread." "Value=-1" "Label=angleSpread"
TaskInfo: TaskDesc "Name=macroRepeat" "Desc=Repeatedly invokes a macro, for the specified number of times or until the macro fails."
TaskInfo: ArgDesc "Name=macro" "Parent=macroRepeat" "Type=string" "Priority=Important" "Desc=Name of the macro to invoke." "Value=" "Display=Macro" "Label=macro"
TaskInfo: ArgDesc "Name=repeatTimes" "Parent=macroRepeat" "Type=int" "Priority=Normal" "Desc=Number of times to call the macro. -1 means repeat forever or until the macro fails." "Value=-1" "Min=-1" "Label=repeatTimes"
TaskInfo: TaskDesc "Name=makeClientsBeep" "Desc=Requests that the client applications emit a beep. (Client applications include MobilePlanner and MobileEyes.)  Audio must be properly configured on the client." "Class=ClientAudio|Instant"
TaskInfo: TaskDesc "Name=move" "Desc=Moves forward by the specified distance, provided that no obstacles are encountered." "Class=Movement"
TaskInfo: ArgDesc "Name=distance" "Parent=move" "Type=int" "Priority=Important" "Desc=Distance (in mm) to move forward from the current location." "Value=1000" "Label=distance"
TaskInfo: ArgDesc "Name=speed" "Parent=move" "Type=int" "Priority=Normal" "Desc=Speed (in mm/sec) at which to move." "Value=400" "Min=0" "Label=speed"
TaskInfo: ArgDesc "Name=front clearance" "Parent=move" "Type=int" "Priority=Detailed" "Desc=Distance (in mm) to maintain between the front of the robot and any obstacles." "Value=200" "Label=front clearance"
TaskInfo: ArgDesc "Name=side clearance" "Parent=move" "Type=int" "Priority=Detailed" "Desc=Distance (in mm) to maintain between the side of the robot and any obstacles." "Value=50" "Label=side clearance"
TaskInfo: ArgDesc "Name=time until fail" "Parent=move" "Type=int" "Priority=Detailed" "Desc=Duration (in sec) to wait for an obstacle to clear before declaring that the move has failed." "Value=30" "Min=0" "Label=time until fail"
TaskInfo: ArgDesc "Name=transAccel" "Parent=move" "Type=int" "Priority=Detailed" "Desc=Acceleration (in mm/sec/sec) for the move. 0 means use the robot's default acceleration." "Value=0" "Min=0" "Label=transAccel"
TaskInfo: ArgDesc "Name=transDecel" "Parent=move" "Type=int" "Priority=Detailed" "Desc=Deceleration (in mm/sec/sec) for the move. 0 means use the robot's default acceleration." "Value=0" "Min=0" "Label=transDecel"
TaskInfo: ArgDesc "Name=minimum time" "Parent=move" "Type=int" "Priority=Detailed" "Desc=Minimum duration (in sec) of this task. If the robot reaches the destination in less time, the task waits for the remainder of the duration. 0 means that task should complete as soon as the robot reaches the destination." "Value=0" "Min=0" "Label=minimum time"
TaskInfo: ArgDesc "Name=AvoidLocationDependentObstacles" "Parent=move" "Type=bool" "Priority=Detailed" "Desc=When enabled (true), the robot avoids location-dependent obstacles like forbidden lines and other robots. If this is disabled, then physical guards must be used to contain the robot." "Value=true" "Label=AvoidLocationDependentObstacles"
TaskInfo: ArgDesc "Name=always succeed" "Parent=move" "Type=bool" "Priority=Detailed" "Desc=Return success regardless of the distance moved. When enabled, the tasks will report success even if the destination is not reached. When disabled, the task fails if the destination is not reached." "Value=false" "Label=always succeed"
TaskInfo: ArgDesc "Name=finish if stopped" "Parent=move" "Type=bool" "Priority=Detailed" "Desc=Finish the task if the robot cannot move after the first two seconds. When enabled, the task finishes as soon as the robot cannot move. When disabled, the robot must be blocked for the specified 'time until fail' before the task is finished." "Value=true" "Label=finish if stopped"
TaskInfo: TaskDesc "Name=Move: Path" "Desc=Map based AMR motion" "Class=Movement"
TaskInfo: ArgDesc "Name=Goal" "Parent=Move: Path" "Type=string" "Priority=Important" "Desc=Specifies the desired Map-based Goal to navigate to." "Value=" "Display=MapItem:Goal|SubtypeAndParent|OptionalAndEditable" "Label=Goal"
TaskInfo: ArgDesc "Name=MotionMode" "Parent=Move: Path" "Type=string" "Priority=Important" "Desc=Specifies the type of motion used during the execution of the task." "Value=Default" "Display=Choices:Default;;Dynamic;;AGV;;Straight" "Label=Motion Mode"
TaskInfo: ArgDesc "Name=ObstacleMode" "Parent=Move: Path" "Type=string" "Priority=Normal" "Desc=Specifies how obstacles are handled during the execution of the task" "Value=None" "Display=Choices:None;;Wait&&Visible:MotionMode!=Default" "Label=Obstacle Mode"
TaskInfo: ArgDesc "Name=Timeout" "Parent=Move: Path" "Type=int" "Priority=Normal" "Desc=Elapsed time in seconds since the AMR has stopped for an obstacle before failing the Task." "Value=400" "Min=1" "Max=6000" "Display=Visible:ObstacleMode!=None&&Visible:MotionMode!=Default" "Label=Timeout"
TaskInfo: ArgDesc "Name=SmoothingMode" "Parent=Move: Path" "Type=string" "Priority=Normal" "Desc=Specifies the type of smoothing algorithm used on the the base AMR path." "Value=Fixed" "Display=Choices:Fixed;;PreferredLine&&Visible:MotionMode!=Straight&&Visible:MotionMode!=Default" "Label=Smoothing Mode"
TaskInfo: ArgDesc "Name=SmoothingPercentage" "Parent=Move: Path" "Type=double" "Priority=Normal" "Desc=Specifies the scaled amount of smoothing used in conjuction with the smoothing algorithm. 100 represents maximum smoothing." "Value=75" "Min=1" "Max=100" "Display=Visible:MotionMode!=Straight&&Visible:MotionMode!=Default" "Label=Smoothing Percentage"
TaskInfo: ArgDesc "Name=ReplanningMode" "Parent=Move: Path" "Type=string" "Priority=Normal" "Desc=Specifies the side of line mode of the replanning algorithm." "Value=Normal" "Display=Choices:Normal;;PreferLeft;;PreferRight&&Visible:MotionMode=Dynamic&&Visible:MotionMode!=Default" "Label=Replanning Mode"
TaskInfo: ArgDesc "Name=LateralReplanningLimit" "Parent=Move: Path" "Type=double" "Priority=Detailed" "Desc=Specifies the maximum lateral distance in mm that the AMR could deviate from its base path during a replanning event." "Value=2500" "Min=50" "Max=3000" "Display=Visible:MotionMode=Dynamic&&Visible:MotionMode!=Default" "Label=Lateral Replanning Limit"
TaskInfo: ArgDesc "Name=ReplanningPreference" "Parent=Move: Path" "Type=double" "Priority=Detailed" "Desc=" "Value=300" "Min=50" "Max=3000" "Display=Visible:False&&Visible:MotionMode!=Default" "Label=ReplanningPreference"
TaskInfo: ArgDesc "Name=ReplanningFreeSpace" "Parent=Move: Path" "Type=double" "Priority=Detailed" "Desc=Specifies the distance in mm to avoid obstacles." "Value=400" "Min=50" "Max=1000" "Display=Visible:MotionMode=Dynamic&&Visible:MotionMode!=Default" "Label=Replanning Free Space"
TaskInfo: ArgDesc "Name=ReplanningTriggerDistance" "Parent=Move: Path" "Type=double" "Priority=Detailed" "Desc=" "Value=150" "Min=100" "Max=1000" "Display=Visible:False&&Visible:MotionMode!=Default" "Label=ReplanningTriggerDistance"
TaskInfo: ArgDesc "Name=ReplanningTriggerTime" "Parent=Move: Path" "Type=double" "Priority=Detailed" "Desc=Specifies the time in seconds to trigger a replanning event.  Measured as the elapsed time from when the AMR comes to a complete stop." "Value=1" "Min=0.5" "Max=300" "Display=Visible:MotionMode=Dynamic&&Visible:MotionMode!=Default" "Label=Replanning Trigger Time"
TaskInfo: ArgDesc "Name=SeamlessMotionMode" "Parent=Move: Path" "Type=string" "Priority=Normal" "Desc=Optimizes motion when possible to reduce unnecessary stops in the AMR trajectory.  Requires Cycle Time Optimization License to activate." "Value=None" "Display=Choices:None;;Queuing&&Visible:MotionMode!=Default" "Label=SeamlessMotionMode"
TaskInfo: ArgDesc "Name=AllowReverseMotion" "Parent=Move: Path" "Type=bool" "Priority=Detailed" "Desc=Specifies whether reverse Motion is allowed when possible for any part of the motion segment." "Value=false" "Display=Checkbox&&&&Visible:MotionMode!=Default" "Label=Allow Reverse Motion"
TaskInfo: ArgDesc "Name=AllowGlobalReplanning" "Parent=Move: Path" "Type=bool" "Priority=Detailed" "Desc=" "Value=false" "Display=Checkbox&&Visible:False&&Visible:MotionMode!=Default" "Label=AllowGlobalReplanning"
TaskInfo: ArgDesc "Name=PositionTolerance" "Parent=Move: Path" "Type=double" "Priority=Normal" "Desc=MMaximum allowable tolerance in mm between the AMR final position and the desired final position." "Value=200" "Min=100" "Max=4000" "Display=Visible:MotionMode!=Default" "Label=Final Position Tolerance"
TaskInfo: ArgDesc "Name=HeadingTolerance" "Parent=Move: Path" "Type=double" "Priority=Normal" "Desc=MMaximum allowable tolerance in degrees between the AMR final heading and the desired final heading." "Value=20" "Min=5" "Max=180" "Display=Visible:MotionMode!=Default" "Label=Final Heading Tolerance"
TaskInfo: ArgDesc "Name=DebugMode" "Parent=Move: Path" "Type=string" "Priority=Detailed" "Desc=Specifies what task information is logged for debugging purposes" "Value=Default" "Display=Choices:Default;;None;;Normal;;Moderate;;Extensive;;All" "Label=Debug Mode"
TaskInfo: ArgDesc "Name=ClearanceMode" "Parent=Move: Path" "Type=string" "Priority=Detailed" "Desc=Specifies the area around the AMR for obstacle protection while moving to the final location" "Value=Default" "Display=Choices:Default;;Normal;;Variable;;Custom" "Label=Clearance Mode"
TaskInfo: ArgDesc "Name=ApproachDistance" "Parent=Move: Path" "Type=double" "Priority=Detailed" "Desc=Specifies the minimum distance in mm that the AMR should stop when approaching an obstacle" "Value=1000" "Min=100" "Max=8000" "Display=Visible:ClearanceMode!=Normal&&Visible:ClearanceMode!=Default&&Visible:ClearanceMode!=Default" "Label=Approach Distance"
TaskInfo: ArgDesc "Name=TaxiLineApproachDistance" "Parent=Move: Path" "Type=double" "Priority=Detailed" "Desc=" "Value=1000" "Min=100" "Max=8000" "Display=Visible:ClearanceMode!=Normal&&Visible:ClearanceMode!=Default&&Visible:false&&Visible:ClearanceMode!=Default" "Label=TaxiLineApproachDistance"
TaskInfo: ArgDesc "Name=VirtualObstaclesAreReal" "Parent=Move: Path" "Type=bool" "Priority=Detailed" "Desc=Treat virtual obstacles (Forbidden Area, etc) as real obstacles" "Value=false" "Display=Checkbox&&Visible:false" "Label=Virtual Obstacles Are Real"
TaskInfo: ArgDesc "Name=ClearanceShape" "Parent=Move: Path" "Type=string" "Priority=Detailed" "Desc=Specifies the footprint shape of the AMR for obstacle protection" "Value=Normal" "Display=Choices:Normal;;Tight;;Expanded;;Custom;;Polygon&&Visible:ClearanceMode!=Default" "Label=Clearance Shape"
TaskInfo: ArgDesc "Name=FrontClearance" "Parent=Move: Path" "Type=double" "Priority=Detailed" "Desc=Specifies the length in mm of the front clearance zone from the front edge of the AMR." "Value=0" "Min=-600" "Max=1000" "Display=Visible:ClearanceShape=Custom&&Visible:ClearanceMode!=Default" "Label=Front Clearance"
TaskInfo: ArgDesc "Name=LeftClearance" "Parent=Move: Path" "Type=double" "Priority=Detailed" "Desc=Specifies the length in mm of the left side clearance zone from the left edge of the AMR." "Value=0" "Min=-600" "Max=1000" "Display=Visible:ClearanceShape=Custom&&Visible:ClearanceMode!=Default" "Label=Left Clearance"
TaskInfo: ArgDesc "Name=RightClearance" "Parent=Move: Path" "Type=double" "Priority=Detailed" "Desc=Specifies the length in mm of the right side clearance zone from the right edge of the AMR." "Value=0" "Min=-600" "Max=1000" "Display=Visible:ClearanceShape=Custom&&Visible:ClearanceMode!=Default" "Label=Right Clearance"
TaskInfo: ArgDesc "Name=BackClearance" "Parent=Move: Path" "Type=double" "Priority=Detailed" "Desc=Specifies the length in mm of the back side clearance zone from the back edge of the AMR." "Value=0" "Min=-600" "Max=1000" "Display=Visible:ClearanceShape=Custom&&Visible:ClearanceMode!=Default" "Label=Back Clearance"
TaskInfo: ArgDesc "Name=ClearanceSwitchDistance" "Parent=Move: Path" "Type=double" "Priority=Detailed" "Desc=Specifies the distance in mm from the desired final position that the AMR will switch to using the defined Internal Clearances" "Value=1500" "Min=0" "Max=3000" "Display=Visible:false" "Label=Clearance Switch Distance"
TaskInfo: ArgDesc "Name=FinalClearanceShape" "Parent=Move: Path" "Type=string" "Priority=Detailed" "Desc=Specifies the footprint shape of the AMR for obstacle protection during the final motion" "Value=Normal" "Display=Choices:Normal;;Tight;;Expanded;;Custom&&Visible:false" "Label=Final Clearance Shape"
