TaskInfo: TaskDesc "Name=Move: Segment" "Desc=Motion that is composed of small segments" "Class=Movement"
TaskInfo: ArgDesc "Name=MotionMode" "Parent=Move: Segment" "Type=string" "Priority=Important" "Desc=Specifies the type of motion used during the execution of the task." "Value=Move" "Display=Choices:Move;;DeltaHeading;;SetHeading" "Label=Motion Mode"
TaskInfo: ArgDesc "Name=Distance" "Parent=Move: Segment" "Type=double" "Priority=Important" "Desc=The distance in mm that the AMR will move from the beginning location.  Motion is parallel with the primary X-axis of the AMR coordinate frame." "Value=1000" "Display=Visible:MotionMode=Move" "Label=Distance"
TaskInfo: ArgDesc "Name=DeltaAngle" "Parent=Move: Segment" "Type=double" "Priority=Important" "Desc=Specifies the desired relative heading change in degrees to the current heading of the AMR. Use positive values to turn the AMR left/counterclockwise. Negative values to turn the AMR right/clockwise." "Value=0" "Display=Visible:MotionMode=DeltaHeading" "Label=DeltaAngle"
TaskInfo: ArgDesc "Name=AbsoluteAngle" "Parent=Move: Segment" "Type=double" "Priority=Important" "Desc=The absolute heading in degrees that the AMR will align to." "Value=0" "Min=-180" "Max=180" "Display=Visible:MotionMode=SetHeading" "Label=AbsoluteAngle"
TaskInfo: ArgDesc "Name=ObstacleMode" "Parent=Move: Segment" "Type=string" "Priority=Normal" "Desc=Specifies how obstacles are handled during the execution of the task" "Value=Wait" "Display=Choices:None;;Wait" "Label=Obstacle Mode"
TaskInfo: ArgDesc "Name=Timeout" "Parent=Move: Segment" "Type=int" "Priority=Normal" "Desc=Elapsed time in seconds since the AMR has stopped for an obstacle before failing the Task." "Value=400" "Min=1" "Max=54000" "Display=Visible:ObstacleMode!=None" "Label=Timeout"
