TaskInfo: TaskDesc "Name=moveProx" "Desc=Move forward by the specified distance, stopping if proximity sensors are triggered.  The stopping criteria can be based on all proximity sensors, or any proximity sensor." "Class=Movement"
TaskInfo: ArgDesc "Name=proxUseProx" "Parent=moveProx" "Type=bool" "Priority=Normal" "Desc=Stop the robot if the specified proximity sensors are triggered. Recommend enabling (true)." "Value=true" "Label=proxUseProx"
TaskInfo: ArgDesc "Name=proxCheckType" "Parent=moveProx" "Type=string" "Priority=Detailed" "Desc=Set of proximity sensors that must be triggered (or not triggered) to stop the move." "Value=AnyTriggered" "Display=Choices:AllTriggered;;AnyTriggered;;AnyNotTriggered;;AllNotTriggered" "Label=proxCheckType"
TaskInfo: ArgDesc "Name=proxUseQuickStop" "Parent=moveProx" "Type=bool" "Priority=Normal" "Desc=Use a quickstop when the proximity sensor or input triggers.  The quickstop is similar to an E-stop, except that it uses the brakes when available and it does not latch." "Value=true" "Label=proxUseQuickStop"
TaskInfo: ArgDesc "Name=proxCheckInterval" "Parent=moveProx" "Type=string" "Priority=Detailed" "Desc=Frequence (in ms) to check the proximity sensors. Time is approximate and platform-dependent. (On some systems, a frequency set to 1 ms may result in checking the sensors every 10 ms, for example.) 0 means that the sensors should be checked as fast as possible and may have an adverse effect on localization." "Value=10ms" "Display=Choices:0ms;;1ms;;10ms;;20ms;;cycle" "Label=proxCheckInterval"
TaskInfo: ArgDesc "Name=distance" "Parent=moveProx" "Type=int" "Priority=Important" "Desc=Distance (in mm) to move forward from the current location." "Value=1000" "Label=distance"
TaskInfo: ArgDesc "Name=speed" "Parent=moveProx" "Type=int" "Priority=Normal" "Desc=Speed (in mm/sec) at which to move." "Value=400" "Min=0" "Label=speed"
TaskInfo: ArgDesc "Name=front clearance" "Parent=moveProx" "Type=int" "Priority=Detailed" "Desc=Distance (in mm) to maintain between the front of the robot and any obstacles." "Value=200" "Label=front clearance"
TaskInfo: ArgDesc "Name=side clearance" "Parent=moveProx" "Type=int" "Priority=Detailed" "Desc=Distance (in mm) to maintain between the side of the robot and any obstacles." "Value=50" "Label=side clearance"
TaskInfo: ArgDesc "Name=time until fail" "Parent=moveProx" "Type=int" "Priority=Detailed" "Desc=Duration (in sec) to wait for an obstacle to clear before declaring that the move has failed." "Value=30" "Min=0" "Label=time until fail"
TaskInfo: ArgDesc "Name=transAccel" "Parent=moveProx" "Type=int" "Priority=Detailed" "Desc=Acceleration (in mm/sec/sec) for the move. 0 means use the robot's default acceleration." "Value=0" "Min=0" "Label=transAccel"
TaskInfo: ArgDesc "Name=transDecel" "Parent=moveProx" "Type=int" "Priority=Detailed" "Desc=Deceleration (in mm/sec/sec) for the move. 0 means use the robot's default acceleration." "Value=0" "Min=0" "Label=transDecel"
TaskInfo: ArgDesc "Name=minimum time" "Parent=moveProx" "Type=int" "Priority=Detailed" "Desc=Minimum duration (in sec) of this task. If the robot reaches the destination in less time, the task waits for the remainder of the duration. 0 means that task should complete as soon as the robot reaches the destination." "Value=0" "Min=0" "Label=minimum time"
TaskInfo: ArgDesc "Name=AvoidLocationDependentObstacles" "Parent=moveProx" "Type=bool" "Priority=Detailed" "Desc=When enabled (true), the robot avoids location-dependent obstacles like forbidden lines and other robots. If this is disabled, then physical guards must be used to contain the robot." "Value=true" "Label=AvoidLocationDependentObstacles"
TaskInfo: ArgDesc "Name=always succeed" "Parent=moveProx" "Type=bool" "Priority=Detailed" "Desc=Return success regardless of the distance moved. When enabled, the tasks will report success even if the destination is not reached. When disabled, the task fails if the destination is not reached." "Value=false" "Label=always succeed"
TaskInfo: ArgDesc "Name=finish if stopped" "Parent=moveProx" "Type=bool" "Priority=Detailed" "Desc=Finish the task if the robot cannot move after the first two seconds. When enabled, the task finishes as soon as the robot cannot move. When disabled, the robot must be blocked for the specified 'time until fail' before the task is finished." "Value=true" "Label=finish if stopped"
TaskInfo: TaskDesc "Name=play" "Desc=Play a sound file, and wait until it finishes playing" "Class=RobotAudio"
TaskInfo: ArgDesc "Name=sound file name" "Parent=play" "Type=string" "Priority=Normal" "Desc=Sound file (mp3, ogg, or wav previously uploaded to the robot). (Special Codes: $g=goal name. Current robot position $X (x in mm) $Y (y in mm) $T (heading in degrees, -180 to 180). Time in GMT: $y=current year, $m=month, $d=day, $H=hour, $M=minute, $S=second.)" "Value=" "Display=RobotFile:All sound files (*.mp3 *.ogg *.wav);;MP3 files (*.mp3);;Ogg Vorbis files (*.ogg);;WAV Files (*.wav)|*.ogg *.wav *.mp3;;*.mp3;;*.ogg;;*.wav" "Label=sound file name"
TaskInfo: ArgDesc "Name=sound file name possibility 2" "Parent=play" "Type=string" "Priority=Detailed" "Desc=Sound file (mp3, ogg, or wav previously uploaded to the robot). (Special Codes: $g=goal name. Current robot position $X (x in mm) $Y (y in mm) $T (heading in degrees, -180 to 180). Time in GMT: $y=current year, $m=month, $d=day, $H=hour, $M=minute, $S=second.)" "Value=" "Display=RobotFile:All sound files (*.mp3 *.ogg *.wav);;MP3 files (*.mp3);;Ogg Vorbis files (*.ogg);;WAV Files (*.wav)|*.ogg *.wav *.mp3;;*.mp3;;*.ogg;;*.wav" "Label=sound file name possibility 2"
