TaskInfo: ArgDesc "Name=importance level" "Parent=play" "Type=string" "Priority=Detailed" "Desc=Importance level for this item. Other tasks may cancel this item to play sound or speech with a higher importance level." "Value=Normal" "Display=Choices:Most Important;;More Important;;Normal;;Less Important;;Least Important" "Label=importance level"
TaskInfo: ArgDesc "Name=cancel less important" "Parent=play" "Type=bool" "Priority=Detailed" "Desc=Cancel other unplayed sound and speech items that have a lower importance level than this item." "Value=true" "Label=cancel less important"
TaskInfo: ArgDesc "Name=repetition time threshold" "Parent=play" "Type=double" "Priority=Detailed" "Desc=Don't perform this task if a task with the same sound or speech content was performed within this many seconds. Use this to avoid annoying repetition of the same speech or sound playback. Use 0.0 to always perform the task." "Value=0" "Label=repetition time threshold"
TaskInfo: TaskDesc "Name=playBackgroundSound" "Desc=Plays a random background sound (at 'Least Important') from a set of prefixes and suffixes (wild cards do NOT work), waiting a length of time between sounds, optionally resuming interrupted sounds, and with the ability to stop playing in some different circumstances.  Note that to interrupt this sound other audio task must be set have 'Cancel less important' set to true." "Class=RobotAudio|Instant"
TaskInfo: ArgDesc "Name=sound file directory" "Parent=playBackgroundSound" "Type=string" "Priority=Normal" "Desc=Directory to look in sound files for" "Value=" "Label=sound file directory"
TaskInfo: ArgDesc "Name=sound file prefix" "Parent=playBackgroundSound" "Type=string" "Priority=Normal" "Desc=Only select a sound file with this prefix.  Wildcards do NOT work.  To play all files that begin with number, just type: number and that will match all files that start with number, like number1, number57574 and NUMBER2. It will NOT match Mynumber1." "Value=" "Label=sound file prefix"
TaskInfo: ArgDesc "Name=sound file suffix" "Parent=playBackgroundSound" "Type=string" "Priority=Normal" "Desc=Only select a sound file with this suffix.  Wildcards to NOT work.  To play all the .mp3 files in the directory, just type: .mp3 and that will match all files that have the extension of mp3 (can play mp3, ogg, or wav files)" "Value=" "Label=sound file suffix"
TaskInfo: ArgDesc "Name=time between plays" "Parent=playBackgroundSound" "Type=double" "Priority=Normal" "Desc=Number of seconds between finishing playing one file and starting to play the next." "Value=15" "Min=0" "Label=time between plays"
TaskInfo: ArgDesc "Name=items between repeats" "Parent=playBackgroundSound" "Type=int" "Priority=Normal" "Desc=Number of items to play before allowing an item to be repeated (there parameter will be ignored if it leaves nothing to play, if it is set larger than the number of items than the one played longest ago will be played)." "Value=0" "Min=0" "Label=items between repeats"
TaskInfo: ArgDesc "Name=resume interrupted" "Parent=playBackgroundSound" "Type=bool" "Priority=Normal" "Desc=If we resume interrupted items, if true interrupted items will be resumed, if false fresh sound will be played" "Value=true" "Label=resume interrupted"
TaskInfo: ArgDesc "Name=skip time on resuming interrupted" "Parent=playBackgroundSound" "Type=bool" "Priority=Normal" "Desc=True if the resume should take into account the time it was interrupted for (and skip that amount of the sound), false if it should not be taken into account (so none of the sound time is lost)" "Value=false" "Label=skip time on resuming interrupted"
TaskInfo: ArgDesc "Name=stop playing condition" "Parent=playBackgroundSound" "Type=string" "Priority=Normal" "Desc=When to stop playing the background noise." "Value=Goal finished" "Display=Choices:Now;;Never;;End of mode/route;;Goal finished" "Label=stop playing condition"
TaskInfo: TaskDesc "Name=playInstant" "Desc=play a sound file and then continue while it is playing" "Class=RobotAudio|Instant"
TaskInfo: ArgDesc "Name=sound file name" "Parent=playInstant" "Type=string" "Priority=Normal" "Desc=Sound file (mp3, ogg, or wav previously uploaded to the robot). (Special Codes: $g=goal name. Current robot position $X (x in mm) $Y (y in mm) $T (heading in degrees, -180 to 180). Time in GMT: $y=current year, $m=month, $d=day, $H=hour, $M=minute, $S=second.)" "Value=" "Display=RobotFile:All sound files (*.mp3 *.ogg *.wav);;MP3 files (*.mp3);;Ogg Vorbis files (*.ogg);;WAV Files (*.wav)|*.ogg *.wav *.mp3;;*.mp3;;*.ogg;;*.wav" "Label=sound file name"
