TaskInfo: TaskDesc "Name=popupSimple" "Desc=Requests that the client applications show a simple popup message. (Client applications include MobilePlanner and MobileEyes.)" "Class=Instant"
TaskInfo: ArgDesc "Name=Title" "Parent=popupSimple" "Type=string" "Priority=Important" "Desc=Title of the popup message. If blank, then the 'Do not show again' checkbox is omitted." "Value=" "Label=Title"
TaskInfo: ArgDesc "Name=Message" "Parent=popupSimple" "Type=string" "Priority=Important" "Desc=Message to be displayed in the popup message. Must be specified." "Value=" "Label=Message"
TaskInfo: ArgDesc "Name=Button label" "Parent=popupSimple" "Type=string" "Priority=Important" "Desc=Label on the button in the popup message." "Value=OK" "Label=Button label"
TaskInfo: ArgDesc "Name=Button timeout" "Parent=popupSimple" "Type=int" "Priority=Important" "Desc=Duration (in sec) of the popup message. 0 means that the popup should be displayed until the button is pressed." "Value=0" "Min=0" "Max=65536" "Label=Button timeout"
TaskInfo: TaskDesc "Name=PrecisionDrive" "Desc=Drives the AMR to a location relative to a specified target" "Class=Movement"
TaskInfo: ArgDesc "Name=TargetShape" "Parent=PrecisionDrive" "Type=string" "Priority=Important" "Desc=Specifies the target shape matched by the AMR’s range sensor data" "Value=Standard" "Display=Choices:StandardCopy;;StandardReverseCopy;;SimpleOpenTarget;;Standard;;StandardReverse;;DockLD;;DockHD" "Label=Target Shape"
TaskInfo: ArgDesc "Name=FinalOffsetX" "Parent=PrecisionDrive" "Type=double" "Priority=Important" "Desc=Final axial distance in mm from the target center to the AMR center in the coordinate system of the specified target" "Value=-1000" "Min=-4000" "Max=4000" "Label=Final Offset X"
TaskInfo: ArgDesc "Name=FinalOffsetY" "Parent=PrecisionDrive" "Type=double" "Priority=Normal" "Desc=Final lateral distance in mm from the target center to the AMR center in the coordinate system of the specified target" "Value=0" "Min=-4000" "Max=4000" "Label=Final Offset Y"
TaskInfo: ArgDesc "Name=FinalOffsetAngle" "Parent=PrecisionDrive" "Type=double" "Priority=Normal" "Desc=Final rotation in degrees from the target center to the AMR center in the coordinate system of the specified target" "Value=0" "Min=-200" "Max=200" "Label=Final Offset Angle"
TaskInfo: ArgDesc "Name=InitialX" "Parent=PrecisionDrive" "Type=double" "Priority=Important" "Desc=Initial axial distance in mm from the target center to the AMR center in the coordinate system of the specified target" "Value=-2000" "Min=-4000" "Max=4000" "Label=Initial X"
TaskInfo: ArgDesc "Name=InitialY" "Parent=PrecisionDrive" "Type=double" "Priority=Normal" "Desc=Initial lateral distance in mm from the target center to the AMR center in the coordinate system of the specified target" "Value=0" "Min=-4000" "Max=4000" "Label=Initial Y"
TaskInfo: ArgDesc "Name=InitialAngle" "Parent=PrecisionDrive" "Type=double" "Priority=Normal" "Desc=Initial rotation in degrees from the target center to the AMR center in the coordinate system of the specified target" "Value=0" "Min=-180" "Max=180" "Label=Initial Angle"
TaskInfo: ArgDesc "Name=ParameterMode" "Parent=PrecisionDrive" "Type=string" "Priority=Detailed" "Desc=Toggles visibility of advanced parameters" "Value=Normal" "Display=Choices:Normal;;Advanced" "Label=Parameter Mode"
TaskInfo: ArgDesc "Name=Timeout" "Parent=PrecisionDrive" "Type=int" "Priority=Detailed" "Desc=Elapsed time in seconds from task start before failing" "Value=60" "Min=10" "Max=54000" "Display=Visible:ParameterMode=Advanced" "Label=Timeout"
TaskInfo: ArgDesc "Name=PathShape" "Parent=PrecisionDrive" "Type=string" "Priority=Detailed" "Desc=Specifies the path shape the AMR follows to the final location" "Value=PreAlign" "Display=Choices:PreAlign;;Straight;;PreAlign2&&Visible:ParameterMode=Advanced" "Label=Path Shape"
TaskInfo: ArgDesc "Name=SearchMode" "Parent=PrecisionDrive" "Type=string" "Priority=Detailed" "Desc=Specifies the size of search area surrounding the Initial location to look for the target" "Value=Normal" "Display=Choices:Normal;;Wide;;Tall;;Minimum;;Maximum;;Rotation&&Visible:ParameterMode=Advanced" "Label=Search Mode"
TaskInfo: ArgDesc "Name=MatchMode" "Parent=PrecisionDrive" "Type=string" "Priority=Detailed" "Desc=Specifies the allowable deviation between the ideal target shape and the detected shape" "Value=Normal" "Display=Choices:Normal;;Lenient;;Strict&&Visible:ParameterMode=Advanced" "Label=Match Mode"
TaskInfo: ArgDesc "Name=FailMode" "Parent=PrecisionDrive" "Type=string" "Priority=Detailed" "Desc=Specifies the abnormal conditions that cause the task to fail immediately" "Value=None" "Display=Choices:None;;FailOnEstop&&Visible:ParameterMode=Advanced" "Label=Fail Mode"
TaskInfo: ArgDesc "Name=DebugMode" "Parent=PrecisionDrive" "Type=string" "Priority=Detailed" "Desc=Specifies what task information is logged for debugging purposes" "Value=Normal" "Display=Visible:ParameterMode=Advanced&&Choices:None;;Normal;;Moderate;;Extensive;;All" "Label=Debug Mode"
TaskInfo: ArgDesc "Name=ClearanceMode" "Parent=PrecisionDrive" "Type=string" "Priority=Detailed" "Desc=Specifies the area around the AMR for obstacle protection while moving to the final location" "Value=Normal" "Display=Visible:ParameterMode=Advanced&&Choices:Normal;;Variable;;Custom" "Label=Clearance Mode"
TaskInfo: ArgDesc "Name=ApproachDistance" "Parent=PrecisionDrive" "Type=double" "Priority=Detailed" "Desc=Specifies the minimum distance in mm that the AMR should stop when approaching an obstacle" "Value=1000" "Min=100" "Max=8000" "Display=Visible:ClearanceMode!=Normal" "Label=Approach Distance"
TaskInfo: ArgDesc "Name=VirtualObstaclesAreReal" "Parent=PrecisionDrive" "Type=bool" "Priority=Detailed" "Desc=Treat virtual obstacles (Forbidden Area, etc) as real obstacles" "Value=true" "Display=Checkbox&&Visible:false" "Label=Virtual Obstacles Are Real"
TaskInfo: ArgDesc "Name=ClearanceShape" "Parent=PrecisionDrive" "Type=string" "Priority=Detailed" "Desc=Specifies the footprint shape of the AMR for obstacle protection" "Value=Normal" "Display=Choices:Normal;;Tight;;Expanded;;Custom&&Visible:ParameterMode=Advanced" "Label=Clearance Shape"
TaskInfo: ArgDesc "Name=FrontClearance" "Parent=PrecisionDrive" "Type=double" "Priority=Detailed" "Desc=Specifies the length in mm of the front clearance zone from the front edge of the AMR." "Value=50" "Min=-600" "Max=1000" "Display=Visible:ClearanceShape=Custom&&Visible:ParameterMode=Advanced" "Label=Front Clearance"
TaskInfo: ArgDesc "Name=LeftClearance" "Parent=PrecisionDrive" "Type=double" "Priority=Detailed" "Desc=Specifies the length in mm of the left side clearance zone from the left edge of the AMR." "Value=75" "Min=-600" "Max=1000" "Display=Visible:ClearanceShape=Custom&&Visible:ParameterMode=Advanced" "Label=Left Clearance"
TaskInfo: ArgDesc "Name=RightClearance" "Parent=PrecisionDrive" "Type=double" "Priority=Detailed" "Desc=Specifies the length in mm of the right side clearance zone from the right edge of the AMR." "Value=75" "Min=-600" "Max=1000" "Display=Visible:ClearanceShape=Custom&&Visible:ParameterMode=Advanced" "Label=Right Clearance"
TaskInfo: ArgDesc "Name=BackClearance" "Parent=PrecisionDrive" "Type=double" "Priority=Detailed" "Desc=Specifies the length in mm of the back side clearance zone from the back edge of the AMR." "Value=20" "Min=-600" "Max=1000" "Display=Visible:ClearanceShape=Custom&&Visible:ParameterMode=Advanced" "Label=Back Clearance"
TaskInfo: ArgDesc "Name=ClearanceSwitchDistance" "Parent=PrecisionDrive" "Type=double" "Priority=Detailed" "Desc=Specifies the distance in mm from the desired final position that the AMR will switch to using the defined Internal Clearances" "Value=300" "Min=0" "Max=3000" "Display=Visible:ClearanceMode=Variable&&Visible:ParameterMode=Advanced" "Label=Clearance Switch Distance"
TaskInfo: ArgDesc "Name=FinalClearanceShape" "Parent=PrecisionDrive" "Type=string" "Priority=Detailed" "Desc=Specifies the footprint shape of the AMR for obstacle protection during the final motion" "Value=Normal" "Display=Choices:Normal;;Tight;;Expanded;;Custom&&Visible:ClearanceMode=Variable&&Visible:ParameterMode=Advanced" "Label=Final Clearance Shape"
TaskInfo: ArgDesc "Name=FinalFrontClearance" "Parent=PrecisionDrive" "Type=double" "Priority=Detailed" "Desc=Specifies the length in mm of the front clearance zone from the front edge of the AMR." "Value=50" "Min=-400" "Max=1000" "Display=Visible:ClearanceMode=Variable&&Visible:FinalClearanceShape=Custom" "Label=Final Front Clearance"
TaskInfo: ArgDesc "Name=FinalLeftClearance" "Parent=PrecisionDrive" "Type=double" "Priority=Detailed" "Desc=Specifies the length in mm of the left side clearance zone from the left edge of the AMR." "Value=50" "Min=-400" "Max=1000" "Display=Visible:ClearanceMode=Variable&&Visible:FinalClearanceShape=Custom" "Label=Final Left Clearance"
TaskInfo: ArgDesc "Name=FinalRightClearance" "Parent=PrecisionDrive" "Type=double" "Priority=Detailed" "Desc=Specifies the length in mm of the right side clearance zone from the right edge of the AMR." "Value=50" "Min=-400" "Max=1000" "Display=Visible:ClearanceMode=Variable&&Visible:FinalClearanceShape=Custom" "Label=Final Right Clearance"
TaskInfo: ArgDesc "Name=FinalBackClearance" "Parent=PrecisionDrive" "Type=double" "Priority=Detailed" "Desc=Specifies the length in mm of the back side clearance zone from the back edge of the AMR." "Value=50" "Min=-400" "Max=1000" "Display=Visible:ClearanceMode=Variable&&Visible:FinalClearanceShape=Custom" "Label=Final Back Clearance"
TaskInfo: ArgDesc "Name=DriveMode" "Parent=PrecisionDrive" "Type=string" "Priority=Detailed" "Desc=Specifies how the driving motion is optimized" "Value=Normal" "Display=Visible:ParameterMode=Advanced&&Choices:Normal;;Smooth;;Precise;;Fast" "Label=Drive Mode"
TaskInfo: ArgDesc "Name=TranslationalSpeed" "Parent=PrecisionDrive" "Type=double" "Priority=Detailed" "Desc=Translational speed limit in mm/s" "Value=100" "Min=20" "Max=500" "Display=Visible:ParameterMode=Advanced&&" "Label=Translational Speed"
TaskInfo: ArgDesc "Name=ForwardSpeed" "Parent=PrecisionDrive" "Type=double" "Priority=Detailed" "Desc=Forward translational speed limit in mm/s" "Value=100" "Min=20" "Max=500" "Display=Visible:false" "Label=Forward Speed"
TaskInfo: ArgDesc "Name=ReverseSpeed" "Parent=PrecisionDrive" "Type=double" "Priority=Detailed" "Desc=Reverse translational speed limit in mm/s" "Value=-100" "Min=-200" "Max=-50" "Display=Visible:false" "Label=Reverse Speed"
TaskInfo: ArgDesc "Name=RotationalSpeed" "Parent=PrecisionDrive" "Type=double" "Priority=Detailed" "Desc=Rotational speed limit in deg/s" "Value=30" "Min=2" "Max=50" "Display=Visible:ParameterMode=Advanced" "Label=Rotational Speed"
TaskInfo: ArgDesc "Name=PrimaryLaser" "Parent=PrecisionDrive" "Type=string" "Priority=Detailed" "Desc=Specifies the laser number on the AMR for finding the target." "Value=Laser_1" "Display=Choices:Laser_1;;Laser_2;;Laser_3;;Laser_4;;Laser_5;;Laser_6&&Visible:ParameterMode=Advanced" "Label=PrimaryLaser"
TaskInfo: ArgDesc "Name=IgnoreDistance" "Parent=PrecisionDrive" "Type=double" "Priority=Normal" "Desc=Specifies the distance in mm from the desired position that the AMR will not consider matching the target." "Value=0" "Min=0" "Max=10000" "Display=Visible:ParameterMode=Advanced" "Label=IgnoreDistance"
TaskInfo: ArgDesc "Name=IgnoreFinalHeading" "Parent=PrecisionDrive" "Type=bool" "Priority=Normal" "Desc=" "Value=false" "Display=Checkbox&&Visible:ParameterMode=Advanced" "Label=IgnoreFinalHeading"
TaskInfo: ArgDesc "Name=TaskRequiresCAPS" "Parent=PrecisionDrive" "Type=bool" "Priority=Normal" "Desc=Enabling this parameter will verify that an AMR has a valid CAPS license installed prior to executing a PrecisionDrive task. The PrecisionDrive task will fail if a CAPS license is not installed on the AMR." "Value=false" "Display=Checkbox&&Visible:ParameterMode=Advanced" "Label=TaskRequiresCAPS"
