TaskInfo: ArgDesc "Name=repetition time threshold" "Parent=sendSpeechInstant" "Type=int" "Priority=Detailed" "Desc=Don't perform this task if a task with the same sound or speech content was performed within this many seconds. Use this to avoid annoying repetition of the same speech or sound playback. Use 0.0 to always perform the task." "Value=0" "Min=0" "Label=repetition time threshold"
TaskInfo: TaskDesc "Name=SendText" "Desc=Sends the specified text to all clients" "Class=Instant"
TaskInfo: ArgDesc "Name=key" "Parent=SendText" "Type=string" "Priority=Important" "Desc=Text identifier for the message" "Value=" "Display=RegExp:^[\w \u2000-\u206F\u2E00-\u2E7F\'!"#$%&()*+,\-.\/:;<=>?@\[\]^_`{|}~]{0,250}$" "Label=key"
TaskInfo: ArgDesc "Name=message" "Parent=SendText" "Type=string" "Priority=Important" "Desc=The text to send" "Value=" "Display=RegExp:^[\w \u2000-\u206F\u2E00-\u2E7F\'!"#$%&()*+,\-.\/:;<=>?@\[\]^_`{|}~]{0,250}$" "Label=message"
TaskInfo: TaskDesc "Name=setHeading" "Desc=Turns to a specified global orientation / heading." "Class=Movement|Heading"
TaskInfo: ArgDesc "Name=heading" "Parent=setHeading" "Type=int" "Priority=Important" "Desc=Global heading (in deg) to which to turn." "Value=0" "Min=-180" "Max=180" "Label=heading"
TaskInfo: ArgDesc "Name=rotVelMax" "Parent=setHeading" "Type=int" "Priority=Detailed" "Desc=Maximum rotational velocity (in deg/sec) when turning. 0 means use the default." "Value=0" "Min=0" "Label=rotVelMax"
TaskInfo: ArgDesc "Name=rotAccel" "Parent=setHeading" "Type=int" "Priority=Detailed" "Desc=Rotational acceleration (in deg/sec/sec) when turning. 0 means use the default." "Value=0" "Min=0" "Label=rotAccel"
TaskInfo: ArgDesc "Name=rotDecel" "Parent=setHeading" "Type=int" "Priority=Detailed" "Desc=Rotational deceleration (in deg/sec/sec) when turning. 0 means use the default." "Value=0" "Min=0" "Label=rotDecel"
TaskInfo: ArgDesc "Name=time until fail" "Parent=setHeading" "Type=int" "Priority=Detailed" "Desc=Duration (in sec) to wait if unable to turn before declaring that the task has failed." "Value=30" "Min=0" "Label=time until fail"
TaskInfo: ArgDesc "Name=minimum time" "Parent=setHeading" "Type=int" "Priority=Detailed" "Desc=Minimum duration (in sec) of this task. If the robot reaches the destination heading in less time, the task waits for the remainder of the duration. 0 means that task should complete as soon as the robot reaches the destination heading." "Value=0" "Min=0" "Label=minimum time"
TaskInfo: TaskDesc "Name=triangleDriveTo" "Desc=Drives to the triangle, stopping a specified distance in front of it. The 'Triangle Drive To' parameters in the Robot Configuration apply to instances of this task." "Class=Movement"
TaskInfo: ArgDesc "Name=frontBackOffset" "Parent=triangleDriveTo" "Type=int" "Priority=Detailed" "Desc=Distance (in mm) to offset the vertex in the front/back direction (+ in front of the triangle, - behind the triangle)." "Value=0" "Label=frontBackOffset"
TaskInfo: ArgDesc "Name=rightLeftOffset" "Parent=triangleDriveTo" "Type=int" "Priority=Detailed" "Desc=Distance (in mm) to offset the vertex in the right/left direction (- to the right of the triangle, + to the left of the triangle)." "Value=0" "Label=rightLeftOffset"
TaskInfo: ArgDesc "Name=angleOffset" "Parent=triangleDriveTo" "Type=double" "Priority=Detailed" "Desc=Angle (in deg) to offset the vertex (+ to the left of the triangle, - to the right of the triangle)." "Value=0" "Label=angleOffset"
TaskInfo: TaskDesc "Name=triangleDriveToAdvanced" "Desc=Drives to the triangle, stopping a specified distance in front of it. This task allows all of the normal triangle driving parameters to be overridden." "Class=Movement"
TaskInfo: ArgDesc "Name=frontBackOffset" "Parent=triangleDriveToAdvanced" "Type=double" "Priority=Detailed" "Desc=Distance (in mm) to offset the vertex in the front/back direction (+ in front of the triangle, - behind the triangle)." "Value=0" "Label=frontBackOffset"
TaskInfo: ArgDesc "Name=rightLeftOffset" "Parent=triangleDriveToAdvanced" "Type=double" "Priority=Detailed" "Desc=Distance (in mm) to offset the vertex in the right/left direction (- to the right of the triangle, + to the left of the triangle)." "Value=0" "Label=rightLeftOffset"
TaskInfo: ArgDesc "Name=angleOffset" "Parent=triangleDriveToAdvanced" "Type=double" "Priority=Detailed" "Desc=Angle (in deg) to offset the vertex (+ to the left of the triangle, - to the right of the triangle)." "Value=0" "Label=angleOffset"
TaskInfo: ArgDesc "Name=FinalDistFromVertex" "Parent=triangleDriveToAdvanced" "Type=double" "Priority=Normal" "Desc=Distance (in mm) from the triangle vertex to the final stopping point of the center of the robot. 0 means drive until a bump or stall is triggered." "Value=500" "Min=-1000" "Max=2000" "Label=FinalDistFromVertex"
TaskInfo: ArgDesc "Name=ApproachDistFromVertex" "Parent=triangleDriveToAdvanced" "Type=double" "Priority=Normal" "Desc=Distance (in mm) from the vertex to the initial approach point for the center of the robot." "Value=750" "Min=300" "Max=2500" "Label=ApproachDistFromVertex"
TaskInfo: ArgDesc "Name=FailTime" "Parent=triangleDriveToAdvanced" "Type=int" "Priority=Normal" "Desc=Maximum duration (in sec) to try to drive to the triangle. If the robot does not succeed during this timeframe, the task fails." "Value=45" "Min=0" "Label=FailTime"
TaskInfo: ArgDesc "Name=TriangleDriveSpeed" "Parent=triangleDriveToAdvanced" "Type=double" "Priority=Normal" "Desc=Speed (in mm/sec) to drive durin g the initial approach." "Value=100" "Min=50" "Max=500" "Label=TriangleDriveSpeed"
TaskInfo: ArgDesc "Name=TriangleDriveTolerance" "Parent=triangleDriveToAdvanced" "Type=double" "Priority=Normal" "Desc=Threshold (in mm)  that indicates how close to drive to the point." "Value=25" "Min=20" "Max=200" "Label=TriangleDriveTolerance"
TaskInfo: ArgDesc "Name=Line1Length" "Parent=triangleDriveToAdvanced" "Type=double" "Priority=Detailed" "Desc=Length (in mm) of the first line of the triangle. 0 matches any line length." "Value=254" "Min=0" "Max=1000" "Label=Line1Length"
TaskInfo: ArgDesc "Name=AngleBetweenLines" "Parent=triangleDriveToAdvanced" "Type=double" "Priority=Detailed" "Desc=Angle (in deg) between the two triangle lines. 0 matches any angle." "Value=135" "Min=-180" "Max=180" "Label=AngleBetweenLines"
TaskInfo: ArgDesc "Name=Line2Length" "Parent=triangleDriveToAdvanced" "Type=double" "Priority=Detailed" "Desc=Length (in mm) of the second line of the triangle. 0 matches any line length." "Value=254" "Min=0" "Max=1000" "Label=Line2Length"
TaskInfo: ArgDesc "Name=MaxDistBetweenLinePoints" "Parent=triangleDriveToAdvanced" "Type=int" "Priority=Detailed" "Desc=Maximum distance (in mm) between points that are turned into lines. This may be used to eliminate points when a laser sees both part of the target triangle and part of the background. 0 disables this feature." "Value=0" "Min=0" "Label=MaxDistBetweenLinePoints"
TaskInfo: ArgDesc "Name=MaxLateralDist" "Parent=triangleDriveToAdvanced" "Type=int" "Priority=Detailed" "Desc=Maximum distance (in mm) to the left or right that the robot will look for a vertex.  (Technically, the maximum distance between the robot's center and an imaginary line projected from the vertex).  Any potential vertex outside this range is ignored. 0 disables this feature." "Value=0" "Min=0" "Label=MaxLateralDist"
TaskInfo: ArgDesc "Name=MaxAngleMisalignment" "Parent=triangleDriveToAdvanced" "Type=int" "Priority=Detailed" "Desc=Maximum difference (in deg) allowed between the robot's heading and the angle of the vertex line. Any vertex line outside this range ignored. 0 disables this feature." "Value=0" "Min=0" "Label=MaxAngleMisalignment"
TaskInfo: ArgDesc "Name=TriangleFrontClearance" "Parent=triangleDriveToAdvanced" "Type=double" "Priority=Normal" "Desc=Front clearance (in mm) when driving to a triangle. If an obstacle is detected in this area, the robot stops. This value should be large enough to allow the robot to plan a path away from the triangle." "Value=100" "Label=TriangleFrontClearance"
TaskInfo: ArgDesc "Name=TriangleSideClearance" "Parent=triangleDriveToAdvanced" "Type=double" "Priority=Normal" "Desc=Side clearance (in mm) when driving to a triangle. If an obstacle is detected in this area, the robot stops. This value should be large enough to allow the robot to plan a path away from the triangle." "Value=100" "Label=TriangleSideClearance"
TaskInfo: ArgDesc "Name=AvoidLocationDependentObstacles" "Parent=triangleDriveToAdvanced" "Type=bool" "Priority=Detailed" "Desc=When enabled (true), the robot avoids location-dependent obstacles like forbidden lines and other robots when driving to the triangle. If this is disabled, then physical guards must be used to contain the robot whenever this task is used." "Value=true" "Label=AvoidLocationDependentObstacles"
TaskInfo: ArgDesc "Name=TriangleAdjustVertex" "Parent=triangleDriveToAdvanced" "Type=bool" "Priority=Detailed" "Desc=Use an alternate calculation for the vertex." "Value=false" "Label=TriangleAdjustVertex"
TaskInfo: ArgDesc "Name=TriangleGotoVertex" "Parent=triangleDriveToAdvanced" "Type=bool" "Priority=Normal" "Desc=Drive to the vertex instead of the point in front of it." "Value=false" "Label=TriangleGotoVertex"
TaskInfo: ArgDesc "Name=TriangleIgnoreDist" "Parent=triangleDriveToAdvanced" "Type=double" "Priority=Detailed" "Desc=Distance (in mm) from the final point at which the robot starts ignoring the triangle and drives solely based on its last reading. When the triangle is black, this value should be set since the robot has the potential to lose a black target when it is too close. (In this case, the default value is 0 when TriangleGoToVertex is true and is 250 when TriangleGoToVertex is false.)  0 is likely acceptable for triangles that are not black." "Value=250" "Label=TriangleIgnoreDist"
TaskInfo: ArgDesc "Name=TriangleBackDist" "Parent=triangleDriveToAdvanced" "Type=int" "Priority=Normal" "Desc=Distance (in mm) that the robot should back up after reaching the triangle point." "Value=0" "Min=0" "Max=0" "Label=TriangleBackDist"
TaskInfo: ArgDesc "Name=TriangleLogMore" "Parent=triangleDriveToAdvanced" "Type=bool" "Priority=Detailed" "Desc=Log additional information about triangle driving." "Value=false" "Label=TriangleLogMore"
TaskInfo: ArgDesc "Name=TriangleTransVelMax" "Parent=triangleDriveToAdvanced" "Type=double" "Priority=Detailed" "Desc=Maximum forward translational velocity (in mm/sec) when driving to the triangle. 0 means use the default." "Value=0" "Min=0" "Label=TriangleTransVelMax"
TaskInfo: ArgDesc "Name=TriangleTransNegVelMax" "Parent=triangleDriveToAdvanced" "Type=double" "Priority=Detailed" "Desc=Maximum backward translational velocity (in mm/sec) when driving to the triangle. 0 means use the default." "Value=0" "Min=0" "Label=TriangleTransNegVelMax"
TaskInfo: ArgDesc "Name=TriangleTransAccel" "Parent=triangleDriveToAdvanced" "Type=double" "Priority=Detailed" "Desc=Translational acceleration (in mm/sec/sec) when driving to the triangle. 0 means use the default." "Value=0" "Min=0" "Label=TriangleTransAccel"
TaskInfo: ArgDesc "Name=TriangleTransDecel" "Parent=triangleDriveToAdvanced" "Type=double" "Priority=Detailed" "Desc=Translational deceleration (in mm/sec/sec) when driving to the triangle. 0 means use the default." "Value=0" "Min=0" "Label=TriangleTransDecel"
TaskInfo: ArgDesc "Name=TriangleRotVelMax" "Parent=triangleDriveToAdvanced" "Type=double" "Priority=Detailed" "Desc=Maximum rotational velocity (in deg/sec) when driving to the triangle. 0 means use the default." "Value=0" "Min=0" "Label=TriangleRotVelMax"
TaskInfo: ArgDesc "Name=TriangleRotAccel" "Parent=triangleDriveToAdvanced" "Type=double" "Priority=Detailed" "Desc=Rotational acceleration (in deg/sec/sec) when driving to the triangle. 0 means use the default." "Value=0" "Min=0" "Label=TriangleRotAccel"
TaskInfo: ArgDesc "Name=TriangleRotDecel" "Parent=triangleDriveToAdvanced" "Type=double" "Priority=Detailed" "Desc=Rotational deceleration (in deg/sec/sec) when driving to the triangle. 0 means use the default." "Value=0" "Min=0" "Label=TriangleRotDecel"
TaskInfo: ArgDesc "Name=StopOnProx" "Parent=triangleDriveToAdvanced" "Type=bool" "Priority=Detailed" "Desc=Stop the robot if any of the proximity sensors are triggered when driving to the triangle. Recommend enabling (true)." "Value=true" "Label=StopOnProx"
TaskInfo: ArgDesc "Name=UseQuickStop" "Parent=triangleDriveToAdvanced" "Type=bool" "Priority=Detailed" "Desc=Use a quickstop when the proximity sensor or input triggers when driving to the triangle.  The quickstop is similar to an E-stop, except that it uses the brakes when available and it does not latch." "Value=false" "Label=UseQuickStop"
TaskInfo: TaskDesc "Name=trianglePointAway" "Desc=Turns away from the most recent triangleDriveTo destination." "Class=Movement|Heading"
TaskInfo: ArgDesc "Name=rotVelMax" "Parent=trianglePointAway" "Type=int" "Priority=Detailed" "Desc=Maximum rotational velocity (in deg/sec) when turning. 0 means use the default." "Value=0" "Min=0" "Label=rotVelMax"
TaskInfo: ArgDesc "Name=rotAccel" "Parent=trianglePointAway" "Type=int" "Priority=Detailed" "Desc=Rotational acceleration (in deg/sec/sec) when turning. 0 means use the default." "Value=0" "Min=0" "Label=rotAccel"
TaskInfo: ArgDesc "Name=rotDecel" "Parent=trianglePointAway" "Type=int" "Priority=Detailed" "Desc=Rotational deceleration (in deg/sec/sec) when turning. 0 means use the default." "Value=0" "Min=0" "Label=rotDecel"
TaskInfo: ArgDesc "Name=time until fail" "Parent=trianglePointAway" "Type=int" "Priority=Detailed" "Desc=Duration (in sec) to wait if unable to turn before declaring that the task has failed." "Value=30" "Min=0" "Label=time until fail"
TaskInfo: TaskDesc "Name=trianglePointAwayAdvanced" "Desc=Turns away from the most recent triangleDriveToAdvanced destination." "Class=Movement|Heading"
TaskInfo: ArgDesc "Name=rotVelMax" "Parent=trianglePointAwayAdvanced" "Type=int" "Priority=Detailed" "Desc=Maximum rotational velocity (in deg/sec) when turning. 0 means use the default." "Value=0" "Min=0" "Label=rotVelMax"
TaskInfo: ArgDesc "Name=rotAccel" "Parent=trianglePointAwayAdvanced" "Type=int" "Priority=Detailed" "Desc=Rotational acceleration (in deg/sec/sec) when turning. 0 means use the default." "Value=0" "Min=0" "Label=rotAccel"
TaskInfo: ArgDesc "Name=rotDecel" "Parent=trianglePointAwayAdvanced" "Type=int" "Priority=Detailed" "Desc=Rotational deceleration (in deg/sec/sec) when turning. 0 means use the default." "Value=0" "Min=0" "Label=rotDecel"
TaskInfo: ArgDesc "Name=time until fail" "Parent=trianglePointAwayAdvanced" "Type=int" "Priority=Detailed" "Desc=Duration (in sec) to wait if unable to turn before declaring that the task has failed." "Value=30" "Min=0" "Label=time until fail"
TaskInfo: TaskDesc "Name=wait" "Desc=Waits for the specified number of seconds. The wait may be interrupted by an explicit continue command." "Class=Timing"
TaskInfo: ArgDesc "Name=seconds to wait" "Parent=wait" "Type=int" "Priority=Important" "Desc=Number of seconds to wait." "Value=5" "Min=1" "Label=seconds to wait"
TaskInfo: ArgDesc "Name=status to wait with" "Parent=wait" "Type=string" "Priority=Detailed" "Desc=Status message to broadcast during the wait." "Value=Waiting" "Label=status to wait with"
TaskInfo: ArgDesc "Name=premotion blink" "Parent=wait" "Type=bool" "Priority=Detailed" "Desc=When enabled (true), the robot performs the pre-motion blinking action during the wait period." "Value=false" "Label=premotion blink"
TaskInfo: TaskDesc "Name=waitActive" "Desc=Calls a macro, and optionally waits a given number of seconds or until told to continue by command and control" "Class=Timing"
TaskInfo: ArgDesc "Name=wait type" "Parent=waitActive" "Type=string" "Priority=Detailed" "Desc=The wait type. Specified length: call the macro (if any) then wait until timeout. If the macro does not complete in the timeout, then abort the macro. Macro length: call the macro (if any) then terminate. Forever: call the macro (if any) then wait endlessly (until the task is cancelled)." "Value=Specified length" "Display=Choices:Specified length;;Macro length;;Forever" "Label=wait type"
TaskInfo: ArgDesc "Name=seconds to wait" "Parent=waitActive" "Type=int" "Priority=Important" "Desc=The number of seconds to wait" "Value=5" "Min=1" "Label=seconds to wait"
TaskInfo: ArgDesc "Name=status to wait with" "Parent=waitActive" "Type=string" "Priority=Detailed" "Desc=The status message to have while waiting" "Value=Waiting" "Label=status to wait with"
TaskInfo: ArgDesc "Name=premotion blink" "Parent=waitActive" "Type=bool" "Priority=Detailed" "Desc=Whether to do the pre motion blink while waiting" "Value=false" "Label=premotion blink"
TaskInfo: ArgDesc "Name=macro" "Parent=waitActive" "Type=string" "Priority=Normal" "Desc=the macro (if any) to call during the wait sequence" "Value=" "Display=Macro" "Label=macro"
TaskInfo: ArgDesc "Name=lockMode" "Parent=waitActive" "Type=bool" "Priority=Normal" "Desc=Whether to lock the mode.  If it is locked it will remain locked until the wait is either cancelled or failed." "Value=false" "Display=Checkbox" "Label=lockMode"
TaskInfo: ArgDesc "Name=succeeded macro" "Parent=waitActive" "Type=string" "Priority=Normal" "Desc=the macro (if any) to call after the wait finishes successfully (a cancelled wait counts as successful)" "Value=" "Display=Macro" "Label=succeeded macro"
TaskInfo: ArgDesc "Name=failed macro" "Parent=waitActive" "Type=string" "Priority=Normal" "Desc=the macro (if any) to call after the wait is failed" "Value=" "Display=Macro" "Label=failed macro"
TaskInfo: TaskDesc "Name=waitCancel" "Desc=Cancels any wait in progress (causing it to succeed)" "Class=Instant"
TaskInfo: TaskDesc "Name=waitFail" "Desc=Fails any wait in progress" "Class=Instant"
TaskInfo: TaskDesc "Name=waitIndefinitely" "Desc=Waits until commanded otherwise" "Class=Timing"
TaskInfo: ArgDesc "Name=status to pause with" "Parent=waitIndefinitely" "Type=string" "Priority=Detailed" "Desc=The status message to have while Pausing" "Value=Pausing" "Label=status to pause with"
